INSERT OR IGNORE INTO `course_sections` (`id`,`course_id`,`title`,`position`,`created_at`) SELECT 'cmf-module-2-01','cognizen-crypto-mastery-foundations-production','Module 2.1: How Cryptocurrency Markets Operate',1,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
