INSERT OR IGNORE INTO `course_sections` (`id`,`course_id`,`title`,`position`,`created_at`) SELECT 'cmf-module-2-04','cognizen-crypto-mastery-foundations-production','Module 2.4: Bull Markets, Bear Markets and Consolidation',4,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-04-lesson-01','cognizen-crypto-mastery-foundations-production','What Is a Market Trend? and Expanding Participation','cmf-module-2-04','text','### Learning Objectives\n\nBy the end of this module, you should be able to:\n\nDefine bull markets, bear markets and consolidation\n\nIdentify the basic characteristics of each market condition\n\nDistinguish between a market trend and a temporary price movement\n\nUnderstand how market structure, volume and sentiment change across market conditions\n\nExplain corrections, relief rallies, breakouts and false breakouts\n\nRecognise that different assets and timeframes can show different trends simultaneously\n\nAdjust expectations and risk management to the prevailing market environment\n\nAvoid common mistakes caused by misidentifying market conditions\n\n### Introduction\n\nCryptocurrency prices do not move continuously upward or downward.\n\nMarkets generally alternate between three broad conditions:\n\nBull markets\n\nBear markets\n\nConsolidation\n\nA bull market is characterised by a sustained upward trend.\n\nA bear market is characterised by a sustained downward trend.\n\nConsolidation occurs when price moves within a relatively defined range without a clear long-term direction.\n\nRecognising the prevailing market environment is important because strategies that work well during one condition may perform poorly during another.\n\nFor example, buying every short-term decline may work during a strong bull market because the broader trend remains upward. The same behaviour can produce repeated losses in a bear market, where each apparent bargain may be followed by another decline.\n\nSimilarly, trend-following strategies may struggle during consolidation because price repeatedly reverses rather than continuing in one direction.\n\nMarket classification is not an exact science. Conditions often become clear only after they have developed.\n\nThe objective is not to label every movement perfectly. It is to understand the evidence, recognise when conditions may be changing and avoid relying on assumptions that no longer fit the market.\n\n### What Is a Market Trend?\n\nA market trend is the general direction in which price moves over a meaningful period.\n\nThe three broad trend categories are:\n\nUptrend\n\nDowntrend\n\nSideways trend\n\nA trend does not require price to move in one direction without interruption.\n\nAn uptrend can include significant declines.\n\nA downtrend can include sharp rallies.\n\nThe direction is determined by the broader pattern of price movement rather than every individual candle or trading session.\n\n### Uptrend\n\nAn uptrend commonly forms a sequence of:\n\nHigher highs\n\nHigher lows\n\nA higher high occurs when price rises above the previous major peak.\n\nA higher low occurs when a decline stops above the previous major low.\n\nThis structure suggests that buyers are progressively willing to pay higher prices and that demand continues to appear during market pullbacks.\n\n### Downtrend\n\nA downtrend commonly forms a sequence of:\n\nLower highs\n\nLower lows\n\nA lower high occurs when a recovery fails below the previous major peak.\n\nA lower low occurs when price falls below the previous major low.\n\nThis indicates that sellers remain dominant and that buyers are unable to sustain recoveries.\n\n### Sideways Trend\n\nA sideways market occurs when price moves between an identifiable upper and lower boundary.\n\nThe market may repeatedly:\n\nRise toward resistance\n\nFall toward support\n\nReverse before establishing a lasting trend\n\nNeither buyers nor sellers maintain clear control.\n\nThis condition is commonly called:\n\nConsolidation\n\nA range\n\nSideways movement\n\nMarket balance\n\n### What Is a Bull Market?\n\nA bull market is an extended period during which prices generally rise and market confidence improves.\n\nIt is usually associated with:\n\nHigher highs and higher lows\n\nIncreasing investor participation\n\nGrowing liquidity\n\nPositive sentiment\n\nStronger demand\n\nGreater willingness to accept risk\n\nIncreased media attention\n\nRising valuations\n\nThe term bullish describes an expectation that an asset or market may rise.\n\nA bull market does not mean that every cryptocurrency increases in value.\n\nSome assets may:\n\nUnderperform\n\nRemain unchanged\n\nDecline\n\nFail completely\n\nThe strongest demand often concentrates in particular assets, sectors or narratives.\n\n### Why Is It Called a Bull Market?\n\nThe term is commonly associated with the way a bull attacks by driving its horns upward.\n\nThe image represents rising prices.\n\nBy contrast, a bear is often described as striking downward with its paws, representing falling prices.\n\nThe exact historical origin is less important than understanding how the terms are used in financial markets.\n\n### Characteristics of a Bull Market\n\n\n\n### Higher Highs and Higher Lows\n\nThe most important technical characteristic is a sustained upward market structure.\n\nBuyers continue entering at progressively higher prices.\n\nDeclines are often followed by recoveries that reach new highs.\n\n### Expanding Participation\n\nAs prices rise, more people become interested.\n\nParticipation may expand from:\n\nExperienced market participants\n\nTo institutions\n\nTo general retail investors\n\nTo people entering primarily because of recent gains\n\nPublic interest often grows after a substantial portion of the price increase has already occurred.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,1,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-04-lesson-02','cognizen-crypto-mastery-foundations-production','Positive Narratives and Forced Selling','cmf-module-2-04','text','### Positive Narratives\n\nBull markets create favourable interpretations of information.\n\nParticipants may focus on:\n\nAdoption\n\nPartnerships\n\nTechnology upgrades\n\nInstitutional investment\n\nRegulatory progress\n\nFuture applications\n\nNegative information may have only a temporary effect because buyers remain willing to enter during declines.\n\n### Increased Risk Appetite\n\nParticipants may become more willing to purchase:\n\nSmaller tokens\n\nNew projects\n\nHighly speculative assets\n\nLeveraged positions\n\nTokens with limited operating history\n\nAs confidence grows, capital often moves from established assets toward higher-risk opportunities.\n\nThis can produce dramatic gains, but it can also create extreme overvaluation.\n\n### Rising Liquidity\n\nBull markets may attract more:\n\nBuyers\n\nTraders\n\nMarket makers\n\nExchange activity\n\nStablecoin liquidity\n\nNew investment capital\n\nGreater liquidity can improve execution in established markets.\n\nHowever, smaller assets may still remain highly illiquid despite rapidly rising prices.\n\n### Bull Market Corrections\n\nA bull market does not move upward continuously.\n\nA correction is a meaningful decline within a broader upward trend.\n\nCorrections can occur because:\n\nTraders take profits\n\nLeverage becomes excessive\n\nPrices rise too quickly\n\nNegative news creates uncertainty\n\nBuyers temporarily withdraw\n\nThe market tests previous support\n\nA correction may be sharp and emotionally difficult while the broader trend remains intact.\n\nHowever, not every decline is merely a correction.\n\nA correction can develop into a full trend reversal.\n\nThe distinction is usually confirmed only after the market either resumes its upward structure or begins forming lower highs and lower lows.\n\n### Buying the Dip\n\n“Buying the dip” means purchasing after a price decline.\n\nThis approach can work during a healthy uptrend when demand repeatedly returns at higher levels.\n\nIt becomes dangerous when participants assume that every decline is temporary.\n\nIn a weakening or bearish market:\n\nEach dip may be followed by a deeper decline\n\nPrevious support may fail\n\nMarket fundamentals may deteriorate\n\nLiquidity may disappear\n\nBuying a lower price is not automatically buying value.\n\nThe market structure and investment thesis must still be assessed.\n\n### Euphoria in Bull Markets\n\nLater stages of a bull market may develop into euphoria.\n\nCommon signs include:\n\nRapid, near-vertical price increases\n\nExtreme leverage\n\nUnrealistic forecasts\n\nWidespread public attention\n\nLarge numbers of new token launches\n\nRejection of risk warnings\n\nSpeculative assets outperforming established assets\n\nPeople borrowing to invest\n\nParticipants may believe that:\n\nPrices can no longer decline\n\nAdoption guarantees profits\n\nEvery correction is a buying opportunity\n\nTraditional valuation no longer applies\n\nA strong market can remain overextended longer than expected.\n\nHowever, the combination of high valuations, leverage and unrealistic expectations creates vulnerability.\n\n### What Is a Bear Market?\n\nA bear market is an extended period during which prices generally decline and market confidence weakens.\n\nIt is commonly associated with:\n\nLower highs and lower lows\n\nReduced liquidity\n\nNegative sentiment\n\nDeclining participation\n\nLower risk appetite\n\nProject failures\n\nFalling valuations\n\nIncreased demand for cash or stable assets\n\nThe term bearish describes an expectation that an asset or market may decline.\n\nSome traditional definitions use a decline of twenty percent or more from a recent peak to describe a bear market. This numerical threshold is only a convention and is particularly limited in cryptocurrency, where twenty-percent movements can occur within otherwise rising markets.\n\nMarket structure and duration are generally more informative than one percentage figure.\n\n### Characteristics of a Bear Market\n\n\n\n### Lower Highs and Lower Lows\n\nThe market repeatedly fails to return to previous peaks.\n\nEach recovery attracts sellers.\n\nPrice then declines below previous lows.\n\nThis structure indicates persistent selling pressure.\n\n### Reduced Participation\n\nRetail attention may decline as previous participants experience losses.\n\nTrading volume may decrease, although panic events can temporarily create very high volume.\n\nNew projects may struggle to attract investment.\n\nDevelopment and hiring may slow, especially for projects dependent on rising token prices.\n\n### Negative Narratives\n\nDuring bear markets, participants interpret information more critically.\n\nAttention may focus on:\n\nRegulation\n\nSecurity failures\n\nInsolvency\n\nWeak adoption\n\nToken inflation\n\nProject abandonment\n\nMacroeconomic risk\n\nEven positive announcements may fail to produce lasting price increases because sellers continue using rallies to exit.\n\n### Declining Risk Appetite\n\nCapital often moves away from speculative assets toward:\n\nLarger and more established cryptocurrencies\n\nStablecoins\n\nTraditional currency\n\nLower-risk investments\n\nSmaller and less liquid tokens may decline far more than the broader market.\n\nSome never recover.\n\n### Forced Selling\n\nBear markets can create forced selling through:\n\nLeveraged liquidations\n\nLoan defaults\n\nFund redemptions\n\nBusiness expenses\n\nPersonal financial needs\n\nCollateral requirements\n\nExchange insolvencies\n\nThis selling may occur regardless of whether participants believe the asset is undervalued.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,2,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-04-lesson-03','cognizen-crypto-mastery-foundations-production','Bear Market Rallies and False Breakouts and False Breakdowns','cmf-module-2-04','text','### Bear Market Rallies\n\nA bear market does not decline continuously.\n\nIt can contain powerful upward movements known as:\n\nBear market rallies\n\nRelief rallies\n\nCountertrend rallies\n\nShort squeezes\n\nThese rallies may result from:\n\nShort sellers taking profits\n\nOversold market conditions\n\nTemporary positive news\n\nReduced selling pressure\n\nTraders attempting to identify the bottom\n\nForced closure of short positions\n\nA bear market rally can be large enough to appear like the beginning of a new bull market.\n\nThe key question is whether the market can:\n\nBreak above previous major highs\n\nMaintain higher lows\n\nSustain demand\n\nImprove broader participation\n\nIf the rally fails below the previous high and price declines again, the bearish structure may remain intact.\n\n### The Danger of False Recovery\n\nAfter a major decline, participants are often eager to believe that the worst is over.\n\nThey may interpret one strong rally as confirmation of a new bull market.\n\nThis can lead to:\n\nOversized purchases\n\nEarly leverage\n\nBuying weak assets\n\nIgnoring continued deterioration\n\nAnchoring to previous prices\n\nA genuine trend reversal usually requires more evidence than one rapid price increase.\n\n### What Is Consolidation?\n\nConsolidation occurs when price moves sideways within a relatively defined range.\n\nThe market alternates between:\n\nSupport near the lower boundary\n\nResistance near the upper boundary\n\nNeither buyers nor sellers establish a sustained directional advantage.\n\nConsolidation may occur:\n\nAfter a strong rise\n\nAfter a severe decline\n\nBefore a major event\n\nDuring uncertainty\n\nWhile the market absorbs previous price movement\n\nIt represents a temporary balance between supply and demand.\n\n### Support and Resistance in a Range\n\n\n\n### Support\n\nSupport is an area where buying demand has previously been strong enough to slow or reverse a decline.\n\n### Resistance\n\nResistance is an area where selling supply has previously been strong enough to slow or reverse a rise.\n\nDuring consolidation, traders may expect price to:\n\nAttract buyers near support\n\nAttract sellers near resistance\n\nHowever, support and resistance are zones rather than exact guarantees.\n\nRepeated testing can weaken a boundary.\n\nEventually, the market may break out of the range.\n\n### Why Markets Consolidate\n\nConsolidation may occur because:\n\nBuyers and sellers disagree about fair value\n\nPrevious winners take profits\n\nNew participants accumulate positions\n\nTraders await additional information\n\nVolatility declines after a major move\n\nLarge orders are being absorbed\n\nThe market is uncertain about future direction\n\nConsolidation can be healthy because it allows the market to process prior gains or losses.\n\nIt can also become frustrating because price repeatedly reverses and directional strategies fail.\n\n### Accumulation Versus Distribution\n\nA sideways market can represent either accumulation or distribution.\n\n### Accumulation\n\nPatient buyers gradually acquire assets from discouraged or short-term sellers.\n\nThis may eventually support an upward breakout.\n\n### Distribution\n\nEarlier holders sell positions gradually to enthusiastic or late buyers.\n\nThis may eventually lead to a downward breakdown.\n\nThe price range alone does not reveal which process is occurring.\n\nAnalysts may examine:\n\nVolume\n\nOwnership changes\n\nMarket structure\n\nBroader trend\n\nReactions to news\n\nOn-chain activity\n\nEven with these tools, interpretation remains uncertain until price leaves the range and sustains the new direction.\n\n### Breakouts\n\nA breakout occurs when price moves above a significant resistance level or outside the upper boundary of a range.\n\nA bullish breakout may suggest that demand has overcome available selling pressure.\n\nPotential confirmation evidence includes:\n\nIncreased trading volume\n\nA decisive close above resistance\n\nBroad market participation\n\nSuccessful retesting of the previous boundary\n\nContinued formation of higher highs and higher lows\n\nA breakout does not guarantee continued price appreciation.\n\nThe market may quickly return to the range.\n\n### Breakdowns\n\nA breakdown occurs when price moves below an important support level or the lower boundary of a range.\n\nIt may indicate that selling pressure has overwhelmed demand.\n\nPotential confirmation evidence includes:\n\nIncreased selling volume\n\nA decisive close below support\n\nFailed attempts to recover the level\n\nLower highs and lower lows\n\nWeakness across related assets\n\nA breakdown can accelerate if it triggers:\n\nStop-loss orders\n\nLeveraged liquidations\n\nPanic selling\n\nAutomated trading systems\n\n### False Breakouts and False Breakdowns\n\nA false breakout occurs when price moves outside a range but quickly returns inside it.\n\nThis is also called a failed breakout.\n\nA false breakdown is the equivalent movement below support followed by a rapid recovery.\n\nFalse moves may result from:\n\nTemporary liquidity shortages\n\nLarge individual orders\n\nStop-loss activity\n\nMarket manipulation\n\nNews-driven volatility\n\nInsufficient participation\n\nEntering immediately after every boundary break can expose traders to repeated losses.\n\nSome participants wait for confirmation or a retest before acting.\n\nWaiting reduces some false-break risk but may result in entering at a less favourable price or missing the movement entirely.\n\nEvery approach involves trade-offs.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,3,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-04-lesson-04','cognizen-crypto-mastery-foundations-production','Volume and Market Conditions and Identifying a Possible Regime Change','cmf-module-2-04','text','### Volume and Market Conditions\n\nVolume can provide context about the strength of a market movement.\n\n### Bullish Expansion With Rising Volume\n\nMay suggest increasing participation and conviction.\n\n### Price Increase With Declining Volume\n\nMay suggest weakening demand, although this is not conclusive.\n\n### Bearish Decline With High Volume\n\nMay indicate panic, forced selling or strong conviction among sellers.\n\n### Consolidation With Declining Volume\n\nMay indicate reduced interest and waiting for a catalyst.\n\n### Breakout With Strong Volume\n\nMay provide more evidence that the movement has broad participation.\n\nVolume should not be used alone.\n\nReported exchange volume can be inaccurate, and different markets may show different activity.\n\n### Volatility Across Market Conditions\n\nVolatility behaves differently across market environments.\n\n### Bull Market\n\nVolatility may expand upward as speculative demand grows.\n\nSharp corrections can still occur.\n\n### Bear Market\n\nVolatility may increase during panic, liquidations and exchange failures.\n\nPeriods of low activity may alternate with sudden declines.\n\n### Consolidation\n\nVolatility often contracts while price remains inside the range.\n\nA later breakout may produce a rapid expansion in volatility.\n\nLow volatility does not mean low risk.\n\nIt may reflect temporary balance before a significant movement.\n\n### Market Regimes\n\nA market regime is a broader environment defined by characteristics such as:\n\nTrend direction\n\nVolatility\n\nLiquidity\n\nCorrelation\n\nInvestor risk appetite\n\nExamples include:\n\nBullish and low volatility\n\nBullish and high volatility\n\nBearish and high volatility\n\nSideways and low volatility\n\nTwo bull markets can behave very differently.\n\nA slow institutional expansion is not the same as a speculative, leveraged rally.\n\nUnderstanding the market regime provides more detail than using only the labels bull or bear.\n\n### Timeframe Matters\n\nThe same cryptocurrency can appear bullish, bearish and sideways depending on the timeframe.\n\nFor example:\n\nThe long-term chart may show an uptrend\n\nThe daily chart may show a correction\n\nThe hourly chart may show consolidation\n\nNone of these observations is necessarily wrong.\n\nThey refer to different periods.\n\nBefore describing a market condition, specify the timeframe:\n\nIntraday\n\nDaily\n\nWeekly\n\nMonthly\n\nMulti-year\n\nA short-term trader and long-term investor may interpret the same chart differently because their decision horizons differ.\n\n### Individual Assets Versus the Broader Market\n\nThe overall cryptocurrency market may be bullish while one token is bearish.\n\nSimilarly, a specific sector may rise while the broader market consolidates.\n\nAn asset’s performance may depend on:\n\nProject developments\n\nToken unlocks\n\nSecurity failures\n\nExchange listings\n\nSector narratives\n\nRegulatory treatment\n\nLiquidity\n\nDo not assume that every cryptocurrency will follow the market leader exactly.\n\nCorrelation may increase during periods of stress, but individual project risk remains important.\n\n### Rotation Within Bull Markets\n\nCapital may move between market segments during an expanding market.\n\nA simplified rotation might involve:\n\nCapital entering larger, more established assets\n\nProfits moving into major alternative cryptocurrencies\n\nSpeculation expanding into smaller tokens\n\nExtremely risky assets attracting late-cycle capital\n\nThis pattern is not guaranteed.\n\nHowever, it illustrates how increasing risk appetite can spread through the market.\n\nLater stages often reward lower-quality assets temporarily, creating the illusion that analysis is unnecessary.\n\n### Defensive Behaviour in Bear Markets\n\nA bear market may encourage more defensive decisions, such as:\n\nReducing position sizes\n\nHolding greater liquidity\n\nAvoiding leverage\n\nFocusing on asset quality\n\nReassessing project fundamentals\n\nLimiting exposure to illiquid tokens\n\nReducing counterparty risk\n\nDefensive behaviour does not require predicting the exact bottom.\n\nIt focuses on preserving the ability to continue participating.\n\n### Strategy and Market Environment\n\nDifferent approaches may perform differently across market conditions.\n\n### Trend-Following Strategies\n\nAttempt to benefit from sustained directional movement.\n\nThey may perform well during strong bull or bear trends but struggle during ranges.\n\n### Range-Trading Strategies\n\nAttempt to buy near support and sell near resistance.\n\nThey may work during consolidation but can suffer when a breakout occurs.\n\n### Long-Term Investing\n\nFocuses on multi-year value and adoption.\n\nLong-term investors still need to manage position size, project risk and valuation.\n\n### Momentum Trading\n\nAttempts to participate in strong recent movement.\n\nIt can benefit from market expansion but may suffer during sudden reversals.\n\nA strategy should be evaluated according to the environment in which it is intended to operate.\n\nNo strategy performs best under every condition.\n\n### Risk Management by Market Condition\n\n\n\n### During Bull Markets\n\nConsider:\n\nAvoiding overconfidence\n\nLimiting leverage\n\nReviewing increasingly speculative holdings\n\nRebalancing oversized positions\n\nPreparing for corrections\n\nQuestioning unrealistic valuations\n\n### During Bear Markets\n\nConsider:\n\nPreserving liquidity\n\nAvoiding repeated impulsive dip-buying\n\nReassessing project survival\n\nReducing counterparty exposure\n\nLimiting leverage\n\nAccepting that some assets may never recover\n\n### During Consolidation\n\nConsider:\n\nAvoiding excessive trading\n\nDefining range boundaries\n\nWatching for false breakouts\n\nReducing expectations\n\nWaiting for clearer evidence\n\nMaintaining disciplined position sizes\n\nThese are general educational principles rather than personalised investment instructions.\n\n### Identifying a Possible Regime Change\n\nA bull market may be weakening when:\n\nHigher highs repeatedly fail\n\nMajor support levels break\n\nLower highs begin forming\n\nParticipation narrows\n\nLeverage becomes excessive\n\nPositive news no longer produces sustained gains\n\nA bear market may be weakening when:\n\nNew lows fail to continue\n\nSelling volume declines\n\nHigher lows begin forming\n\nNegative news has less effect\n\nStronger assets show relative resilience\n\nPrice recovers major resistance levels\n\nA range may be ending when:\n\nPrice repeatedly tests one boundary\n\nVolume expands\n\nVolatility increases\n\nThe market closes decisively outside the range\n\nA breakout level survives a retest\n\nNo single sign is definitive.\n\nA combination of evidence provides a stronger basis for analysis.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,4,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-04-lesson-05','cognizen-crypto-mastery-foundations-production','Avoiding Prediction Certainty and Key Takeaway','cmf-module-2-04','text','### Avoiding Prediction Certainty\n\nMarket labels can create false confidence.\n\nA participant may declare:\n\n“The bull market has begun.”\n\n“The bear market is over.”\n\n“This range must break upward.”\n\nThese statements may encourage oversized positions because uncertainty has been replaced by apparent certainty.\n\nA more disciplined approach uses probabilities:\n\nThe evidence currently supports an uptrend\n\nThe trend remains valid while specified conditions hold\n\nA break below a particular structure would weaken the view\n\nAlternative outcomes remain possible\n\nGood analysis defines what would prove it wrong.\n\n### A Market-Condition Assessment Framework\n\nWhen evaluating the market, ask:\n\n### Trend\n\nIs price forming higher highs or lower lows?\n\nWhich timeframe am I analysing?\n\nHas the structure changed?\n\n### Momentum\n\nIs price movement strengthening or weakening?\n\nAre rallies or declines becoming smaller?\n\n### Volume\n\nIs participation supporting the movement?\n\nDoes volume expand during breakouts?\n\n### Liquidity\n\nAre spreads narrowing or widening?\n\nCan positions be entered and exited efficiently?\n\n### Sentiment\n\nIs the market fearful, confident or euphoric?\n\nAre risks being ignored?\n\n### Fundamentals\n\nIs adoption improving or deteriorating?\n\nAre token supply and project finances sustainable?\n\n### Risk\n\nWhat happens if my market classification is wrong?\n\nIs the position size appropriate for that uncertainty?\n\n### Common Misunderstandings\n\n#### “A Bull Market Means Every Asset Will Rise”\n\nWeak or poorly designed projects can decline during broad market strength.\n\n#### “A Twenty-Percent Decline Automatically Means a Bear Market”\n\nCryptocurrency volatility makes fixed numerical definitions less reliable.\n\n#### “Every Bear Market Rally Is a New Bull Market”\n\nA rally can occur within an intact downtrend.\n\n#### “Consolidation Is Meaningless Price Movement”\n\nIt may reflect accumulation, distribution or the market processing previous movement.\n\n#### “A Breakout Guarantees Continuation”\n\nFalse breakouts occur frequently.\n\n#### “Low Volatility Means Low Risk”\n\nVolatility can expand rapidly after a period of compression.\n\n#### “Buying Every Dip Works Over Time”\n\nIt only works when the asset retains value and demand eventually returns.\n\n#### “Long-Term Investors Can Ignore Market Conditions”\n\nMarket conditions affect valuation, liquidity and portfolio risk even when the investment horizon is long.\n\n#### “The Market Is Either Bullish or Bearish”\n\nSideways and mixed conditions can persist for extended periods.\n\n### Module Summary\n\nCryptocurrency markets generally move through three broad conditions:\n\nBull markets\n\nBear markets\n\nConsolidation\n\nBull markets are characterised by sustained upward structure, improving confidence and increasing risk appetite.\n\nBear markets are characterised by lower highs, lower lows, declining confidence and reduced liquidity.\n\nConsolidation occurs when buyers and sellers remain balanced within a range.\n\nBull markets contain corrections.\n\nBear markets contain relief rallies.\n\nConsolidation can produce both genuine and false breakouts.\n\nMarket classification depends on timeframe, and different assets may experience different conditions simultaneously.\n\nVolume, liquidity, volatility, market structure and sentiment can provide evidence about the prevailing environment.\n\nNo market label guarantees the next movement.\n\nThe purpose of identifying market conditions is not to predict with certainty. It is to align expectations, strategy and risk management with the evidence currently available.\n\n### Key Takeaway\n\nBull markets reward optimism until optimism becomes excessive.\n\nBear markets punish risk until fear becomes extreme.\n\nConsolidation tests patience while the market decides which side has greater conviction.\n\nYou do not need to predict every turning point. You need to recognise the prevailing evidence, define what would change your view and ensure that being wrong does not create an unacceptable loss.','markdown',NULL,NULL,NULL,4,0,0,0,'',NULL,5,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-04-lesson-06','cognizen-crypto-mastery-foundations-production','Check your understanding','cmf-module-2-04','text','### Check your understanding\n\nAnswer these questions to self-assess your understanding before moving on.\n\n1. What is a market trend?\n\n2. What market structure commonly defines an uptrend?\n\n3. What market structure commonly defines a downtrend?\n\n4. What is a bull market?\n\n5. Why can a correction occur without ending a bull market?\n\n6. Why is buying every dip dangerous?\n\n7. What is a bear market rally?\n\n8. What evidence may distinguish a new uptrend from a temporary relief rally?\n\n9. What is consolidation?\n\n10. What is the difference between accumulation and distribution?\n\n11. What is a breakout?\n\n12. What is a false breakout?\n\n13. How can trading volume support breakout analysis?\n\n14. Why can low volatility still involve substantial risk?\n\n15. How can the same asset be bullish and bearish at the same time?\n\n16. Why might a trend-following strategy struggle during consolidation?\n\n17. What signs may indicate that a market regime is changing?\n\n18. Why should market analysis use probabilities rather than certainty?','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,6,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `course_sections` (`id`,`course_id`,`title`,`position`,`created_at`) SELECT 'cmf-module-2-05','cognizen-crypto-mastery-foundations-production','Module 2.5: Introduction to Fundamental Analysis',5,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
