INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-11-lesson-04','cognizen-crypto-mastery-foundations-production','Free Float and Step 6: Examine Liquidity','cmf-module-2-11','text','### Free Float\n\nFree float refers to the supply realistically available for active trading.\n\nIt may exclude tokens that are:\n\nLocked\n\nStaked long term\n\nHeld by founders\n\nControlled by treasuries\n\nPermanently inactive\n\nDeposited in strategic reserves\n\nLow free float can cause rapid price increases because only a small amount is available for purchase.\n\nIt can also create severe declines when a large holder begins selling.\n\nA token’s current market price may therefore be based on trading in only a small percentage of its total supply.\n\n### Low Float and High Valuation\n\nConsider a project with:\n\nToken price: 2\n\nCirculating supply: 20 million\n\nMaximum supply: 1 billion\n\nCurrent market capitalisation:\n\n2 × 20 million = 40 million\n\nFully diluted valuation:\n\n2 × 1 billion = 2 billion\n\nOnly two percent of the maximum supply circulates.\n\nThe token may appear to be a relatively small project based on market capitalisation.\n\nIts fully diluted valuation already assumes a two-billion value.\n\nFor the price to remain at two units as all tokens enter circulation, demand must expand enough to support fifty times more supply.\n\n### Token Burns and Supply Reduction\n\nA token burn permanently removes tokens from usable supply.\n\nBurns may occur through:\n\nTransaction fees\n\nProtocol revenue\n\nRedemption\n\nScheduled destruction\n\nGovernance decisions\n\nBurns can offset new issuance.\n\nThe relevant measure is net supply change.\n\nIf:\n\nFifty million tokens are issued\n\nTen million are burned\n\nThe total supply still grows by forty million.\n\nA project should not be considered deflationary merely because it conducts burns.\n\n### Buybacks\n\nA project may use revenue or treasury funds to purchase tokens from the market.\n\nThe tokens may then be:\n\nBurned\n\nHeld\n\nDistributed\n\nUsed for compensation\n\nBuybacks can support market demand.\n\nTheir quality depends on where the funds come from.\n\nA buyback funded through genuine recurring revenue differs from one funded using capital raised from previous token buyers.\n\nBuybacks should be transparent and economically sustainable.\n\n### Supply Changes Through Governance\n\nSome protocols allow token holders or administrators to modify:\n\nIssuance\n\nMaximum supply\n\nReward rates\n\nBurn mechanisms\n\nVesting\n\nTreasury distribution\n\nThis creates governance risk.\n\nA fixed-supply claim is weaker when a small group can vote to change it.\n\nAsk:\n\nWho can propose the change?\n\nWho can approve it?\n\nWhat voting threshold applies?\n\nIs there a delay before implementation?\n\nCan users reject the upgrade?\n\nAre emergency powers available?\n\nSupply policy is only as predictable as the governance system controlling it.\n\n### Bridged and Wrapped Supply\n\nTokens may move between blockchain networks through bridges or wrapping mechanisms.\n\nA representation of the original asset may be issued on another network while the original asset is locked.\n\nSupply data can become confusing because:\n\nOriginal tokens remain locked\n\nWrapped tokens circulate elsewhere\n\nSeveral bridges may issue versions\n\nData providers may count assets differently\n\nA legitimate wrapping system should maintain appropriate backing.\n\nIf more wrapped tokens exist than assets held in reserve, the representation may be undercollateralised.\n\nAlways distinguish between:\n\nNative tokens\n\nOfficial bridged tokens\n\nThird-party wrapped representations\n\n### Token Migrations\n\nA project may move from one token or blockchain to another.\n\nDuring migration:\n\nOld tokens may be exchanged for new tokens\n\nThe conversion ratio may differ\n\nDeadlines may apply\n\nSupply rules may change\n\nUnsupported tokens may become worthless\n\nUsers should verify migration instructions through official sources.\n\nFraudsters may create fake migration websites designed to steal wallet credentials.\n\nA migration can also alter the project’s distribution and governance structure.\n\n### Supply Transparency\n\nA credible project should provide clear information about:\n\nCurrent supply\n\nMaximum supply\n\nMinting rules\n\nBurned tokens\n\nMajor allocations\n\nVesting\n\nTreasury wallets\n\nGovernance powers\n\nSupply claims should be verifiable through:\n\nSmart contract code\n\nBlockchain explorers\n\nIndependent audits\n\nTransparent dashboards\n\nPublic treasury addresses\n\nWarning signs include:\n\nConflicting numbers\n\nUndisclosed wallets\n\nUnexplained supply increases\n\nPrivileged minting\n\nMissing unlock schedules\n\nFrequent changes to allocation categories\n\n### A Token Supply Analysis Process\n\n\n\n### Step 1: Record the Core Numbers\n\nIdentify:\n\nPrice\n\nCirculating supply\n\nTotal supply\n\nMaximum supply\n\nMarket capitalisation\n\nFully diluted valuation\n\n### Step 2: Identify Future Supply\n\nExamine:\n\nFounder vesting\n\nInvestor unlocks\n\nValidator emissions\n\nCommunity rewards\n\nTreasury releases\n\n### Step 3: Analyse Distribution\n\nDetermine:\n\nInsider ownership\n\nPublic ownership\n\nTreasury control\n\nLargest wallets\n\nGovernance concentration\n\n### Step 4: Assess Demand\n\nAsk whether genuine use can absorb future issuance.\n\n### Step 5: Review Control\n\nIdentify who can mint, burn or change supply rules.\n\n### Step 6: Examine Liquidity\n\nCompare unlocks and large holdings with:\n\nTrading volume\n\nOrder-book depth\n\nLiquidity pools\n\nAvailable exchanges\n\nSupply should never be assessed independently from demand and liquidity.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,4,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-11-lesson-05','cognizen-crypto-mastery-foundations-production','A Token Distribution Checklist and Key Takeaway','cmf-module-2-11','text','### A Token Distribution Checklist\n\nBefore evaluating a token, ask:\n\nWhat is the circulating supply?\n\nWhat is the total supply?\n\nIs there a maximum supply?\n\nWho can change the supply rules?\n\nWhat percentage currently circulates?\n\nWhat is the fully diluted valuation?\n\nWho received the initial supply?\n\nWhat did founders and investors pay?\n\nWhat vesting schedules apply?\n\nWhen are the largest unlocks?\n\nHow large are unlocks relative to circulating supply and volume?\n\nWho controls treasury tokens?\n\nHow concentrated is ownership?\n\nDo exchange or contract wallets distort holder data?\n\nHow much supply is staked?\n\nWhat creates new supply?\n\nWhat removes supply?\n\nIs supply currently inflationary or deflationary on a net basis?\n\nCan network demand absorb future issuance?\n\nAre the reported figures independently verifiable?\n\n### Common Warning Signs\n\nPotential warning signs include:\n\nVery low circulating supply\n\nExtremely high fully diluted valuation\n\nLarge insider allocations\n\nShort vesting periods\n\nLarge imminent unlocks\n\nUnexplained minting authority\n\nTreasury control by one person\n\nSupply figures that differ across sources\n\nHigh inflation with weak adoption\n\nPromotional focus on burns while ignoring issuance\n\nConcentrated voting power\n\nLittle available market liquidity\n\nPrivate investors with extremely low cost bases\n\nFrequent changes to supply rules\n\nWrapped assets without transparent backing\n\nOne concern may be manageable.\n\nSeveral interacting concerns can produce severe dilution, governance and liquidity risk.\n\n### Common Misunderstandings\n\n#### “A Fixed Maximum Supply Guarantees Price Appreciation”\n\nDemand must continue, and governance must not be able to change the cap easily.\n\n#### “Circulating Supply Includes Every Existing Token”\n\nLocked, vested and reserved tokens may be excluded.\n\n#### “A Token Unlock Means Everyone Will Sell”\n\nRecipients may hold or stake, but the ability to sell creates potential supply pressure.\n\n#### “High Fully Diluted Valuation Means the Token Will Reach That Value”\n\nFDV applies the current marginal price to future supply. The price may decline as supply expands.\n\n#### “A Broad Wallet Distribution Proves Broad Ownership”\n\nOne person may control several wallets, while one exchange wallet may represent many users.\n\n#### “Staked Tokens Are Permanently Removed”\n\nThey may later be unstaked and sold.\n\n#### “Token Burns Guarantee Deflation”\n\nNew issuance may exceed the burn.\n\n#### “Founder Tokens Are Harmless Because They Are Locked”\n\nThey remain potential future supply and may already provide governance or staking power.\n\n#### “A Low Token Price Means the Asset Is Cheap”\n\nSupply and valuation determine scale, not the price of one unit.\n\n### Module Summary\n\nToken supply analysis examines how many tokens exist, how many may eventually exist and how they enter the market.\n\nImportant measurements include:\n\nCirculating supply\n\nTotal supply\n\nMaximum supply\n\nFree float\n\nFully diluted supply\n\nToken distribution shows who owns or will receive the asset.\n\nImportant groups include:\n\nFounders\n\nEmployees\n\nPrivate investors\n\nPublic participants\n\nCommunities\n\nTreasuries\n\nValidators\n\nVesting delays the release of tokens, while token unlocks make previously restricted supply transferable.\n\nThe impact of an unlock depends on its size, recipient incentives, market liquidity and existing demand.\n\nLow circulating supply can support rapid price appreciation, but it may conceal significant future dilution.\n\nOwnership concentration can affect market stability, staking and governance.\n\nBurns and buybacks may reduce supply or create demand, but they must be compared with new issuance.\n\nA complete supply assessment combines supply data with distribution, liquidity, demand and governance control.\n\n### Key Takeaway\n\nA token’s current price reflects trading in the supply available today.\n\nIts long-term value will also be influenced by the supply arriving tomorrow.\n\nBefore evaluating any digital asset, understand how many tokens exist, how many remain locked, who will receive them and what incentives those holders have.\n\nSupply creates the units. Distribution determines who holds the power.\n\nThe next module is 2.12: Inflation, Deflation and Token Burns.','markdown',NULL,NULL,NULL,5,0,0,0,'',NULL,5,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-11-lesson-06','cognizen-crypto-mastery-foundations-production','Check your understanding','cmf-module-2-11','text','### Check your understanding\n\nAnswer these questions to self-assess your understanding before moving on.\n\n1. What is circulating supply?\n\n2. How does total supply differ from maximum supply?\n\n3. How is fully diluted valuation calculated?\n\n4. Why can circulating supply differ between data providers?\n\n5. What are the main ways tokens enter circulation?\n\n6. Why should allocation categories be examined according to effective control?\n\n7. What is vesting?\n\n8. What is a cliff period?\n\n9. How does linear vesting work?\n\n10. What factors determine the market effect of a token unlock?\n\n11. What is supply overhang?\n\n12. How does dilution affect an existing holder?\n\n13. Why do private-investor acquisition prices matter?\n\n14. What is free float?\n\n15. Why is a low-float, high-FDV structure potentially risky?\n\n16. Why must wallet-concentration data be interpreted carefully?\n\n17. How can token distribution affect governance?\n\n18. Do staked tokens permanently leave supply?\n\n19. Why should token burns be compared with issuance?\n\n20. What questions determine whether future demand can absorb future supply?','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,6,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `course_sections` (`id`,`course_id`,`title`,`position`,`created_at`) SELECT 'cmf-module-2-12','cognizen-crypto-mastery-foundations-production','Module 2.12: Inflation, Deflation and Token Burns',12,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-12-lesson-01','cognizen-crypto-mastery-foundations-production','What Is Token Inflation? and Net Issuance','cmf-module-2-12','text','### Learning Objectives\n\nBy the end of this module, you should be able to:\n\nDefine token inflation and deflation\n\nDistinguish supply inflation from price inflation\n\nCalculate gross issuance, burn rate and net issuance\n\nExplain how inflation affects ownership and purchasing power\n\nUnderstand why blockchain networks issue new tokens\n\nEvaluate token burns, buybacks and other supply-reduction mechanisms\n\nDistinguish between inflationary, disinflationary and deflationary token models\n\nRecognise misleading claims about scarcity and burns\n\nAssess whether a token’s supply policy is economically sustainable\n\n### Introduction\n\nCryptocurrency projects frequently promote themselves using phrases such as:\n\nFixed supply\n\nDeflationary token\n\nScarce digital asset\n\nBurn-powered economics\n\nDecreasing issuance\n\nUltra-sound money\n\nThese terms can sound attractive because investors often associate scarcity with rising value.\n\nHowever, supply reduction does not automatically create demand, and token inflation does not automatically make an asset unsuccessful.\n\nA blockchain may issue new tokens to compensate validators, secure the network, finance development or encourage participation.\n\nAnother network may burn transaction fees, but still create more tokens than it removes.\n\nA token may have a fixed supply while demand continually declines.\n\nUnderstanding inflation, deflation and token burns requires more than observing whether supply rises or falls.\n\nWe must examine:\n\nWhy supply changes\n\nHow quickly it changes\n\nWho receives new tokens\n\nWhat economic value they provide\n\nHow many tokens are removed\n\nWhether genuine demand exists\n\nWho can change the supply rules\n\nThe important question is not simply whether a token is inflationary or deflationary.\n\nIt is whether the supply system supports sustainable network activity and long-term value.\n\n### What Is Token Inflation?\n\nToken inflation occurs when the number of tokens in existence or circulation increases over time.\n\nNew tokens may be created through:\n\nMining rewards\n\nValidator rewards\n\nStaking incentives\n\nLiquidity-mining programmes\n\nCommunity distributions\n\nTreasury releases\n\nFounder and investor unlocks\n\nGovernance decisions\n\nAdministrative minting\n\nInflation increases the available or potential token supply.\n\nIf demand does not grow at a similar or faster rate, additional supply may place downward pressure on the token’s price.\n\nHowever, inflation can also serve a productive purpose.\n\nNew tokens may compensate participants for providing services essential to the network.\n\n### Monetary Inflation Versus Price Inflation\n\nThe word “inflation” can refer to different concepts.\n\n### Monetary or Supply Inflation\n\nThis refers to an increase in the number of currency units or tokens.\n\nFor example, if token supply rises from 100 million to 110 million, supply has increased by ten percent.\n\n### Price Inflation\n\nThis refers to a general increase in the prices of goods and services, reducing the purchasing power of money.\n\nA cryptocurrency can experience supply inflation while its market price rises.\n\nThis may happen when demand grows faster than supply.\n\nIt can also have a fixed supply while losing purchasing power because demand declines.\n\nSupply policy influences value, but it does not determine price by itself.\n\n### Calculating Token Inflation\n\nA simplified annual token inflation calculation is:\n\nAnnual inflation rate = New tokens issued during the year ÷ Supply at the beginning of the year × 100\n\nSuppose a network begins the year with 200 million tokens and issues another 20 million.\n\nThe approximate inflation rate is:\n\n20 million ÷ 200 million × 100 = 10 percent\n\nThis means supply increased by ten percent during the year.\n\nThe calculation becomes more complex when:\n\nTokens are also burned\n\nSupply unlocks occur\n\nIssuance changes during the year\n\nBridged tokens are counted\n\nTreasury tokens are classified differently\n\nThe most useful measure is often net supply growth rather than gross issuance alone.\n\n### Gross Issuance\n\nGross issuance is the total number of new tokens created during a period.\n\nSuppose a network creates:\n\n15 million tokens for validators\n\n5 million for ecosystem rewards\n\n2 million for development grants\n\nGross issuance is:\n\n15 million + 5 million + 2 million = 22 million tokens\n\nGross issuance shows how much new supply the protocol created before accounting for any tokens removed.\n\n### Token Burns\n\nA token burn permanently removes tokens from usable supply.\n\nTokens may be burned by:\n\nSending them to an inaccessible address\n\nDestroying them through smart contract logic\n\nRemoving transaction fees from circulation\n\nBurning tokens during redemption\n\nConducting scheduled supply reductions\n\nUsing protocol revenue to purchase and destroy tokens\n\nA legitimate burn should make the tokens permanently unspendable.\n\nMoving tokens into a treasury wallet is not necessarily a burn because they may later re-enter circulation.\n\n### Net Issuance\n\nNet issuance considers both newly created and permanently removed tokens.\n\nThe simplified calculation is:\n\nNet issuance = Gross issuance − Tokens burned\n\nSuppose a network creates 22 million tokens and burns 8 million during the same period.\n\nNet issuance is:\n\n22 million − 8 million = 14 million tokens\n\nThe token remains inflationary because total supply increased by 14 million.\n\nA project may advertise that millions of tokens were burned while giving less attention to the larger amount being created.\n\nAlways compare burns with gross issuance.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,1,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-12-lesson-02','cognizen-crypto-mastery-foundations-production','Net Inflation Rate and Unproductive Inflation','cmf-module-2-12','text','### Net Inflation Rate\n\nThe net inflation rate can be approximated as:\n\nNet new supply ÷ Beginning supply × 100\n\nIf the beginning supply was 200 million and net issuance was 14 million:\n\n14 million ÷ 200 million × 100 = 7 percent\n\nThe gross issuance rate may have been eleven percent, but the net inflation rate is seven percent after burns.\n\nNet inflation provides a clearer picture of the actual supply change.\n\n### Why Blockchain Networks Create New Tokens\n\nNew issuance is not automatically a flaw.\n\nBlockchain networks require participants to provide resources and accept risk.\n\n### Network Security\n\nMiners and validators may receive newly issued tokens for:\n\nProducing blocks\n\nVerifying transactions\n\nMaintaining network availability\n\nCommitting computing power or capital\n\nActing honestly\n\nWithout sufficient compensation, fewer participants may secure the network.\n\n### Ecosystem Development\n\nTokens may fund:\n\nSoftware development\n\nSecurity audits\n\nResearch\n\nDeveloper grants\n\nInfrastructure\n\nCommunity education\n\n### User Adoption\n\nNew tokens may reward early users or encourage people to try an application.\n\n### Liquidity\n\nLiquidity providers may receive tokens for making markets more usable.\n\nThe key question is whether the value received by the network justifies the value being distributed through new tokens.\n\n### Inflation as a Security Budget\n\nSome blockchains use inflation to create a security budget.\n\nValidators or miners incur costs when securing the network.\n\nThese may include:\n\nHardware\n\nElectricity\n\nStaked capital\n\nTechnical infrastructure\n\nOperational risk\n\nNew token issuance compensates them.\n\nA network that eliminates issuance completely may need transaction fees to provide enough security.\n\nIf fee revenue is too low, participants may leave, potentially weakening the network.\n\nA supply cap therefore creates an important long-term question:\n\nHow will network security be funded when new issuance becomes very small or ends?\n\nScarcity is valuable only when the network remains secure and useful.\n\n### Inflation and Ownership Dilution\n\nInflation can dilute existing holders.\n\nSuppose you own one million tokens out of a total supply of 100 million.\n\nYour share is one percent.\n\nIf supply increases to 120 million and your holdings remain unchanged, your share becomes:\n\n1 million ÷ 120 million = approximately 0.83 percent\n\nYou still own one million tokens, but your proportional ownership has declined.\n\nDilution may affect:\n\nGovernance power\n\nStaking influence\n\nScarcity\n\nClaims on rewards\n\nRelative ownership\n\nThis does not automatically mean the market value of your holdings will fall.\n\nDemand may increase enough to offset dilution.\n\n### Staking and Inflation\n\nProof-of-Stake networks often distribute new tokens to participants who stake their assets.\n\nSuppose:\n\nToken supply inflation is eight percent\n\nA staker earns ten percent\n\nA non-staker earns nothing\n\nThe staker’s token quantity grows faster than total supply, while the non-staker’s proportional ownership declines.\n\nThis means staking rewards may partly represent a transfer from non-stakers to stakers.\n\nThe headline reward should be compared with:\n\nSupply inflation\n\nValidator fees\n\nLock-up periods\n\nSlashing risk\n\nToken-price changes\n\nTax obligations\n\nA ten-percent token reward is not necessarily a ten-percent increase in real wealth.\n\n### Real Yield\n\nReal yield attempts to measure the return remaining after accounting for dilution or inflation.\n\nA simplified approximation is:\n\nReal token yield ≈ Nominal reward rate − Token inflation rate\n\nSuppose:\n\nNominal staking reward: 12 percent\n\nSupply inflation: 9 percent\n\nThe approximate real token yield is three percent before considering fees, price changes and other risks.\n\nThis does not mean the investor will earn three percent in national-currency terms.\n\nIf the token price falls by 40 percent, the investor may still experience a substantial financial loss.\n\n### Inflation and Selling Pressure\n\nNew tokens create potential selling pressure because recipients may need or want to sell them.\n\nPossible sellers include:\n\nMiners paying electricity costs\n\nValidators realising rewards\n\nEmployees receiving compensation\n\nDevelopers funding operations\n\nLiquidity providers capturing incentives\n\nInvestors receiving unlocked allocations\n\nThe impact depends on:\n\nIssuance size\n\nRecipient behaviour\n\nMarket liquidity\n\nExisting demand\n\nToken price\n\nEconomic conditions\n\nIssuance paid to participants with unavoidable operating expenses may create more consistent selling pressure than issuance paid to long-term holders.\n\n### Productive Inflation\n\nInflation can be described as productive when it supports activity that strengthens the network.\n\nExamples may include:\n\nCompensating independent validators\n\nFunding essential development\n\nAttracting early liquidity\n\nSupporting security research\n\nBuilding public infrastructure\n\nThe activity should create value that may eventually increase sustainable demand.\n\nProductive inflation resembles an investment by the network in its own growth and security.\n\n### Unproductive Inflation\n\nInflation may be unproductive when new tokens primarily support:\n\nExcessive insider compensation\n\nArtificial trading volume\n\nTemporary speculative activity\n\nUnsustainable yields\n\nMarketing without product delivery\n\nRewards unrelated to genuine contribution\n\nIf token issuance exceeds the value being created, holders are diluted without receiving a stronger network in return.\n\nThe issue is therefore not merely how much is issued, but what the network receives in exchange.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,2,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-12-lesson-03','cognizen-crypto-mastery-foundations-production','Disinflation and Burning Uncirculated Tokens','cmf-module-2-12','text','### Disinflation\n\nDisinflation occurs when supply continues increasing, but at a progressively slower rate.\n\nFor example:\n\nYear 1 supply growth: 12 percent\n\nYear 2: 8 percent\n\nYear 3: 5 percent\n\nYear 4: 3 percent\n\nThe asset remains inflationary because supply is still expanding.\n\nHowever, the inflation rate is declining.\n\nScheduled reward reductions and halvings can create disinflation.\n\nDisinflation should not be confused with deflation.\n\nSupply is still growing—just more slowly.\n\n### Deflation\n\nToken deflation occurs when total or circulating supply decreases over a period.\n\nThis happens when tokens are destroyed faster than new tokens are issued.\n\nSuppose:\n\nFive million new tokens are created\n\nEight million are burned\n\nNet issuance is:\n\n5 million − 8 million = negative 3 million\n\nSupply has decreased by three million tokens.\n\nThe token was net deflationary during that period.\n\nDeflation may be:\n\nPermanent\n\nTemporary\n\nDependent on network activity\n\nControlled through governance\n\nTriggered by redemption\n\nA token can be deflationary during high network usage and inflationary during quieter periods.\n\n### Deflation Does Not Guarantee Price Appreciation\n\nA declining supply may support scarcity, but price still depends on demand.\n\nConsider a project that burns ten percent of its supply while losing nearly all its users.\n\nThe supply is smaller, but the asset may still fall in price because demand has declined even faster.\n\nThe simplified relationship is:\n\nReduced supply can support price when demand remains stable or increases\n\nReduced supply cannot compensate indefinitely for disappearing demand\n\nAn unwanted token remains unwanted even when it becomes scarcer.\n\n### Burn Mechanisms\n\nToken burns can occur through different mechanisms.\n\n### Transaction-Fee Burns\n\nA portion of transaction fees is permanently destroyed.\n\nHigher network usage may then create more burns.\n\nThis can connect genuine activity with supply reduction.\n\n### Revenue-Funded Burns\n\nA project uses earned revenue to purchase tokens and destroy them.\n\nThe quality of this mechanism depends on whether the revenue is recurring and external to the token economy.\n\n### Scheduled Burns\n\nA predetermined number of tokens is burned at specific intervals.\n\nThis creates predictability but may not be connected to actual network use.\n\n### Redemption Burns\n\nTokens are destroyed when redeemed for another asset or service.\n\nStablecoin issuers, wrapped-token systems and tokenised-asset platforms may use this model.\n\n### Penalty Burns\n\nTokens may be burned when validators behave dishonestly or users violate protocol rules.\n\nThis can support security incentives.\n\n### Transaction-Fee Burns\n\nA fee-burn mechanism can align network use with token scarcity.\n\nA simplified cycle may be:\n\nUsers perform transactions\n\nThey pay fees\n\nPart of the fee is burned\n\nAvailable supply decreases or net issuance slows\n\nHowever, evaluate:\n\nWhether users are paying genuine economic fees\n\nWhether the burned asset is the token being analysed\n\nWhether issuance exceeds the burn\n\nWhether high fees discourage network use\n\nWhether the burn mechanism can be changed\n\nA network should not make itself unusably expensive merely to create a larger token burn.\n\n### Buybacks and Burns\n\nA project may use revenue to buy tokens from the market and burn them.\n\nThis can create buying demand and reduce supply.\n\nThe mechanism resembles a corporate share buyback, but important differences may exist.\n\nToken holders may not have:\n\nShareholder rights\n\nLegal claims on revenue\n\nOwnership in the operating company\n\nProtection against governance changes\n\nInvestigate:\n\nWhere the buyback funds originate\n\nWho authorises the purchases\n\nWhether transactions are transparent\n\nWhether tokens are genuinely burned\n\nWhether the programme is discretionary\n\nWhether insiders sell into the buyback\n\nA buyback funded from previous token-sale proceeds is less economically meaningful than one funded through sustainable external revenue.\n\n### Manual Versus Programmatic Burns\n\n\n\n### Manual Burn\n\nA team or governance body decides when and how many tokens to destroy.\n\nThis provides flexibility but creates discretion and trust requirements.\n\n### Programmatic Burn\n\nThe protocol automatically burns tokens according to predefined rules.\n\nThis improves predictability.\n\nHowever, governance or contract upgrades may still alter the rules.\n\n“Automatic” does not always mean permanent or uncontrollable.\n\n### Burn Addresses\n\nA burn address is a blockchain address designed to be unusable because no known participant controls the required private key.\n\nTokens sent there remain visible on the blockchain but cannot reasonably be spent.\n\nBefore accepting a burn claim, verify:\n\nThe transaction\n\nThe destination address\n\nWhether the address is genuinely inaccessible\n\nWhether the tokens were removed from reported supply\n\nA transfer to a normal treasury wallet should not be called a burn.\n\n### Burning Uncirculated Tokens\n\nSome projects announce the burning of tokens that were never circulating.\n\nFor example, a project may create a maximum supply of one billion tokens, release only 200 million and later burn 300 million unreleased tokens.\n\nThe maximum potential supply falls.\n\nHowever, no active market supply was removed because those tokens were never available.\n\nThis may still improve future supply expectations, but it does not create the same immediate scarcity as burning actively circulating tokens.\n\nThe distinction should be disclosed clearly.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,3,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-12-lesson-04','cognizen-crypto-mastery-foundations-production','Burns as Marketing and Evaluating Supply Sustainability','cmf-module-2-12','text','### Burns as Marketing\n\nToken burns are highly visible and easy to promote.\n\nA project may announce:\n\nMillions of tokens destroyed\n\nThe largest burn in project history\n\nPermanent scarcity\n\nDeflationary transformation\n\nThe number of tokens burned means little without context.\n\nAsk:\n\nWhat percentage of supply was burned?\n\nWere the tokens circulating?\n\nHow many new tokens were issued?\n\nWhat was the net supply change?\n\nDid the burn come from genuine revenue?\n\nWill future issuance replace the burned amount?\n\nBurning one billion tokens may sound significant, but not when one trillion tokens remain.\n\n### Deflationary Transaction Taxes\n\nSome tokens automatically take a percentage from each transfer and burn part of it.\n\nFor example, every transaction may incur:\n\nA burn\n\nA redistribution to holders\n\nA liquidity contribution\n\nA project tax\n\nThis can reduce supply but also create problems:\n\nExpensive transfers\n\nWeak exchange compatibility\n\nReduced liquidity\n\nComplex accounting\n\nHidden administrative control\n\nIncentives to hold rather than use the token\n\nA token designed to become more valuable by discouraging transactions may have limited practical utility.\n\nScarcity mechanisms should not undermine the product’s intended function.\n\n### Rebasing Tokens\n\nA rebasing token automatically changes the number of tokens held in user wallets.\n\nFor example, the protocol may increase or decrease balances to target a particular price or supply condition.\n\nA user might hold:\n\n100 tokens today\n\n110 after a positive rebase\n\n90 after a negative rebase\n\nA larger token balance does not necessarily mean greater value because every holder’s supply may change proportionally.\n\nRebasing can be confusing and should not be mistaken for free yield.\n\nThe market value of the total holding matters more than the number of units displayed.\n\n### Elastic Supply\n\nElastic-supply tokens expand or contract according to predefined rules.\n\nThe objective may be to influence price stability or respond to demand.\n\nHowever, changing token balances cannot guarantee stable purchasing power.\n\nThe system still depends on:\n\nMarket behaviour\n\nLiquidity\n\nConfidence\n\nAccurate price data\n\nEffective incentives\n\nSupply adjustments can produce unexpected outcomes when participants act differently from the economic model’s assumptions.\n\n### Maximum Supply\n\nA fixed maximum supply establishes the highest number of tokens permitted under the current rules.\n\nIt can create predictability.\n\nHowever, ask:\n\nHas the maximum already been reached?\n\nHow quickly will remaining tokens be issued?\n\nCan governance change the cap?\n\nCan a chain split create alternative versions?\n\nHow are network security and development funded?\n\nA maximum supply is one component of tokenomics, not a complete investment thesis.\n\n### Unlimited Supply\n\nA token with no maximum supply can still have controlled and predictable inflation.\n\nFor example, issuance may be:\n\nFixed annually\n\nLimited to a low percentage\n\nAdjusted according to staking participation\n\nPartly offset by burns\n\nAn unlimited theoretical supply does not mean unlimited immediate issuance.\n\nSimilarly, a capped token can still experience substantial short-term dilution when most supply remains locked.\n\nRate and timing matter as much as the final limit.\n\n### Supply Policy and Governance\n\nToken supply rules may be controlled by:\n\nImmutable protocol code\n\nDeveloper upgrades\n\nToken-holder voting\n\nFoundation decisions\n\nAdministrative keys\n\nValidator consensus\n\nA supply policy is more credible when changes require broad, transparent agreement.\n\nA fixed-supply promise is weaker when one administrator can mint new tokens immediately.\n\nEvaluate:\n\nWho can propose changes?\n\nWho approves them?\n\nWhat voting power do insiders hold?\n\nIs there an implementation delay?\n\nCan users reject the change?\n\nIs the contract upgradeable?\n\nScarcity is partly a governance property.\n\n### Inflation and Fully Diluted Valuation\n\nA token with low circulating supply and large future issuance may appear inexpensive based on current market capitalisation.\n\nFully diluted valuation provides additional context.\n\nSuppose:\n\nPrice: 1\n\nCirculating supply: 50 million\n\nMaximum supply: 1 billion\n\nCurrent market capitalisation:\n\n50 million\n\nFully diluted valuation:\n\n1 billion\n\nFor the price to remain at one unit as the full supply enters circulation, market demand must support twenty times more tokens.\n\nHigh future inflation or unlocks can make the current price difficult to sustain.\n\n### Demand Growth\n\nSupply analysis must always be paired with demand analysis.\n\nA token can absorb inflation when:\n\nMore users join\n\nNetwork activity expands\n\nStaking demand grows\n\nThe asset becomes useful as collateral\n\nInstitutional participation increases\n\nLiquidity deepens\n\nA deflationary token can still perform poorly when:\n\nUsers leave\n\nTechnology fails\n\nCompetition improves\n\nRegulation restricts access\n\nThe token lacks utility\n\nThe relationship can be simplified as:\n\nPrice pressure depends on the interaction between changing supply and changing demand.\n\n### Evaluating Supply Sustainability\n\nA sustainable supply model should answer:\n\nWhy are new tokens issued?\n\nWhat value does the network receive?\n\nWho absorbs the new supply?\n\nHow does issuance change over time?\n\nWhat happens when rewards decline?\n\nCan fees eventually support network security?\n\nAre burns funded by genuine activity?\n\nCan governance change the rules?\n\nDoes demand grow independently of speculation?\n\nThe goal is not necessarily zero inflation.\n\nIt is an issuance system that supports the network without destroying the economic value of participation.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,4,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-12-lesson-05','cognizen-crypto-mastery-foundations-production','Inflation, Deflation and Market Cycles and Key Takeaway','cmf-module-2-12','text','### Inflation, Deflation and Market Cycles\n\nSupply mechanisms can interact with market cycles.\n\n### During Bull Markets\n\nStrong demand may absorb high issuance.\n\nRecipients can sell rewards without causing obvious weakness.\n\nThis can make an inflationary system appear healthier than it is.\n\n### During Bear Markets\n\nDemand contracts while validators, employees and investors may continue selling newly issued or unlocked tokens.\n\nInflation becomes more visible.\n\n### During High Network Activity\n\nFee burns may increase, reducing net issuance.\n\n### During Low Activity\n\nBurns may decline while reward issuance continues.\n\nA token can therefore shift between inflationary and deflationary conditions depending on network use and market demand.\n\n### A Supply-Policy Assessment Framework\n\n\n\n### Issuance\n\nHow many tokens are created?\n\nWho receives them?\n\nWhat service do they provide?\n\n### Inflation\n\nWhat is the annual gross inflation rate?\n\nWhat is the net inflation rate?\n\nIs the rate rising or declining?\n\n### Burns\n\nHow are tokens burned?\n\nAre they circulating tokens?\n\nIs the burn connected to genuine revenue or use?\n\n### Demand\n\nWhat recurring reasons exist to acquire or hold the token?\n\nCan demand absorb future issuance?\n\n### Governance\n\nWho can change the supply rules?\n\nHow difficult is alteration?\n\n### Sustainability\n\nCan the network remain secure when issuance declines?\n\nDoes the model require permanently rising prices?\n\n### Common Warning Signs\n\nPotential warning signs include:\n\nHigh inflation hidden behind large nominal staking rewards\n\nHeavy promotion of burns without reporting gross issuance\n\nBurns involving only unreleased tokens\n\nUnlimited minting controlled by one administrator\n\nLarge future token unlocks\n\nNo plan for funding security after emissions decline\n\nBuybacks funded mainly from prior token sales\n\nTransaction taxes that discourage genuine use\n\nDeflationary claims unsupported by net supply data\n\nSupply rules that can change without broad approval\n\nHigh FDV combined with low circulating supply\n\nDependence on permanent speculative demand\n\n### Common Misunderstandings\n\n#### “Inflation Is Always Bad”\n\nIt can fund security, development and useful participation.\n\n#### “Deflation Is Always Good”\n\nDeclining demand can outweigh reduced supply.\n\n#### “A Token Burn Guarantees a Higher Price”\n\nPrice depends on both supply and demand.\n\n#### “Staking Rewards Are Free Income”\n\nThey may compensate for dilution and introduce additional risks.\n\n#### “A Maximum Supply Means No Inflation”\n\nSupply may continue expanding until the maximum is reached.\n\n#### “Unlimited Supply Means Hyperinflation”\n\nIssuance may be low, controlled and partly offset by burns.\n\n#### “A Large Burn Is Automatically Significant”\n\nIts importance depends on the percentage of supply and whether the tokens circulated.\n\n#### “Buying Back Tokens Is the Same as Returning Profits to Shareholders”\n\nToken holders may have no legal ownership or revenue rights.\n\n#### “More Tokens in My Wallet Means I Am Wealthier”\n\nRebases and inflation may increase units without increasing purchasing power.\n\n#### “A Deflationary Token Is Scarce”\n\nScarcity also depends on demand, ownership distribution, utility and the credibility of the supply rules.\n\n### Module Summary\n\nToken inflation occurs when supply increases.\n\nDeflation occurs when tokens are permanently removed faster than new tokens are created.\n\nDisinflation means that supply continues growing, but at a slower rate.\n\nGross issuance measures all newly created tokens.\n\nNet issuance subtracts burned tokens from gross issuance.\n\nNew issuance can fund:\n\nNetwork security\n\nDevelopment\n\nLiquidity\n\nAdoption\n\nCommunity participation\n\nIt can also dilute holders and create selling pressure.\n\nToken burns may be linked to transaction fees, revenue, redemptions or scheduled supply reductions.\n\nBurn claims should be evaluated according to:\n\nPercentage of supply removed\n\nWhether the tokens circulated\n\nGross issuance\n\nNet supply change\n\nThe source of burn funding\n\nA fixed or deflationary supply does not guarantee value.\n\nDemand, network usefulness, security and governance remain essential.\n\nA sustainable supply model rewards useful participation, controls dilution and remains functional without relying on permanently rising token prices.\n\n### Key Takeaway\n\nInflation tells you how supply expands. Deflation tells you how supply contracts.\n\nNeither tells you, by itself, whether a token will become more valuable.\n\nFollow the full economic process: how many tokens are created, who receives them, what value they provide, how many are removed and whether genuine demand can absorb the remaining supply.\n\nScarcity supports value only when people continue wanting what has become scarce.','markdown',NULL,NULL,NULL,5,0,0,0,'',NULL,5,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-12-lesson-06','cognizen-crypto-mastery-foundations-production','Check your understanding','cmf-module-2-12','text','### Check your understanding\n\nAnswer these questions to self-assess your understanding before moving on.\n\n1. What is token inflation?\n\n2. How does supply inflation differ from price inflation?\n\n3. How is an annual token inflation rate estimated?\n\n4. What is gross issuance?\n\n5. How is net issuance calculated?\n\n6. Why do blockchain networks issue new tokens?\n\n7. How can inflation dilute existing holders?\n\n8. Why should staking rewards be compared with supply inflation?\n\n9. What is real staking yield?\n\n10. What is productive inflation?\n\n11. How does disinflation differ from deflation?\n\n12. Can a token be deflationary during one period and inflationary during another?\n\n13. Why does a declining supply not guarantee a rising price?\n\n14. What is a transaction-fee burn?\n\n15. How does a revenue-funded buyback differ from one funded through earlier token sales?\n\n16. Why is burning unreleased supply different from burning circulating tokens?\n\n17. What risks may arise from deflationary transaction taxes?\n\n18. What is a rebasing token?\n\n19. Why does a fixed maximum supply not provide a complete tokenomics assessment?\n\n20. How can governance affect the credibility of a supply policy?\n\n21. Why should supply analysis always include demand?\n\n22. What evidence is needed to determine whether a token is genuinely net deflationary?','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,6,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `course_sections` (`id`,`course_id`,`title`,`position`,`created_at`) SELECT 'cmf-module-2-13','cognizen-crypto-mastery-foundations-production','Module 2.13: Token Vesting and Unlock Schedules',13,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
