INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-13-lesson-01','cognizen-crypto-mastery-foundations-production','What Is Token Vesting? and Supply Predictability','cmf-module-2-13','text','### Learning Objectives\n\nBy the end of this module, you should be able to:\n\nExplain why cryptocurrency projects use token vesting\n\nDistinguish between locked, vested, unlocked and circulating tokens\n\nUnderstand cliffs, linear vesting and milestone-based releases\n\nInterpret a token unlock schedule\n\nEvaluate unlock size relative to circulating supply, liquidity and trading volume\n\nIdentify the incentives of founders, employees and early investors\n\nExplain how unlocks may affect dilution, governance and market sentiment\n\nRecognise common vesting-related warning signs\n\nIncorporate future unlocks into a cryptocurrency investment analysis\n\n### Introduction\n\nA cryptocurrency’s current circulating supply shows how many tokens are available today.\n\nIt does not necessarily show how many may become available tomorrow.\n\nLarge quantities of tokens may still be reserved for:\n\nFounders\n\nEmployees\n\nEarly investors\n\nAdvisers\n\nProject treasuries\n\nCommunity rewards\n\nEcosystem development\n\nValidators or stakers\n\nThese tokens may be locked temporarily and released according to a vesting schedule.\n\nVesting can align project participants with long-term development by preventing them from selling their entire allocation immediately.\n\nHowever, vesting does not remove supply.\n\nIt delays when that supply becomes transferable.\n\nA project may appear to have a relatively small circulating supply while substantial insider allocations are scheduled to unlock over the following months or years.\n\nUnderstanding these schedules helps learners evaluate:\n\nFuture dilution\n\nPotential selling pressure\n\nGovernance concentration\n\nInsider incentives\n\nThe credibility of a project’s long-term alignment\n\nA token unlock is not automatically bearish. Recipients may continue holding, staking or using their tokens.\n\nNevertheless, unlocks change what holders are able to do, and that change should form part of a complete investment analysis.\n\n### What Is Token Vesting?\n\nToken vesting is a process through which allocated tokens become available gradually rather than immediately.\n\nA project may promise a founder ten million tokens but restrict access according to a four-year schedule.\n\nThe founder may technically have an allocation, but not all tokens can be transferred or sold at once.\n\nVesting is intended to encourage participants to remain committed to the project.\n\nIt may also:\n\nReduce immediate selling pressure\n\nProtect public buyers from sudden insider exits\n\nRetain employees\n\nReward continued contribution\n\nProvide more predictable supply growth\n\nAlign compensation with long-term delivery\n\nThe quality of vesting depends on how the schedule is designed and enforced.\n\n### Important Vesting Terms\n\n\n\n### Allocated Tokens\n\nTokens designated for a particular person, group or purpose.\n\nAn allocation may belong to:\n\nFounders\n\nEmployees\n\nInvestors\n\nAdvisers\n\nA treasury\n\nA community programme\n\nAllocated tokens are not necessarily transferable immediately.\n\n### Locked Tokens\n\nLocked tokens cannot currently be transferred under the applicable smart contract, agreement or custody arrangement.\n\nThe lock may expire:\n\nOn a specific date\n\nGradually over time\n\nWhen a milestone is achieved\n\nAfter a governance decision\n\nThe strength of the lock depends on how it is enforced.\n\nA smart contract lock may be more independently verifiable than a private promise not to sell.\n\n### Vested Tokens\n\nA token is vested when the recipient has earned the right to it under the vesting conditions.\n\nHowever, vested does not always mean immediately available.\n\nSome structures distinguish between:\n\nTokens that have been earned\n\nTokens that have been released\n\nTokens that can be transferred\n\nThe project documentation should define these terms clearly.\n\n### Unlocked Tokens\n\nUnlocked tokens are no longer restricted by the vesting schedule.\n\nThe recipient may generally:\n\nHold them\n\nTransfer them\n\nStake them\n\nVote with them\n\nSell them\n\nAn unlock creates potential supply. It does not confirm that a sale has occurred.\n\n### Circulating Tokens\n\nCirculating tokens are considered available within the market.\n\nAn unlocked token may be included in circulating supply even when its owner continues holding it.\n\nUnlocking and selling are therefore separate events.\n\n### Why Projects Use Vesting\n\n\n\n### Long-Term Alignment\n\nA founder receiving all tokens at launch could sell immediately and abandon the project.\n\nA multi-year vesting schedule makes more of the founder’s financial outcome dependent on the project’s future success.\n\n### Employee Retention\n\nTeam tokens may vest gradually while an employee remains with the project.\n\nIf the employee leaves early, they may forfeit the unvested portion.\n\nThis creates an incentive to continue contributing.\n\n### Investor Protection\n\nVesting prevents private investors from releasing their full allocation into the public market immediately after launch.\n\nThis is particularly important when early investors purchased tokens at prices far below the public market price.\n\n### Supply Predictability\n\nA published vesting schedule helps the market estimate when new supply may enter circulation.\n\nThis allows investors, exchanges and project treasuries to plan more effectively.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,1,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-13-lesson-02','cognizen-crypto-mastery-foundations-production','Governance Stability and Community and Ecosystem Unlocks','cmf-module-2-13','text','### Governance Stability\n\nTokens may provide voting rights.\n\nGradual release can prevent one group from obtaining its complete governance allocation immediately.\n\nHowever, some projects allow locked tokens to vote or earn staking rewards. The exact rules must be examined.\n\n### The Vesting Cliff\n\nA cliff is an initial period during which no tokens are released.\n\nFor example, a founder may receive an allocation with:\n\nA twelve-month cliff\n\nFollowed by thirty-six months of gradual vesting\n\nDuring the first twelve months, none of the allocation becomes transferable.\n\nAt the end of the cliff, a portion may unlock at once.\n\nThis first release is sometimes called the cliff unlock.\n\n### Example of a Cliff\n\nSuppose a founder receives twelve million tokens under the following schedule:\n\nTwelve-month cliff\n\nTwenty-five percent released after the cliff\n\nRemaining seventy-five percent released monthly over three years\n\nAfter twelve months:\n\nThree million tokens unlock at once\n\nThe remaining nine million tokens are then released gradually.\n\nThe initial cliff release may be significant because a large quantity becomes transferable on one date.\n\n### Linear Vesting\n\nLinear vesting releases tokens gradually at a consistent rate.\n\nSuppose twelve million tokens vest evenly over forty-eight months.\n\nThe monthly release would be:\n\n12 million ÷ 48 = 250,000 tokens per month\n\nLinear vesting creates predictable supply growth.\n\nIt may reduce the shock of one large release.\n\nHowever, it can create continuous selling pressure if recipients regularly sell each monthly allocation.\n\n### Periodic Vesting\n\nTokens may unlock at specified intervals, such as:\n\nWeekly\n\nMonthly\n\nQuarterly\n\nAnnually\n\nPeriodic releases may be easier to administer than continuous vesting.\n\nHowever, larger intervals can create more noticeable supply events.\n\nA quarterly release of three million tokens may have a different market effect from smaller daily releases totalling the same annual amount.\n\n### Milestone-Based Vesting\n\nMilestone-based vesting releases tokens when specified project objectives are completed.\n\nPossible milestones include:\n\nMain network launch\n\nCompletion of a security audit\n\nReaching a user target\n\nAchieving a revenue threshold\n\nDelivering a technical upgrade\n\nObtaining regulatory approval\n\nThis model can connect compensation with performance.\n\nHowever, the milestones must be:\n\nObjective\n\nMeasurable\n\nIndependently verifiable\n\nDifficult to manipulate\n\nA vague milestone such as “successful ecosystem expansion” gives insiders excessive discretion.\n\n### Performance-Based Vesting\n\nPerformance-based vesting links token releases to defined outcomes.\n\nExamples may include:\n\nNetwork uptime\n\nDeveloper growth\n\nTransaction-fee revenue\n\nProduct delivery\n\nBusiness partnerships\n\nSecurity performance\n\nThis can improve incentive alignment.\n\nIt can also encourage teams to manipulate short-term metrics or prioritise measurable targets over long-term network health.\n\nThe chosen performance measures should reward genuine value creation.\n\n### Hybrid Vesting\n\nMany projects combine several structures.\n\nFor example:\n\nTwelve-month cliff\n\nMonthly linear vesting\n\nAdditional tokens released after technical milestones\n\nContinued vesting only while the employee remains active\n\nHybrid arrangements can align incentives more precisely.\n\nThey also increase complexity.\n\nComplex schedules should be documented clearly enough for public participants to understand future supply.\n\n### Categories of Token Unlocks\n\n\n\n### Founder and Team Unlocks\n\nThese releases affect the people building and controlling the project.\n\nQuestions include:\n\nWhat percentage of supply belongs to the team?\n\nHow long is the vesting period?\n\nAre tokens released before major products are delivered?\n\nCan the team vote or stake while tokens remain locked?\n\nWhat happens when a team member leaves?\n\nShort vesting periods may allow founders to realise substantial gains before the project proves sustainable.\n\n### Private Investor Unlocks\n\nPrivate investors may have acquired tokens at much lower prices than public buyers.\n\nTheir willingness to sell may therefore be high even after a significant market decline.\n\nEvaluate:\n\nThe private sale price\n\nThe public launch price\n\nCurrent market price\n\nAllocation size\n\nVesting duration\n\nHistorical wallet behaviour\n\nThe difference between cost basis and market price helps reveal potential profit-taking incentives.\n\n### Adviser Unlocks\n\nAdvisers may receive tokens for strategic, technical or commercial support.\n\nInvestigate:\n\nWhether they genuinely contributed\n\nHow much they received\n\nTheir vesting terms\n\nWhether their role is ongoing\n\nWhether the relationship is publicly confirmed\n\nLarge adviser allocations with short vesting periods may function more like promotional compensation.\n\n### Treasury Unlocks\n\nTreasury tokens may be released to fund:\n\nSalaries\n\nDevelopment\n\nGrants\n\nMarketing\n\nPartnerships\n\nLiquidity\n\nTreasury releases are not necessarily harmful.\n\nThe project needs resources to operate.\n\nHowever, repeated token sales may create sustained market pressure, particularly when the treasury has limited cash or stable assets.\n\n### Community and Ecosystem Unlocks\n\nThese tokens may support:\n\nAirdrops\n\nStaking rewards\n\nUser incentives\n\nDeveloper grants\n\nLiquidity programmes\n\nThe key question is whether the distribution creates lasting value or temporary activity.\n\nRecipients of promotional rewards may sell immediately, increasing circulating supply without strengthening adoption.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,2,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-13-lesson-03','cognizen-crypto-mastery-foundations-production','Unlock Size in Context and Revocable Vesting','cmf-module-2-13','text','### Unlock Size in Context\n\nAn unlock should never be assessed only by the number of tokens released.\n\nConsider its size relative to the market.\n\nImportant comparisons include:\n\nPercentage of circulating supply\n\nPercentage of total supply\n\nAverage daily trading volume\n\nOrder-book depth\n\nDecentralised exchange liquidity\n\nExisting market capitalisation\n\n### Example: Unlock Relative to Circulating Supply\n\nSuppose:\n\nCirculating supply: 100 million tokens\n\nUpcoming unlock: 5 million tokens\n\nThe release equals:\n\n5 million ÷ 100 million × 100 = 5 percent of circulating supply\n\nA five-percent increase may be material, especially in an illiquid market.\n\n### Example: Unlock Relative to Trading Volume\n\nSuppose:\n\nFive million tokens unlock\n\nAverage daily genuine trading volume is one million tokens\n\nThe unlock equals five days of typical trading volume.\n\nIf recipients attempt to sell a large portion immediately, normal market demand may not absorb it without price impact.\n\nReported volume should be treated cautiously because some exchange activity may be artificial.\n\n### Unlocks and Dilution\n\nWhen additional tokens enter circulation, each existing token represents a smaller proportion of circulating supply.\n\nSuppose:\n\nCirculating supply before unlock: 100 million\n\nYour holding: 1 million\n\nYour share: 1 percent\n\nAfter 20 million tokens unlock:\n\nNew circulating supply: 120 million\n\nYour share: approximately 0.83 percent\n\nYour token quantity remains unchanged.\n\nYour relative ownership has declined.\n\nWhether the market price declines depends on demand, liquidity and recipient behaviour.\n\n### Unlocks and Market Price\n\nAn unlock may affect price through several channels.\n\n### Actual Selling\n\nRecipients sell unlocked tokens into the market.\n\n### Expected Selling\n\nOther participants sell before the unlock because they anticipate future pressure.\n\n### Reduced Buying\n\nPotential buyers delay purchases until the event has passed.\n\n### Improved Liquidity\n\nAdditional supply may make the market easier to trade, attracting larger participants.\n\n### Confidence Effects\n\nA transparent and well-designed release may reinforce trust, while an unexpected unlock may damage confidence.\n\nThe market impact is therefore behavioural as well as mechanical.\n\n### Unlocks May Be Priced In\n\nKnown unlock schedules are public information.\n\nMarket participants may adjust positions before the release.\n\nThe token’s current price may already reflect expectations of:\n\nInsider selling\n\nSupply growth\n\nTreasury distributions\n\nReduced scarcity\n\nThis is described as the event being priced in.\n\nHowever, expectations can be wrong.\n\nRecipients may sell more or less than anticipated, and market demand may change.\n\nA scheduled event can still create volatility even when it is widely known.\n\n### Unlocking Does Not Mean Selling\n\nAn unlocked token may be:\n\nHeld in the same wallet\n\nMoved to custody\n\nStaked\n\nDelegated for governance\n\nUsed as collateral\n\nSold privately\n\nTransferred to an exchange\n\nSold on the open market\n\nOn-chain monitoring may provide clues, but interpretation remains uncertain.\n\nA transfer to an exchange can indicate possible selling, although it may also support:\n\nCustody\n\nMarket making\n\nCollateral\n\nInternal reorganisation\n\nAn unlock should be treated as increased capacity to sell, not proof of a sale.\n\n### Cost Basis and Selling Incentives\n\nCost basis refers to the price at which a holder acquired tokens.\n\nSuppose:\n\nEarly investors paid 0.02\n\nPublic buyers paid 1.00\n\nCurrent market price is 0.30\n\nPublic buyers have lost seventy percent.\n\nEarly investors still hold a fifteen-times return.\n\nThey may therefore sell profitably at prices that appear deeply depressed to later participants.\n\nUnderstanding cost basis helps explain why falling prices do not necessarily remove insider selling pressure.\n\n### Token Unlocks and Governance\n\nUnlocked tokens may increase the recipient’s governance influence.\n\nDepending on the protocol, voting rights may begin:\n\nWhen tokens are allocated\n\nWhen they vest\n\nWhen they unlock\n\nWhen they are staked\n\nWhen they are delegated\n\nA large team or investor unlock can shift control over:\n\nTreasury spending\n\nFee changes\n\nToken issuance\n\nProtocol upgrades\n\nLeadership appointments\n\nUnlock analysis should therefore examine both market and governance consequences.\n\n### Staking Locked Tokens\n\nSome projects allow locked tokens to earn staking rewards.\n\nThis can create several effects:\n\nInsiders receive additional tokens before their allocation becomes liquid\n\nGovernance influence may accumulate\n\nFuture supply becomes larger than the original allocation\n\nPublic participants may experience greater dilution\n\nAsk whether rewards on locked tokens are:\n\nImmediately transferable\n\nSubject to the same vesting schedule\n\nIncluded in supply projections\n\nAvailable for governance\n\nA vesting schedule may appear restrictive while still granting substantial economic benefits to insiders.\n\n### Accelerated Vesting\n\nSome agreements allow tokens to vest earlier under certain conditions.\n\nPossible triggers include:\n\nAcquisition of the project\n\nTermination of employment\n\nGovernance approval\n\nChange of control\n\nCompletion of a milestone\n\nProject dissolution\n\nAccelerated vesting can create unexpected supply.\n\nReview whether the documentation identifies these conditions clearly.\n\n### Revocable and Irrevocable Vesting\n\n\n\n### Revocable Vesting\n\nUnvested tokens can be cancelled or returned if the participant leaves or fails to meet conditions.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,3,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-13-lesson-04','cognizen-crypto-mastery-foundations-production','Irrevocable Vesting and 2. Measure Its Scale','cmf-module-2-13','text','### Irrevocable Vesting\n\nThe allocation continues vesting regardless of future contribution, once granted.\n\nRevocable structures may improve accountability.\n\nHowever, the authority to cancel allocations must be governed fairly and transparently.\n\n### Smart Contract Enforcement\n\nVesting may be enforced through a smart contract.\n\nPotential advantages include:\n\nTransparent release dates\n\nAutomated execution\n\nPublic verification\n\nReduced reliance on private promises\n\nHowever, smart contract enforcement still presents risks:\n\nCoding errors\n\nUpgradeable contracts\n\nAdministrative override powers\n\nIncorrect release calculations\n\nCompromised administrator keys\n\nVerify whether the contract can be changed and who controls any upgrade authority.\n\n### Off-Chain Vesting Agreements\n\nSome tokens are held in ordinary wallets while recipients agree contractually not to sell before specified dates.\n\nThis structure relies more heavily on:\n\nLegal agreements\n\nCustodians\n\nProject oversight\n\nRecipient honesty\n\nOff-chain arrangements may be difficult for the public to verify.\n\nA transfer restriction described in a document may not be enforced technically.\n\n### Unlock Schedules and Fully Diluted Valuation\n\nA low circulating supply can produce a modest current market capitalisation.\n\nLarge future unlocks may reveal a much higher fully diluted valuation.\n\nSuppose:\n\nPrice: 2\n\nCirculating supply: 50 million\n\nMaximum supply: 500 million\n\nCurrent market capitalisation:\n\n2 × 50 million = 100 million\n\nFully diluted valuation:\n\n2 × 500 million = 1 billion\n\nIf the remaining tokens unlock over three years, demand must grow substantially for the price to remain stable.\n\nThe schedule determines how quickly the market must absorb this future supply.\n\n### Unlock Frequency\n\nTwo projects may release the same total number of tokens but create different market conditions.\n\n### Large Infrequent Unlocks\n\nPotentially create:\n\nEvent-driven volatility\n\nMarket anticipation\n\nSudden liquidity changes\n\nLarger one-time selling pressure\n\n### Small Frequent Unlocks\n\nPotentially create:\n\nContinuous supply pressure\n\nGreater predictability\n\nLess dramatic individual events\n\nOngoing treasury or insider selling\n\nNeither structure is automatically superior.\n\nThe market’s liquidity and demand determine which is easier to absorb.\n\n### The Unlock Cliff Effect\n\nA project may have little new insider supply during its first year because of a cliff.\n\nThis can create an artificially limited circulating supply.\n\nWhen the cliff ends, supply growth may accelerate sharply.\n\nEarly price performance should therefore be interpreted in the context of:\n\nInitial float\n\nCliff duration\n\nFirst major unlock\n\nInsider cost basis\n\nLiquidity\n\nA token’s early scarcity may be temporary.\n\n### Tracking Unlock Schedules\n\nUseful sources may include:\n\nOfficial tokenomics documentation\n\nVesting smart contracts\n\nBlockchain explorers\n\nProject governance proposals\n\nTreasury reports\n\nIndependent token-unlock dashboards\n\nRegulatory or fundraising documents\n\nCompare several sources.\n\nWatch for:\n\nConflicting release dates\n\nChanged allocation categories\n\nUnannounced schedule revisions\n\nTokens moving before the stated date\n\nUnlocks omitted from circulating-supply calculations\n\nThe most reliable evidence is generally the enforceable contract and observable blockchain activity, interpreted alongside the legal and project documentation.\n\n### Unlock Calendars\n\nAn unlock calendar organises future releases by date.\n\nA useful calendar may record:\n\nDate\n\nRecipient category\n\nNumber of tokens\n\nPercentage of circulating supply\n\nPercentage of total supply\n\nEstimated market value\n\nVesting type\n\nKnown recipient wallets\n\nExpected future releases\n\nDo not rely only on the estimated currency value.\n\nThe market price may change significantly before the unlock date.\n\nToken quantity and percentage of supply are generally more stable analytical measures.\n\n### Analysing Historical Unlocks\n\nReview how the market behaved around previous releases.\n\nConsider:\n\nPrice before and after the unlock\n\nTrading volume\n\nExchange inflows\n\nRecipient wallet behaviour\n\nBroader market conditions\n\nProject announcements\n\nAvoid assuming that the unlock caused every price movement.\n\nThe market may also have responded to:\n\nBitcoin or broader market trends\n\nRegulation\n\nSecurity events\n\nProduct releases\n\nMacroeconomic developments\n\nHistorical behaviour provides context, not certainty.\n\n### Transparent Versus Hidden Unlocks\n\nA transparent project publishes:\n\nAllocation sizes\n\nRecipient categories\n\nRelease dates\n\nVesting contracts\n\nAny schedule changes\n\nHidden or poorly explained unlocks create greater risk.\n\nWarning signs include:\n\nTokens entering circulation unexpectedly\n\nFounder wallets not disclosed\n\nSupply data changing without explanation\n\nNew allocations created through governance\n\nTreasury movements before announcements\n\nVesting contracts controlled by one administrator\n\nUnexpected supply damages market confidence even when the release itself is technically permitted.\n\n### Evaluating Vesting Quality\n\nA credible vesting design generally shows:\n\nLong-term alignment\n\nClearly identified recipients\n\nEnforceable restrictions\n\nTransparent schedules\n\nReasonable founder and investor allocations\n\nRelease periods matching project development\n\nConsequences when contributors leave\n\nLimited unilateral override powers\n\nA weak design may show:\n\nVery short cliffs\n\nImmediate insider liquidity\n\nLarge early unlocks\n\nVague ecosystem allocations\n\nHidden acceleration clauses\n\nAdministrative control over release dates\n\nInsiders gaining governance power before public participants\n\n### A Token Unlock Assessment Framework\n\n\n\n### 1. Identify the Event\n\nHow many tokens unlock?\n\nOn what date?\n\nWhich allocation is involved?\n\n### 2. Measure Its Scale\n\nPercentage of circulating supply\n\nPercentage of total supply\n\nComparison with average trading volume\n\nComparison with available liquidity','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,4,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-13-lesson-05','cognizen-crypto-mastery-foundations-production','3. Analyse Recipients and Key Takeaway','cmf-module-2-13','text','### 3. Analyse Recipients\n\nFounders, employees, investors or community?\n\nWhat was their acquisition price?\n\nAre they active contributors?\n\nHave they sold previous releases?\n\n### 4. Evaluate Market Conditions\n\nIs the market bullish, bearish or consolidating?\n\nIs demand increasing?\n\nIs liquidity strong?\n\n### 5. Review Governance Effects\n\nWill recipients gain voting or staking influence?\n\nCan they change future supply rules?\n\n### 6. Examine Transparency\n\nIs the schedule publicly verifiable?\n\nCan it be changed?\n\nWere previous releases handled as promised?\n\n### 7. Consider Alternative Outcomes\n\nRecipients hold\n\nRecipients stake\n\nRecipients sell gradually\n\nRecipients sell aggressively\n\nThe market absorbs the supply\n\nAnalysis should consider several scenarios rather than assuming one outcome.\n\n### Vesting and Unlock Warning Signs\n\nPotential warning signs include:\n\nA large proportion of supply allocated to insiders\n\nVery short founder or investor vesting\n\nPublic buyers receiving liquidity before product delivery while insiders prepare for early exits\n\nMajor cliff unlocks shortly after launch\n\nPrivate investors holding large unrealised profits\n\nUnlocks exceeding normal market volume\n\nLocked tokens receiving transferable staking rewards\n\nUnclear treasury-release rules\n\nVesting schedules that can be changed unilaterally\n\nOff-chain restrictions that cannot be verified\n\nMissing or conflicting unlock information\n\nA large gap between market capitalisation and fully diluted valuation\n\nRepeated movement of tokens before published release dates\n\n### Common Misunderstandings\n\n#### “Locked Tokens Do Not Matter”\n\nThey represent potential future supply, governance and dilution.\n\n#### “An Unlock Means the Price Must Fall”\n\nRecipients may hold or stake, and demand may absorb the supply.\n\n#### “If the Unlock Is Public, It Cannot Affect Price”\n\nThe expected effect may be priced in, but actual behaviour can still differ.\n\n#### “Vesting Eliminates Insider Risk”\n\nIt delays transferability but does not remove concentrated ownership or governance influence.\n\n#### “Linear Vesting Creates No Market Pressure”\n\nIt may create continuous selling rather than one large event.\n\n#### “A Long Vesting Period Guarantees Alignment”\n\nRecipients may still receive staking rewards, voting power or other benefits.\n\n#### “Circulating Supply Automatically Updates Correctly”\n\nData providers may use different methods or update at different times.\n\n#### “Price Declines After an Unlock Prove Insiders Sold”\n\nBroader market conditions or other events may explain the movement.\n\n#### “Founder Tokens Are Earned Simply Because They Were Allocated”\n\nThe quality of vesting depends on whether continued contribution or measurable milestones are required.\n\n### Module Summary\n\nToken vesting restricts when allocated tokens become transferable.\n\nIt is used to:\n\nAlign founders and employees\n\nRetain contributors\n\nDelay investor selling\n\nCreate predictable supply growth\n\nSupport governance stability\n\nCommon structures include:\n\nCliffs\n\nLinear vesting\n\nPeriodic releases\n\nMilestone-based vesting\n\nHybrid schedules\n\nAn unlock makes tokens transferable but does not prove they will be sold.\n\nThe potential impact depends on:\n\nUnlock size\n\nCirculating supply\n\nTrading volume\n\nMarket liquidity\n\nRecipient cost basis\n\nMarket conditions\n\nRecipient behaviour\n\nLarge unlocks can affect dilution, market sentiment and governance power.\n\nA complete analysis should compare current market capitalisation with fully diluted valuation and examine the entire future release schedule.\n\nVesting information should be verified through official documentation, smart contracts and blockchain activity.\n\n### Key Takeaway\n\nToken vesting delays supply. It does not eliminate it.\n\nBefore evaluating a cryptocurrency’s current price, examine who owns the locked supply, when it becomes transferable, what those holders paid and whether the market has enough demand and liquidity to absorb future releases.\n\nToday’s circulating supply tells you what is available now.\n\nThe vesting schedule tells you what may become available next.\n\nThe next module is 2.14: Cryptocurrency Portfolio Construction.','markdown',NULL,NULL,NULL,5,0,0,0,'',NULL,5,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-13-lesson-06','cognizen-crypto-mastery-foundations-production','Check your understanding','cmf-module-2-13','text','### Check your understanding\n\nAnswer these questions to self-assess your understanding before moving on.\n\n1. What is token vesting?\n\n2. Why do projects use vesting schedules?\n\n3. What is the difference between locked, vested and unlocked tokens?\n\n4. What is a vesting cliff?\n\n5. How does linear vesting work?\n\n6. What are the benefits and risks of milestone-based vesting?\n\n7. Why should unlock size be compared with circulating supply?\n\n8. How can trading volume and liquidity affect an unlock’s market impact?\n\n9. Does an unlock prove that the recipient sold the tokens?\n\n10. Why does an early investor’s cost basis matter?\n\n11. How can an unlock affect governance?\n\n12. What risks arise when locked tokens earn transferable staking rewards?\n\n13. What is accelerated vesting?\n\n14. How does smart contract vesting differ from an off-chain agreement?\n\n15. Why should unlock schedules be considered alongside fully diluted valuation?\n\n16. What is the difference between one large unlock and continuous smaller releases?\n\n17. What information should appear in an unlock calendar?\n\n18. Why must previous unlock performance be interpreted within broader market conditions?\n\n19. What characteristics indicate a credible vesting design?\n\n20. What warning signs may suggest weak insider alignment?','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,6,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `course_sections` (`id`,`course_id`,`title`,`position`,`created_at`) SELECT 'cmf-module-2-14','cognizen-crypto-mastery-foundations-production','Module 2.14: Cryptocurrency Portfolio Construction',14,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
