INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-16-lesson-01','cognizen-crypto-mastery-foundations-production','What Is Position Sizing? and Position Size and Maximum Loss','cmf-module-2-16','text','### Learning Objectives\n\nBy the end of this module, you should be able to:\n\nExplain what position sizing is and why it matters\n\nDistinguish between position size, portfolio allocation and trade risk\n\nCalculate the percentage of a portfolio allocated to an asset\n\nDetermine position size using a predefined maximum loss\n\nUnderstand how volatility, liquidity and conviction affect position size\n\nExplain the relationship between entry price, stop-loss level and capital at risk\n\nRecognise how leverage changes effective exposure\n\nAvoid common position-sizing mistakes\n\nDevelop basic position limits for investing and trading\n\n### Introduction\n\nCryptocurrency participants often spend considerable time deciding what to buy.\n\nThey may research technology, tokenomics, market trends and price charts.\n\nHowever, one of the most important questions receives far less attention:\n\nHow much should be allocated to the position?\n\nA strong asset can still cause serious financial harm when the position is too large.\n\nA weak or speculative asset can be included responsibly when the amount is small enough that complete failure would not damage the broader portfolio.\n\nPosition sizing determines the financial importance of each decision.\n\nIt affects:\n\nPotential profit\n\nPotential loss\n\nPortfolio volatility\n\nEmotional pressure\n\nAbility to remain disciplined\n\nRisk of financial ruin\n\nSuccessful risk management does not require every decision to be correct.\n\nIt requires incorrect decisions to remain survivable.\n\nThis module provides an educational framework rather than personalised investment or trading advice.\n\n### What Is Position Sizing?\n\nPosition sizing is the process of deciding how much capital to allocate to a particular asset or trade.\n\nA position can be expressed as:\n\nA currency amount\n\nA number of tokens\n\nA percentage of the portfolio\n\nA percentage of total trading capital\n\nA defined amount at risk\n\nSuppose a portfolio is worth 20,000 units and 2,000 units are invested in one asset.\n\nThe position represents:\n\n2,000 ÷ 20,000 × 100 = 10 percent of the portfolio\n\nThe ten-percent allocation describes the position’s size relative to the portfolio.\n\nHowever, it does not automatically tell us how much money is at risk.\n\nIf the investor plans to hold the asset through a complete failure, the full 2,000 units may be at risk.\n\nIf a trader has a predefined exit that limits the expected loss to 200 units, the planned trade risk is smaller.\n\n### Position Size Versus Trade Risk\n\nThese terms should not be confused.\n\n### Position Size\n\nThe total financial value of the asset or market exposure.\n\n### Trade Risk\n\nThe amount expected to be lost if the predefined risk-control level is reached.\n\nFor example:\n\nPosition size: 5,000 units\n\nPlanned exit: 8 percent below entry\n\nApproximate capital at risk: 400 units\n\nThe position is worth 5,000 units, but the planned trade risk is 400 units.\n\nThis assumes the position can actually be exited near the chosen level.\n\nSlippage, gaps, exchange failure or poor liquidity may produce a larger loss.\n\nA stop-loss reduces intended risk. It does not guarantee the maximum possible loss.\n\n### Why Position Sizing Matters\n\n\n\n### It Limits the Damage From Being Wrong\n\nEven detailed research can produce an incorrect conclusion.\n\nTechnology may fail, regulation may change or the market may behave unexpectedly.\n\nA manageable position allows the portfolio to survive.\n\n### It Reduces Emotional Pressure\n\nAn oversized position can cause:\n\nConstant price monitoring\n\nPanic selling\n\nRefusal to accept evidence\n\nImpulsive additional buying\n\nSleep disruption\n\nConflict with family or financial obligations\n\nWhen every price movement feels personally threatening, the position may be too large.\n\n### It Preserves Future Opportunity\n\nCapital lost in one oversized position is no longer available for future investments.\n\nRisk management protects the ability to continue learning and participating.\n\n### It Prevents One Asset From Controlling the Portfolio\n\nA portfolio should not depend accidentally on one token, exchange or market narrative.\n\n### Portfolio Allocation Percentage\n\nThe simplest position-sizing calculation is:\n\nPosition allocation = Position value ÷ Total portfolio value × 100\n\nSuppose:\n\nTotal cryptocurrency portfolio: 50,000 units\n\nPosition value: 7,500 units\n\nThe allocation is:\n\n7,500 ÷ 50,000 × 100 = 15 percent\n\nThis calculation should be repeated as prices change.\n\nA position that began at ten percent may grow to thirty percent after a strong rally.\n\nNo new purchase is required for concentration risk to increase.\n\n### Position Size and Maximum Loss\n\nA risk-based approach begins by deciding how much capital can be lost on one decision.\n\nThe process is:\n\nDetermine the total capital\n\nSelect a maximum percentage or amount at risk\n\nIdentify the distance between the entry and risk-control level\n\nCalculate the position size\n\nThe simplified formula is:\n\nPosition size = Maximum capital at risk ÷ Percentage distance to exit','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,1,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-16-lesson-02','cognizen-crypto-mastery-foundations-production','Position-Sizing Example and Liquidity-Based Position Sizing','cmf-module-2-16','text','### Position-Sizing Example\n\nSuppose:\n\nTrading capital: 20,000 units\n\nMaximum risk per trade: 1 percent\n\nMaximum capital at risk: 200 units\n\nEntry price: 10 units\n\nPlanned exit price: 9 units\n\nThe difference between entry and exit is:\n\n10 percent\n\nThe position size is:\n\n200 ÷ 0.10 = 2,000 units\n\nAt an entry price of 10 units, the number of tokens would be:\n\n2,000 ÷ 10 = 200 tokens\n\nIf the position exits at 9 units, the expected loss is approximately:\n\n200 tokens × 1-unit decline = 200 units\n\nThis excludes fees, slippage and other execution costs.\n\n### Including Transaction Costs\n\nTrading costs increase the real amount at risk.\n\nPossible costs include:\n\nEntry fee\n\nExit fee\n\nBid-ask spread\n\nSlippage\n\nNetwork fees\n\nBorrowing or funding charges\n\nSuppose the intended maximum loss is 200 units, but expected total costs are 20 units.\n\nOnly 180 units should be allocated to price risk if the overall maximum is to remain near 200.\n\nThe calculation becomes:\n\nAvailable price risk = Maximum total risk − Estimated costs\n\nIgnoring costs can cause repeated small breaches of the risk limit.\n\n### Stop-Loss Distance\n\nThe distance between entry and exit has a major effect on position size.\n\nSuppose the maximum acceptable loss remains 200 units.\n\n#### Five-Percent Exit Distance\n\n200 ÷ 0.05 = 4,000-unit position\n\n#### Ten-Percent Exit Distance\n\n200 ÷ 0.10 = 2,000-unit position\n\n#### Twenty-Percent Exit Distance\n\n200 ÷ 0.20 = 1,000-unit position\n\nA wider stop requires a smaller position if the same amount of capital is to remain at risk.\n\nThis is a central principle:\n\nWider risk tolerance should reduce position size—not automatically increase the amount of money at risk.\n\n### Choosing a Risk-Control Level\n\nThe exit level should be based on a reasoned assessment rather than an arbitrary percentage.\n\nPossible considerations include:\n\nMarket structure\n\nSupport levels\n\nVolatility\n\nInvestment-thesis invalidation\n\nLiquidity\n\nHolding period\n\nAsset risk\n\nFor a short-term trade, the exit may be linked to a chart level that invalidates the setup.\n\nFor a long-term investment, risk may be managed through:\n\nSmaller initial allocation\n\nDiversification\n\nFundamental review\n\nMaximum portfolio weighting\n\nThesis invalidation\n\nA long-term investor may not use a tight stop-loss, but this makes initial position size even more important.\n\n### Position Sizing for Long-Term Investments\n\nLong-term investors often cannot define one precise exit price.\n\nThe asset may experience substantial volatility while the long-term thesis remains intact.\n\nPosition size can instead be based on a severe-loss scenario.\n\nAsk:\n\nWhat happens if this asset loses eighty percent—or becomes worthless?\n\nSuppose an investor can tolerate a maximum loss of 1,000 units in a highly speculative project.\n\nIf complete failure is possible, the maximum position may be 1,000 units.\n\nFor a more established but still volatile asset, the investor may model a fifty- or seventy-percent decline.\n\nThe assumed loss should be realistic rather than optimistic.\n\n### Position Sizing by Asset Risk\n\nDifferent assets should not automatically receive the same allocation.\n\nA risk hierarchy might consider:\n\n### More Established Assets\n\nMay have:\n\nLonger operating history\n\nGreater liquidity\n\nWider adoption\n\nStronger infrastructure\n\nThey can still experience severe declines.\n\n### Emerging Assets\n\nMay have:\n\nGrowing adoption\n\nShorter operating history\n\nModerate liquidity\n\nGreater execution uncertainty\n\n### Speculative Assets\n\nMay have:\n\nLow liquidity\n\nConcentrated ownership\n\nLimited products\n\nHigh token inflation\n\nSignificant probability of failure\n\nHigher uncertainty generally supports a smaller position.\n\nThe purpose is not to predict which asset will succeed. It is to limit the consequences if it does not.\n\n### Volatility-Based Position Sizing\n\nMore volatile assets experience larger routine price movements.\n\nUsing the same position size across assets can therefore create very different risk exposures.\n\nSuppose:\n\nAsset A typically moves 3 percent per day\n\nAsset B typically moves 15 percent per day\n\nAn equal capital allocation may allow Asset B to dominate portfolio volatility.\n\nA volatility-based approach assigns smaller positions to assets with greater price variability.\n\nOne commonly used volatility measure is average true range, or ATR, which will be discussed in more detail in later technical-analysis lessons.\n\nThe broad principle is:\n\nAs expected volatility increases, position size should generally decrease.\n\n### Liquidity-Based Position Sizing\n\nPosition size should also reflect the ability to exit.\n\nA large position in an illiquid token may be difficult to sell without causing substantial price impact.\n\nBefore setting the size, examine:\n\nGenuine trading volume\n\nOrder-book depth\n\nBid-ask spread\n\nDecentralised exchange liquidity\n\nNumber of credible trading venues\n\nWithdrawal reliability\n\nA position should be small enough that it can be exited under realistic—not ideal—market conditions.\n\nReported daily volume may be misleading, so order-book and liquidity-pool depth also matter.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,2,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-16-lesson-03','cognizen-crypto-mastery-foundations-production','Conviction and Position Size and Correlated Positions','cmf-module-2-16','text','### Conviction and Position Size\n\nInvestors sometimes allocate more capital to their highest-conviction ideas.\n\nThis can be reasonable, but conviction must be evidence-based.\n\nHigh conviction should reflect:\n\nDetailed fundamental analysis\n\nStrong adoption evidence\n\nSustainable tokenomics\n\nClear value capture\n\nAdequate liquidity\n\nA favourable risk-and-reward relationship\n\nDefined invalidation conditions\n\nConviction should not come primarily from:\n\nCommunity loyalty\n\nFounder admiration\n\nRecent price increases\n\nRepeated social-media exposure\n\nPersonal desire to recover losses\n\nConfidence does not reduce the probability of an unknown event.\n\nEven the strongest thesis requires a position limit.\n\n### The Difference Between Confidence and Certainty\n\nA participant may believe an investment has a high probability of success.\n\nThat does not make failure impossible.\n\nMarkets contain:\n\nUnknown information\n\nChanging conditions\n\nHuman error\n\nFraud\n\nTechnology risk\n\nRegulatory risk\n\nPosition sizing exists because certainty is unavailable.\n\nThe more certain a person feels, the more important it may be to challenge the analysis before increasing exposure.\n\nExtreme confidence is often present near market peaks and inside highly committed communities.\n\n### Scaling Into a Position\n\nScaling in means entering a position through several smaller purchases rather than buying the full amount immediately.\n\nPotential advantages include:\n\nReduced dependence on one entry price\n\nTime to reassess the thesis\n\nLower emotional pressure\n\nAbility to observe market liquidity\n\nReduced impact of poor timing\n\nPotential disadvantages include:\n\nAdditional fees\n\nThe asset rising before the position is complete\n\nRepeated buying into a deteriorating asset\n\nLack of a clear maximum allocation\n\nA scaling plan should define:\n\nTotal maximum position\n\nNumber of planned entries\n\nConditions for each entry\n\nConditions that cancel further purchases\n\nScaling in is not permission to keep adding indefinitely as price falls.\n\n### Scaling Out of a Position\n\nScaling out means reducing a holding through several smaller sales.\n\nPotential advantages include:\n\nLower market impact\n\nReduced pressure to identify one perfect exit\n\nGradual risk reduction\n\nContinued participation if the price rises further\n\nPotential disadvantages include:\n\nAdditional fees and taxes\n\nRemaining exposure during a decline\n\nAn unclear exit process\n\nThe plan should specify why and when each reduction occurs.\n\n### Pyramiding\n\nPyramiding means adding to a position as the market moves in the expected direction.\n\nA disciplined pyramiding approach may:\n\nAdd only after the original position is profitable\n\nKeep total risk within a defined limit\n\nMove risk-control levels appropriately\n\nStop adding when maximum allocation is reached\n\nAn undisciplined approach can lead to buying increasingly large amounts near a market peak.\n\nA rising price is not enough to justify a larger position. Valuation, risk and total exposure must still be assessed.\n\n### Averaging Down\n\nAveraging down means purchasing more after the price falls, reducing the average acquisition price.\n\nThis may be rational when:\n\nThe original thesis remains valid\n\nThe asset’s value has improved relative to price\n\nThe maximum allocation has not been exceeded\n\nLiquidity and project quality remain strong\n\nIt is dangerous when:\n\nThe project is deteriorating\n\nToken supply is increasing unexpectedly\n\nThe investor is chasing losses\n\nThe purchase has no predefined limit\n\nThe asset is failing permanently\n\nA lower price does not automatically mean lower risk.\n\nSometimes price falls because risk has increased.\n\n### Maximum Position Limits\n\nA portfolio policy may define maximum allocations for:\n\nOne core asset\n\nOne emerging asset\n\nOne speculative token\n\nOne blockchain ecosystem\n\nOne exchange\n\nOne stablecoin\n\nOne DeFi protocol\n\nLimits should be defined before the market becomes emotionally intense.\n\nFor example, a policy might state that no speculative position may exceed a small percentage of the portfolio.\n\nThe exact percentage depends on individual circumstances.\n\nThe principle is that uncertainty should have a financial boundary.\n\n### Aggregate Exposure\n\nSeveral positions may appear separate while expressing the same underlying view.\n\nFor example, an investor might hold:\n\nThe native token of a blockchain\n\nSeveral applications built on it\n\nA liquid-staking token linked to it\n\nA lending position collateralised by it\n\nThese positions share substantial ecosystem exposure.\n\nPosition sizing should consider the aggregate risk rather than treating each token independently.\n\nThe total exposure may be much larger than any single line item suggests.\n\n### Correlated Positions\n\nIf several positions tend to decline together, the portfolio’s effective risk may be concentrated.\n\nSuppose five trades each risk one percent of capital.\n\nIf they are highly correlated, one market event could trigger all five losses simultaneously.\n\nThe portfolio is effectively risking more than one percent on the same underlying outcome.\n\nPosition sizing should account for:\n\nMarket correlation\n\nEcosystem dependency\n\nShared collateral\n\nCommon narratives\n\nBroad risk sentiment\n\nRisk per trade is not the same as total portfolio risk.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,3,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-16-lesson-04','cognizen-crypto-mastery-foundations-production','Open Risk and Compounding Losses','cmf-module-2-16','text','### Open Risk\n\nOpen risk is the total amount currently exposed across active positions.\n\nA trader may limit risk per position while still accumulating excessive total risk.\n\nSuppose:\n\nFive open trades\n\nEach risks two percent of capital\n\nIf all fail, the planned loss may be ten percent before considering slippage.\n\nA trading plan may therefore establish:\n\nMaximum risk per position\n\nMaximum total open risk\n\nMaximum exposure to correlated positions\n\nMaximum daily or weekly loss\n\nThese limits help prevent several individually acceptable trades from combining into an unacceptable portfolio risk.\n\n### Leverage and Position Size\n\nLeverage allows a participant to control exposure larger than the deposited capital.\n\nSuppose a trader deposits 1,000 units and uses five-times leverage.\n\nThe market exposure is:\n\n1,000 × 5 = 5,000 units\n\nThe position size is 5,000 units, not merely the 1,000-unit collateral deposit.\n\nA ten-percent adverse movement on the 5,000-unit position represents approximately 500 units before fees and liquidation effects.\n\nThat is a fifty-percent loss of the deposited capital.\n\nLeverage changes the speed at which losses occur and reduces the distance to liquidation.\n\n### Effective Exposure\n\nEffective exposure is the actual market value controlled after accounting for leverage and derivatives.\n\nA portfolio dashboard should include:\n\nCash deposited\n\nPosition notional value\n\nLeverage\n\nLiquidation level\n\nMaximum intended loss\n\nFunding costs\n\nFocusing only on collateral can create the illusion that a leveraged position is small.\n\nThe market responds to the notional exposure.\n\n### Leverage Does Not Replace Position Sizing\n\nSome traders use leverage while reducing the amount of collateral committed.\n\nThis can create capital efficiency, but it does not remove risk.\n\nThe trade remains exposed to:\n\nLiquidation\n\nFunding charges\n\nExchange failure\n\nSlippage\n\nRapid price movement\n\nReduced ability to wait\n\nLeverage should be considered only after the underlying position size and maximum loss have been calculated.\n\nStarting with the desired leverage ratio encourages excessive exposure.\n\nStart with risk, then calculate the position.\n\n### Risk-to-Reward and Position Size\n\nRisk-to-reward compares the potential loss with the potential gain.\n\nSuppose:\n\nPlanned loss: 200 units\n\nPotential gain: 600 units\n\nThe risk-to-reward ratio is:\n\n1 to 3\n\nA favourable ratio does not guarantee that the trade is attractive.\n\nProbability also matters.\n\nA trade with a one-to-ten ratio may still be poor if the chance of success is extremely low.\n\nPosition size should be based on the amount at risk, not the hoped-for reward.\n\nRisk-to-reward will be covered in greater detail in the next module.\n\n### Percentage Risk Models\n\nSome traders define a fixed percentage of trading capital that may be lost on one position.\n\nFor example:\n\n0.5 percent\n\n1 percent\n\n2 percent\n\nThe appropriate amount depends on:\n\nStrategy reliability\n\nTrading frequency\n\nAsset volatility\n\nCorrelation\n\nExperience\n\nFinancial capacity\n\nA fixed-percentage model automatically reduces position sizes after losses because the capital base becomes smaller.\n\nIt also increases size gradually as capital grows.\n\nHowever, no fixed percentage is universally appropriate.\n\n### Fixed Monetary Risk\n\nAnother method limits each position to a fixed monetary loss.\n\nFor example:\n\nMaximum planned loss per position: 100 units\n\nThis method is simple.\n\nHowever, the amount becomes a changing percentage of the portfolio as capital rises or falls.\n\nA 100-unit risk may be minor in a 50,000-unit portfolio but excessive in a 1,000-unit account.\n\nPercentage-based risk often scales more naturally with portfolio size.\n\n### Maximum Drawdown Limits\n\nA trader or investor may define a maximum acceptable portfolio drawdown.\n\nPossible rules may include:\n\nReduce position sizes after a specified decline\n\nStop opening new trades temporarily\n\nReview the strategy\n\nMove to simulated trading\n\nReassess market conditions\n\nThe purpose is to interrupt a damaging cycle of:\n\nLoss\n\nEmotional frustration\n\nLarger risk\n\nFurther loss\n\nA drawdown limit should trigger review rather than encourage immediate attempts to recover capital.\n\n### Losing Streaks\n\nEven a profitable strategy can experience consecutive losses.\n\nSuppose a strategy has a sixty-percent success rate.\n\nIt can still produce several losses in a row.\n\nPosition sizing should allow the participant to survive normal losing streaks.\n\nIf each loss risks ten percent of capital:\n\nFive consecutive full losses would produce a severe drawdown\n\nIf each loss risks one percent:\n\nThe same losing streak is far more manageable\n\nThe objective is not to assume the worst will always occur. It is to ensure that ordinary statistical variation does not cause ruin.\n\n### Compounding Losses\n\nLosses reduce the capital available for future decisions.\n\nA fifty-percent decline requires a one-hundred-percent gain to recover.\n\nAn eighty-percent decline requires a four-hundred-percent gain.\n\nThis asymmetry makes large losses especially damaging.\n\nPosition sizing helps prevent one or several decisions from creating a drawdown that becomes mathematically difficult to recover.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,4,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-16-lesson-05','cognizen-crypto-mastery-foundations-production','Position Size and Emotional Comfort and Position-Sizing Checklist','cmf-module-2-16','text','### Position Size and Emotional Comfort\n\nA practical test is to observe emotional reactions.\n\nA position may be too large when the holder:\n\nChecks the price constantly\n\nCannot sleep normally\n\nHides the position from family\n\nFeels unable to sell\n\nRejects contradictory evidence\n\nChanges the plan after every small movement\n\nUses essential money\n\nEmotional discomfort is not a mathematical measure, but it can reveal that the financial exposure exceeds the person’s genuine tolerance.\n\n### Position Size and Investment Thesis\n\nThe investment thesis should determine the conditions under which a position remains valid.\n\nPosition size may be reduced when:\n\nAdoption weakens\n\nTokenomics deteriorate\n\nSecurity problems emerge\n\nGovernance centralises\n\nValuation becomes excessive\n\nLiquidity declines\n\nPosition sizing is not only an entry decision.\n\nIt should respond to changing evidence.\n\n### Portfolio Rebalancing\n\nA successful asset may grow beyond its intended allocation.\n\nSuppose a token rises from ten percent to forty percent of the portfolio.\n\nThe investor now has substantially greater concentration risk.\n\nPossible responses include:\n\nSelling part of the position\n\nRedirecting new capital elsewhere\n\nRaising the target only after updated analysis\n\nAccepting the concentration deliberately\n\nDoing nothing is also a decision.\n\nThe position should not remain oversized merely because selling a winner feels uncomfortable.\n\n### Position Sizing for Stablecoins and Yield Products\n\nA stablecoin may have low price volatility but still carry:\n\nDepegging risk\n\nIssuer risk\n\nReserve risk\n\nRegulatory risk\n\nSmart contract risk\n\nA lending or staking product adds another layer of platform risk.\n\nPosition size should reflect total potential loss, not only historical price movement.\n\nA position can appear stable until a failure causes a sudden and severe loss.\n\n### Position Sizing for Illiquid Tokens\n\nIlliquid tokens may show high expected return but require especially cautious sizing.\n\nRisks include:\n\nWide spreads\n\nLarge price impact\n\nDifficult exits\n\nManipulation\n\nExchange delisting\n\nLiquidity removal\n\nThe correct position may be substantially smaller than the amount an investor can technically purchase.\n\nBeing able to enter is not the same as being able to exit.\n\n### A Basic Position-Sizing Process\n\n\n\n### Step 1: Define the Total Capital Base\n\nUse the capital genuinely allocated to the strategy or portfolio.\n\nDo not include emergency money or funds required for essential obligations.\n\n### Step 2: Determine Maximum Acceptable Loss\n\nChoose the amount that can be lost without creating unacceptable harm.\n\n### Step 3: Identify the Risk Scenario\n\nFor a trade, this may be the distance to a planned exit.\n\nFor an investment, it may be a severe drawdown or complete-failure assumption.\n\n### Step 4: Calculate the Position\n\nUse:\n\nPosition size = Maximum capital at risk ÷ Assumed percentage loss\n\n### Step 5: Adjust for Costs and Liquidity\n\nInclude fees, slippage, market depth and execution uncertainty.\n\n### Step 6: Check Portfolio Concentration\n\nCombine the position with related ecosystem, platform and market exposures.\n\n### Step 7: Confirm Emotional and Financial Suitability\n\nAsk whether the position can be held and managed without compromising essential financial security or disciplined judgement.\n\n### Example: Long-Term Speculative Position\n\nSuppose:\n\nCryptocurrency portfolio: 30,000 units\n\nMaximum acceptable loss from one speculative asset: 300 units\n\nFailure scenario: 100-percent loss\n\nMaximum position size:\n\n300 ÷ 1.00 = 300 units\n\nThe position represents:\n\n300 ÷ 30,000 × 100 = 1 percent of the portfolio\n\nIf the token fails completely, the loss remains within the predetermined limit.\n\n### Example: Moderate-Risk Investment\n\nSuppose:\n\nPortfolio: 30,000 units\n\nMaximum acceptable loss: 600 units\n\nStress scenario: 60-percent decline\n\nPosition size:\n\n600 ÷ 0.60 = 1,000 units\n\nPortfolio allocation:\n\n1,000 ÷ 30,000 × 100 = approximately 3.33 percent\n\nThis calculation does not predict a maximum actual loss.\n\nIt creates an allocation based on a defined scenario.\n\n### Example: Short-Term Trade\n\nSuppose:\n\nTrading account: 25,000 units\n\nMaximum planned risk: 1 percent\n\nRisk amount: 250 units\n\nEntry price: 50\n\nStop level: 47.50\n\nRisk per token: 2.50\n\nNumber of tokens:\n\n250 ÷ 2.50 = 100 tokens\n\nPosition value:\n\n100 × 50 = 5,000 units\n\nThe position uses twenty percent of the account’s capital but risks approximately one percent if the exit occurs as planned.\n\nLeverage, slippage and gaps could increase the actual loss.\n\n### Position-Sizing Checklist\n\nBefore opening or increasing a position, ask:\n\nWhat is the total relevant portfolio or trading capital?\n\nWhat is the maximum acceptable loss?\n\nIs the asset an investment, trade or speculation?\n\nWhat event or price invalidates the decision?\n\nWhat percentage decline is being assumed?\n\nWhat position size follows from that risk?\n\nWhat costs and slippage should be included?\n\nIs the asset sufficiently liquid?\n\nDoes the position share risk with existing holdings?\n\nWhat is the total ecosystem or platform exposure?\n\nIs leverage involved?\n\nWhat is the true notional exposure?\n\nCould several open positions lose simultaneously?\n\nDoes the position exceed a predefined allocation limit?\n\nCan the full loss be tolerated financially and emotionally?\n\nAm I increasing size because of evidence or emotion?\n\nWhat would cause the position to be reduced?','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,5,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-16-lesson-06','cognizen-crypto-mastery-foundations-production','Common Position-Sizing Mistakes and Key Takeaway','cmf-module-2-16','text','### Common Position-Sizing Mistakes\n\n\n\n### Deciding Size From Potential Profit\n\nLarge expected returns do not justify unlimited exposure.\n\n### Investing a Round Amount Without Risk Analysis\n\nConvenient numbers may have no relationship to acceptable loss.\n\n### Using the Same Size for Every Asset\n\nAssets have different volatility, liquidity and failure risks.\n\n### Ignoring Correlation\n\nSeveral small positions can combine into one large underlying exposure.\n\n### Treating a Stop-Loss as Guaranteed\n\nPrice gaps, slippage and exchange problems can create larger losses.\n\n### Increasing Size After Losses\n\nThis attempts to recover money through greater risk.\n\n### Allowing Winners to Become Uncontrolled Concentrations\n\nPrice appreciation can change the portfolio’s risk profile.\n\n### Confusing Collateral With Exposure\n\nA leveraged position controls more value than the deposited margin.\n\n### Averaging Down Without a Maximum Limit\n\nRepeated buying can turn a small error into a major loss.\n\n### Sizing According to Social-Media Confidence\n\nPopularity and certainty are not risk measures.\n\n### Common Misunderstandings\n\n#### “A Strong Investment Deserves a Very Large Position”\n\nUnexpected failure remains possible, and valuation may already be excessive.\n\n#### “A Small Token Price Allows Me to Buy More Safely”\n\nUnit price does not determine risk or valuation.\n\n#### “A Stop-Loss Defines My Exact Maximum Loss”\n\nExecution can occur at a worse price or fail entirely.\n\n#### “Using Leverage With Less Cash Means the Position Is Smaller”\n\nEconomic exposure is determined by the full notional value.\n\n#### “Several One-Percent Risks Mean I Am Only Risking One Percent”\n\nCorrelated positions may all lose together.\n\n#### “Averaging Down Always Improves the Investment”\n\nIt reduces average cost while increasing total exposure.\n\n#### “Position Sizing Is Only for Traders”\n\nLong-term investors also need limits for asset, custody and project failure.\n\n#### “Higher Conviction Means Lower Risk”\n\nConviction is a belief. Risk exists independently of belief.\n\n#### “A Stablecoin Position Does Not Need a Limit”\n\nStablecoins and yield platforms can fail suddenly.\n\n### Module Summary\n\nPosition sizing determines how much capital is allocated to an asset or trade.\n\nIt is different from the amount planned to be lost.\n\nA position may be large while the intended trade risk is smaller because of a predefined exit.\n\nA risk-based sizing process begins with the maximum acceptable loss.\n\nThe simplified formula is:\n\nPosition size = Maximum capital at risk ÷ Percentage distance to the risk-control level\n\nFor long-term investments, the percentage may be based on a severe drawdown or complete-failure scenario.\n\nPosition size should account for:\n\nVolatility\n\nLiquidity\n\nFees\n\nSlippage\n\nToken quality\n\nCorrelation\n\nCustody\n\nLeverage\n\nPortfolio concentration\n\nSeveral individually small positions can create substantial combined risk when they depend on the same market, ecosystem or platform.\n\nLeverage changes effective exposure and can accelerate liquidation.\n\nThe objective of position sizing is not to remove losses.\n\nIt is to ensure that each loss remains financially survivable and that no single decision gains excessive control over the portfolio.\n\n### Key Takeaway\n\nYou cannot control whether the next cryptocurrency decision will succeed.\n\nYou can control how much damage it causes if it fails.\n\nDecide the acceptable loss first. Then calculate the position.\n\nPosition sizing transforms uncertainty from a threat to the entire portfolio into a defined and manageable risk.','markdown',NULL,NULL,NULL,4,0,0,0,'',NULL,6,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-16-lesson-07','cognizen-crypto-mastery-foundations-production','Check your understanding','cmf-module-2-16','text','### Check your understanding\n\nAnswer these questions to self-assess your understanding before moving on.\n\n1. What is position sizing?\n\n2. How does position size differ from capital at risk?\n\n3. How is a portfolio allocation percentage calculated?\n\n4. What is the basic risk-based position-sizing formula?\n\n5. Why must trading costs be included in the calculation?\n\n6. How does a wider stop-loss distance affect position size?\n\n7. How can long-term investors size positions without a precise stop-loss?\n\n8. Why should more volatile assets generally receive smaller positions?\n\n9. How does liquidity affect the appropriate position size?\n\n10. What is the difference between conviction and certainty?\n\n11. What are the potential benefits and risks of scaling into a position?\n\n12. Why can averaging down be dangerous?\n\n13. What is aggregate exposure?\n\n14. Why can correlated positions create greater risk than expected?\n\n15. What is open risk?\n\n16. How does leverage change effective exposure?\n\n17. Why should position size be based on risk rather than desired leverage?\n\n18. What is the purpose of a maximum drawdown limit?\n\n19. How can a losing streak affect an oversized strategy?\n\n20. What emotional behaviours may indicate that a position is too large?\n\n21. Why do stablecoin and yield positions still require limits?\n\n22. What steps form a basic position-sizing process?','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,7,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `course_sections` (`id`,`course_id`,`title`,`position`,`created_at`) SELECT 'cmf-module-2-17','cognizen-crypto-mastery-foundations-production','Module 2.17: Risk-to-Reward Principles',17,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
