INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-19-lesson-01','cognizen-crypto-mastery-foundations-production','What Is a Candlestick? and Closing Location','cmf-module-2-19','text','### Learning Objectives\n\nBy the end of this module, you should be able to:\n\nExplain what a candlestick chart represents\n\nIdentify the open, high, low and close of a candle\n\nDistinguish between bullish and bearish candles\n\nInterpret candle bodies, wicks and trading ranges\n\nUnderstand how timeframe affects candlestick meaning\n\nRecognise several common single- and multi-candle formations\n\nEvaluate candlesticks within trend, volume and market context\n\nAvoid treating individual patterns as guaranteed trading signals\n\nApply a structured process when reading a candlestick chart\n\n### Introduction\n\nCandlestick charts are among the most widely used tools in cryptocurrency market analysis.\n\nEach candlestick summarises how an asset’s price moved during a selected period.\n\nA candle may represent:\n\nOne minute\n\nOne hour\n\nFour hours\n\nOne day\n\nOne week\n\nOne month\n\nCandlesticks allow traders and investors to see more than the final price.\n\nThey show:\n\nWhere the period began\n\nWhere it ended\n\nHow high price moved\n\nHow low price moved\n\nWhether buyers or sellers controlled the close\n\nHow much volatility occurred\n\nA single candle can provide useful information about market behaviour.\n\nHowever, no candle should be interpreted in isolation.\n\nIts meaning depends on:\n\nThe broader trend\n\nIts location on the chart\n\nNearby support and resistance\n\nTrading volume\n\nMarket liquidity\n\nThe candles that came before and after it\n\nCandlestick analysis is therefore a method of reading market behaviour—not a collection of shapes that automatically predict the future.\n\n### What Is a Candlestick?\n\nA candlestick is a visual representation of four price points during a specified period:\n\nOpen\n\nHigh\n\nLow\n\nClose\n\nThese are commonly abbreviated as OHLC.\n\n### Open\n\nThe first traded price during the selected period.\n\n### High\n\nThe highest price reached during the period.\n\n### Low\n\nThe lowest price reached during the period.\n\n### Close\n\nThe final traded price when the period ends.\n\nTogether, these values show both the direction and range of price movement.\n\n### The Anatomy of a Candle\n\nA candlestick contains two main parts:\n\nThe body\n\nThe wicks\n\n### The Body\n\nThe body represents the distance between the opening and closing prices.\n\nA large body indicates a substantial difference between the open and close.\n\nA small body indicates that the market closed relatively close to where it opened.\n\n### The Wicks\n\nThe thin lines above and below the body are called:\n\nWicks\n\nShadows\n\nTails\n\nThe upper wick extends toward the period’s highest price.\n\nThe lower wick extends toward the period’s lowest price.\n\nWicks show where price travelled before returning toward the closing level.\n\n### Bullish Candles\n\nA bullish candle forms when the closing price is higher than the opening price.\n\nThis means price increased during that period.\n\nThe body begins at the opening price and ends at the higher closing price.\n\nCharting platforms commonly display bullish candles in green or white, although colours can be customised.\n\nA bullish candle indicates that buyers achieved a higher closing price than the price at which the period began.\n\nIt does not necessarily mean buyers controlled every moment of the period.\n\nPrice may have fallen first and recovered later.\n\n### Bearish Candles\n\nA bearish candle forms when the closing price is lower than the opening price.\n\nThis means price declined during the period.\n\nThe body begins at the opening price and ends at the lower closing price.\n\nBearish candles are commonly displayed in red or black.\n\nA bearish candle indicates that sellers achieved a lower closing price than the opening price.\n\nHowever, price may still have risen significantly before sellers regained control.\n\nThe wicks reveal this intraperiod movement.\n\n### Candle Range\n\nThe total candle range is the distance between the high and low.\n\nThe formula is:\n\nRange = High price − Low price\n\nSuppose a daily candle has:\n\nHigh: 110\n\nLow: 90\n\nIts total range is:\n\n110 − 90 = 20 units\n\nThe range provides information about volatility during that period.\n\nA larger-than-normal range may indicate:\n\nStrong momentum\n\nNews-driven activity\n\nA breakout\n\nLiquidations\n\nPanic or euphoria\n\nA small range may indicate:\n\nConsolidation\n\nLow participation\n\nIndecision\n\nReduced volatility\n\nRange should be compared with previous candles rather than judged without context.\n\n### Body Size\n\nThe size of the body helps describe the strength of movement between the open and close.\n\n### Large Bullish Body\n\nMay suggest strong buying pressure during the period.\n\n### Large Bearish Body\n\nMay suggest strong selling pressure.\n\n### Small Body\n\nMay indicate:\n\nIndecision\n\nBalance between buyers and sellers\n\nReduced momentum\n\nA temporary pause\n\nBody size is relative.\n\nA body considered large on one asset or timeframe may be ordinary on another.\n\n### Closing Location\n\nThe candle’s closing position within its range can provide useful information.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,1,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-19-lesson-02','cognizen-crypto-mastery-foundations-production','Close Near the High and Candle Overlap','cmf-module-2-19','text','### Close Near the High\n\nSuggests buyers maintained control into the end of the period.\n\n### Close Near the Low\n\nSuggests sellers maintained control into the close.\n\n### Close Near the Middle\n\nSuggests neither side achieved decisive control.\n\nThe close is often regarded as more significant than temporary intraperiod movement because it shows where the market accepted price when the candle completed.\n\nAn unfinished candle can change substantially before closing.\n\n### Understanding Upper Wicks\n\nAn upper wick shows that price traded above the candle body but did not remain there.\n\nA long upper wick may indicate that:\n\nBuyers pushed price upward\n\nSellers responded\n\nHigher prices were rejected\n\nProfit-taking occurred\n\nResistance was encountered\n\nHowever, a long upper wick is not automatically bearish.\n\nIn a strong uptrend, it may simply reflect volatility before further continuation.\n\nIts meaning depends on where it appears.\n\nA long upper wick at major resistance after a prolonged rally may be more significant than the same wick in the middle of an ordinary trading range.\n\n### Understanding Lower Wicks\n\nA lower wick shows that price traded below the candle body before recovering.\n\nA long lower wick may indicate that:\n\nSellers pushed price lower\n\nBuyers entered\n\nLower prices were rejected\n\nShort positions were closed\n\nSupport attracted demand\n\nA long lower wick is not automatically bullish.\n\nIn a strong downtrend, a temporary recovery may fail and selling may continue.\n\nContext determines whether the wick represents meaningful demand or only a brief reaction.\n\n### Rejection\n\nRejection occurs when price moves into an area but fails to remain there.\n\nA wick often provides visual evidence of rejection.\n\nFor example:\n\nPrice falls below support\n\nBuyers enter aggressively\n\nPrice recovers before the candle closes\n\nA long lower wick remains\n\nThis may indicate rejection of lower prices.\n\nHowever, rejection should ideally be supported by:\n\nA meaningful chart level\n\nIncreased volume\n\nFollow-through from later candles\n\nA favourable broader market structure\n\nA wick alone does not prove that a reversal has begun.\n\n### Candlestick Timeframes\n\nA candlestick has meaning only in relation to its timeframe.\n\nA one-hour candle summarises one hour of trading.\n\nA daily candle summarises twenty-four hours.\n\nA weekly candle summarises an entire week.\n\nThe same market movement can appear very different across timeframes.\n\nOne daily candle may contain:\n\nTwenty-four hourly candles\n\nNinety-six fifteen-minute candles\n\nHundreds of shorter candles\n\nA bullish daily candle can therefore include several bearish intraday movements.\n\n### Higher-Timeframe Candles\n\nHigher-timeframe candles usually contain more trading activity and can provide stronger information about the broader market.\n\nA weekly rejection at major resistance may carry more significance than a five-minute rejection at an arbitrary level.\n\nHowever, higher-timeframe candles develop slowly.\n\nWaiting for them to close may delay entry or confirmation.\n\n### Lower-Timeframe Candles\n\nLower-timeframe candles provide more detail and more frequent signals.\n\nThey also contain more:\n\nNoise\n\nFalse breakouts\n\nShort-term volatility\n\nTrading costs\n\nEmotional pressure\n\nThe timeframe should match the participant’s objective.\n\n### Candle Close Versus Intraperiod Movement\n\nA candle should not be considered complete until the timeframe ends.\n\nA candle that appears strongly bullish halfway through the period may close bearish.\n\nFor example:\n\nPrice opens at 100\n\nRises to 115\n\nFalls to 95\n\nCloses at 98\n\nDuring the period, the candle initially appeared bullish.\n\nAt completion, it records:\n\nA bearish body\n\nA long upper wick\n\nRejection of higher prices\n\nActing on an unfinished candle can therefore produce misleading conclusions.\n\nSome strategies require waiting for the candle close before treating a signal as confirmed.\n\n### The Relationship Between Candles\n\nCandlestick analysis becomes more useful when examining sequences rather than isolated candles.\n\nA series of candles can reveal:\n\nTrend\n\nMomentum\n\nVolatility\n\nBuyer and seller persistence\n\nRepeated rejection\n\nMarket compression\n\nBreakout attempts\n\nFor example, several large bullish candles closing near their highs may indicate strong momentum.\n\nA sequence of smaller bodies with long upper wicks may suggest that upward momentum is weakening.\n\nThe transition between candle behaviour can be more informative than one named pattern.\n\n### Momentum Through Candlesticks\n\nStrengthening bullish momentum may appear as:\n\nIncreasing body size\n\nCloses near candle highs\n\nLimited lower movement\n\nBreaks above previous highs\n\nRising volume\n\nWeakening bullish momentum may appear as:\n\nSmaller bodies\n\nLonger upper wicks\n\nFailure to reach new highs\n\nGreater overlap\n\nLower volume\n\nThe same principles apply in reverse to bearish momentum.\n\nCandles do not measure momentum perfectly, but they provide a visual representation of how aggressively price is moving.\n\n### Candle Overlap\n\nCandle overlap occurs when several candles trade within similar price ranges.\n\nHigh overlap may suggest:\n\nConsolidation\n\nIndecision\n\nBalance\n\nWeak directional momentum\n\nLow overlap with consecutive directional candles may suggest stronger trend movement.\n\nFor example, a series of bullish candles that open near the previous close and advance consistently may show stronger directional conviction than alternating candles occupying the same range.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,2,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-19-lesson-03','cognizen-crypto-mastery-foundations-production','Gaps in Cryptocurrency Markets and Bearish Engulfing Pattern','cmf-module-2-19','text','### Gaps in Cryptocurrency Markets\n\nTraditional markets can open at a very different price from the previous closing price because they close overnight or on weekends.\n\nCryptocurrency markets generally trade continuously.\n\nTraditional price gaps are therefore less common on continuous spot charts.\n\nHowever, gaps may still appear because of:\n\nExchange-specific outages\n\nIlliquid trading\n\nFutures-market closures\n\nSudden market movement\n\nDifferences between platforms\n\nA gap on one exchange may not exist on another.\n\nAlways confirm the market, trading pair and data source.\n\n### Common Single-Candle Formations\n\nCandlestick names are descriptive labels for recurring shapes.\n\nThey should not be treated as automatic instructions.\n\n### Doji\n\nA doji forms when the opening and closing prices are equal or very close.\n\nThe candle may have:\n\nLong wicks\n\nShort wicks\n\nOne dominant wick\n\nA doji indicates that neither buyers nor sellers achieved a meaningful difference between the open and close.\n\nIt may suggest indecision.\n\nHowever, a doji is common and does not automatically signal reversal.\n\nIts importance increases when it appears:\n\nAfter a sustained trend\n\nAt major support or resistance\n\nWith unusual volume\n\nBefore confirming follow-through\n\n### Spinning Top\n\nA spinning top has:\n\nA small body\n\nAn upper wick\n\nA lower wick\n\nIt suggests that price moved in both directions but closed near the opening level.\n\nLike a doji, it may indicate balance or indecision.\n\nA spinning top in the middle of consolidation may contain little useful information.\n\nAt the end of a strong move, it may suggest that momentum is weakening.\n\n### Hammer\n\nA hammer commonly has:\n\nA small body near the top of the range\n\nA long lower wick\n\nLittle or no upper wick\n\nIt may form after a decline.\n\nThe shape suggests that sellers pushed price lower, but buyers recovered much of the loss before the close.\n\nA hammer can indicate rejection of lower prices.\n\nIts potential significance increases when it appears:\n\nAt support\n\nAfter an extended decline\n\nWith strong volume\n\nBefore bullish follow-through\n\nWithout confirmation, it may be only a temporary recovery.\n\n### Hanging Man\n\nThe hanging man has a shape similar to a hammer but appears after an upward move.\n\nIt may suggest that sellers were able to push price substantially lower during the period, even though price recovered before the close.\n\nIts location changes the interpretation.\n\nThe candle may indicate emerging weakness, but later confirmation is required.\n\nThis illustrates why candle shapes cannot be interpreted independently from the preceding trend.\n\n### Shooting Star\n\nA shooting star commonly has:\n\nA small body near the lower portion of the range\n\nA long upper wick\n\nLittle or no lower wick\n\nIt may form after an upward move.\n\nThe shape suggests that buyers drove price higher but sellers rejected the advance before the close.\n\nIts significance may increase at major resistance or after an extended rally.\n\nA shooting star does not guarantee reversal. Strong markets can absorb the selling and continue upward.\n\n### Inverted Hammer\n\nAn inverted hammer resembles a shooting star but usually appears after a decline.\n\nIt has:\n\nA small body near the lower end\n\nA long upper wick\n\nIt may indicate that buyers attempted to regain control.\n\nHowever, because price failed to close near the high, confirmation from subsequent candles is important.\n\nAgain, identical shapes can receive different names depending on trend and location.\n\n### Marubozu\n\nA marubozu is a candle with a large body and very small or absent wicks.\n\nA bullish marubozu suggests buyers controlled most of the period.\n\nA bearish marubozu suggests strong seller control.\n\nIt may indicate momentum or a decisive breakout.\n\nHowever, an unusually large candle after an extended move may also signal exhaustion or a temporary emotional extreme.\n\nThe next candles provide important context.\n\n### Common Multi-Candle Formations\n\nPatterns involving several candles attempt to show a change or continuation in market behaviour.\n\nThey should be evaluated with context and confirmation.\n\n### Bullish Engulfing Pattern\n\nA bullish engulfing pattern generally involves:\n\nA bearish candle\n\nFollowed by a larger bullish candle whose body covers the previous candle’s body\n\nIt may suggest that buyers have overcome the previous selling pressure.\n\nPotential significance increases when it forms:\n\nAfter a decline\n\nAt support\n\nWith increased volume\n\nWithin improving broader market structure\n\nThe word “engulfing” usually refers to the candle bodies rather than necessarily the full wicks.\n\n### Bearish Engulfing Pattern\n\nA bearish engulfing pattern generally involves:\n\nA bullish candle\n\nFollowed by a larger bearish candle whose body covers the previous body\n\nIt may suggest that sellers have taken control.\n\nIt may be more relevant:\n\nAfter an upward move\n\nAt resistance\n\nWith increased selling volume\n\nWhen momentum is already weakening\n\nOne engulfing pattern does not override a strong long-term trend automatically.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,3,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-19-lesson-04','cognizen-crypto-mastery-foundations-production','Inside Bar and Failed Candlestick Patterns','cmf-module-2-19','text','### Inside Bar\n\nAn inside bar forms when the high and low of a candle remain within the range of the previous candle.\n\nIt represents a contraction in price movement.\n\nThe larger previous candle is sometimes called the mother bar.\n\nAn inside bar may indicate:\n\nConsolidation\n\nReduced volatility\n\nIndecision\n\nPreparation for a breakout\n\nIt does not predict breakout direction by itself.\n\nThe broader trend and surrounding levels provide context.\n\n### Outside Bar\n\nAn outside bar forms when a candle’s high exceeds the previous high and its low falls below the previous low.\n\nIt shows expanded volatility and movement in both directions.\n\nThe closing position helps interpret which side gained control.\n\nAn outside bar closing near its high may favour buyers.\n\nOne closing near its low may favour sellers.\n\nIt can also represent chaotic volatility rather than a reliable directional signal.\n\n### Morning Star\n\nA morning-star formation is traditionally considered a possible bullish reversal pattern.\n\nIt commonly includes:\n\nA strong bearish candle\n\nA small-bodied candle showing reduced momentum\n\nA strong bullish candle closing significantly into the first candle’s range\n\nIt suggests a transition from seller control to indecision and then buyer strength.\n\nBecause cryptocurrency markets trade continuously, the gaps sometimes described in traditional versions of the pattern may not appear.\n\nThe underlying behavioural transition matters more than perfect textbook geometry.\n\n### Evening Star\n\nAn evening-star formation is the bearish counterpart.\n\nIt commonly includes:\n\nA strong bullish candle\n\nA small-bodied candle showing indecision\n\nA strong bearish candle closing significantly into the first candle’s range\n\nIt may suggest a transition from buyer control to seller strength.\n\nIts relevance increases near resistance or after an extended rise.\n\n### Three White Soldiers\n\nThis formation generally consists of three consecutive bullish candles with relatively strong bodies and progressively higher closes.\n\nIt may indicate sustained buying momentum.\n\nPotential concerns include:\n\nEntering after much of the move has already occurred\n\nShort-term overextension\n\nLow-liquidity manipulation\n\nA strong pattern does not mean the market offers an attractive entry at every price.\n\n### Three Black Crows\n\nThis pattern generally consists of three consecutive bearish candles with progressively lower closes.\n\nIt may indicate sustained selling pressure.\n\nHowever, after a severe decline, entering a new short position may offer poor risk-to-reward.\n\nDirection and entry quality are separate questions.\n\n### Candlestick Patterns and Context\n\nThe same candle can have different meaning depending on where it appears.\n\nA hammer:\n\nAt major support after a decline may suggest buyer rejection\n\nIn the middle of a range may mean very little\n\nDuring a strong downtrend may fail immediately\n\nA shooting star:\n\nAt resistance after a rally may indicate selling pressure\n\nDuring a strong breakout may be absorbed\n\nOn an illiquid token may result from one abnormal transaction\n\nBefore interpreting a candle, ask:\n\nWhat is the broader trend?\n\nWhere is the candle located?\n\nIs the level technically significant?\n\nWhat does volume show?\n\nDid later candles confirm the interpretation?\n\n### Support and Resistance Context\n\nCandlestick formations are often more meaningful near established support or resistance.\n\nFor example, a long lower wick at support may show that buyers defended an area that previously attracted demand.\n\nA bearish engulfing candle at resistance may show that sellers again responded near a known supply area.\n\nThe pattern is not important because of its name alone.\n\nIt is important because it records market behaviour at a location where participants were already expected to act.\n\n### Volume Confirmation\n\nVolume can help assess the participation behind a candlestick formation.\n\n### Bullish Reversal With Strong Volume\n\nMay suggest that meaningful buying demand entered.\n\n### Breakout Candle With Rising Volume\n\nMay provide stronger evidence that the move has broad participation.\n\n### Large Candle With Low Volume\n\nMay be less convincing, particularly in an illiquid market.\n\nHowever, volume interpretation is not mechanical.\n\nHigh volume may represent both aggressive buying and aggressive selling.\n\nThe candle’s direction, close and location provide additional context.\n\n### Follow-Through\n\nFollow-through occurs when later price action supports the message of the original candle.\n\nFor example:\n\nA hammer forms at support\n\nThe next candle closes above the hammer’s high\n\nPrice begins forming a higher low\n\nThis provides stronger evidence than the hammer alone.\n\nA supposed bullish pattern that is followed by immediate selling has failed to gain confirmation.\n\nWaiting for follow-through can reduce false signals, but it may produce a less favourable entry.\n\n### Failed Candlestick Patterns\n\nA failed pattern can itself provide information.\n\nSuppose a bullish engulfing candle forms at support, but price then falls below the pattern’s low.\n\nThis indicates that buyers were unable to maintain control.\n\nTraders who entered based on the bullish pattern may exit, adding further selling pressure.\n\nPattern failure reminds us that technical analysis must include invalidation.\n\nA pattern without a defined failure point is only a visual description.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,4,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-19-lesson-05','cognizen-crypto-mastery-foundations-production','Candlesticks and Liquidity and Common Misunderstandings','cmf-module-2-19','text','### Candlesticks and Liquidity\n\nCandlestick reliability depends partly on market liquidity.\n\nIn an illiquid token:\n\nOne transaction can create a long wick\n\nSpreads can distort the open and close\n\nPrice can be manipulated\n\nPatterns may form without broad participation\n\nA textbook formation in a weak market may provide little useful evidence.\n\nBefore analysing candles, examine:\n\nTrading volume\n\nMarket depth\n\nExchange quality\n\nBid-ask spread\n\nNumber of active participants\n\nChart clarity does not guarantee market quality.\n\n### Exchange Differences\n\nCryptocurrency prices can vary across exchanges.\n\nA candlestick pattern may appear on one platform and not another because of differences in:\n\nLiquidity\n\nTrading volume\n\nStablecoin pairs\n\nLocal users\n\nExchange outages\n\nOne abnormal transaction\n\nFor major analysis, compare several credible markets or use an aggregated data source.\n\nAlways know which exchange and trading pair created the chart.\n\n### Heikin-Ashi Candles\n\nHeikin-Ashi is an alternative charting method that uses averaged price calculations to smooth market movement.\n\nIt may help display:\n\nTrend direction\n\nTrend persistence\n\nChanges in momentum\n\nHowever, Heikin-Ashi candles do not show the exact ordinary market open and close.\n\nThey are calculated values.\n\nThis means they may be useful for trend visualisation but less suitable for precise entry, exit or transaction-price analysis.\n\nTraditional candlesticks and Heikin-Ashi candles should not be confused.\n\n### Candlestick Patterns Are Not Independent Events\n\nMany named patterns describe the same underlying behaviour:\n\nRejection\n\nMomentum\n\nIndecision\n\nExpansion\n\nContraction\n\nTransfer of control\n\nInstead of memorising dozens of names, focus on the questions:\n\nWho controlled the open-to-close movement?\n\nWhere did price encounter rejection?\n\nDid the range expand or contract?\n\nWhere did the candle close?\n\nHow does it relate to previous candles?\n\nWhat happened next?\n\nUnderstanding the behaviour is more useful than memorising pattern labels.\n\n### Candlesticks and Risk Management\n\nCandlestick patterns may help define:\n\nEntry\n\nInvalidation\n\nStop placement\n\nTarget\n\nPosition size\n\nFor example, a trader considering a bullish rejection candle may place invalidation below the candle’s low.\n\nThe distance between entry and invalidation then affects position size.\n\nHowever, a stop placed exactly beyond a visible candle may be vulnerable to normal volatility or liquidity-seeking movement.\n\nRisk levels should account for:\n\nMarket structure\n\nVolatility\n\nLiquidity\n\nPosition size\n\nFees and slippage\n\nThe candle provides a reference point, not a guaranteed protective boundary.\n\n### A Practical Candlestick Reading Process\n\n\n\n### Step 1: Confirm the Market\n\nIdentify:\n\nAsset\n\nExchange\n\nTrading pair\n\nLiquidity\n\n### Step 2: Select the Timeframe\n\nUse a timeframe appropriate to the investment or trading objective.\n\n### Step 3: Identify the Broader Trend\n\nDetermine whether the market is:\n\nRising\n\nFalling\n\nConsolidating\n\n### Step 4: Mark Key Locations\n\nIdentify:\n\nSupport\n\nResistance\n\nPrevious highs and lows\n\nConsolidation boundaries\n\n### Step 5: Read the Candle\n\nExamine:\n\nBody size\n\nWick size\n\nTotal range\n\nClosing location\n\nDirection\n\n### Step 6: Compare With Previous Candles\n\nLook for:\n\nMomentum\n\nContraction\n\nExpansion\n\nRepeated rejection\n\nPattern development\n\n### Step 7: Examine Volume\n\nDetermine whether participation supports the movement.\n\n### Step 8: Wait for Confirmation Where Appropriate\n\nLook for follow-through or a successful retest.\n\n### Step 9: Define Invalidation\n\nIdentify what price behaviour would prove the interpretation wrong.\n\n### Step 10: Assess Risk-to-Reward\n\nDetermine whether the potential opportunity justifies the possible loss.\n\n### Candlestick Analysis Checklist\n\nBefore acting on a candlestick formation, ask:\n\nWhich timeframe am I viewing?\n\nHas the candle closed?\n\nWhat is the broader trend?\n\nIs the market liquid?\n\nWhere did the candle form?\n\nIs it near meaningful support or resistance?\n\nHow large is the body relative to recent candles?\n\nWhat do the upper and lower wicks show?\n\nWhere did the candle close within its range?\n\nIs volatility expanding or contracting?\n\nDoes volume support the interpretation?\n\nWhat do the surrounding candles show?\n\nHas follow-through occurred?\n\nWhat would invalidate the pattern?\n\nIs the risk-to-reward acceptable?\n\nCould exchange-specific data be distorting the candle?\n\nAm I interpreting behaviour or merely recognising a shape?\n\n### Common Candlestick Mistakes\n\n\n\n### Memorising Patterns Without Understanding Context\n\nA named candle is treated as a guaranteed signal.\n\n### Acting Before the Candle Closes\n\nThe final formation may differ substantially from its intraperiod appearance.\n\n### Ignoring the Broader Trend\n\nA small reversal pattern is expected to overturn a powerful trend immediately.\n\n### Ignoring Location\n\nA candle in the middle of a range is treated like one at major support or resistance.\n\n### Using Illiquid Market Data\n\nOne abnormal trade creates a misleading wick or pattern.\n\n### Ignoring Volume\n\nThe analysis does not consider whether meaningful participation supported the move.\n\n### Overlooking Failed Patterns\n\nThe participant remains committed even after invalidation.\n\n### Using Very Short Timeframes Without Accounting for Noise\n\nFrequent signals create excessive trading and costs.\n\n### Treating Candle Colour as Complete Information\n\nThe body, wicks, range and close provide additional information.\n\n### Common Misunderstandings\n\n#### “A Green Candle Means Buyers Controlled the Entire Period”\n\nPrice may have fallen significantly before recovering.\n\n#### “A Red Candle Means No Buying Occurred”\n\nBuyers may have entered but failed to maintain a close above the opening price.\n\n#### “A Long Lower Wick Guarantees a Reversal”\n\nIt shows rejection during that period, not guaranteed future demand.\n\n#### “A Doji Means the Trend Must Reverse”\n\nIt indicates balance or indecision and may occur during continuation.\n\n#### “An Engulfing Candle Overrides the Broader Trend”\n\nA single formation may fail against strong market structure.\n\n#### “Large Candles Are Always Strong Signals”\n\nThey may reflect exhaustion, liquidation or low liquidity.\n\n#### “Candlestick Patterns Work Equally on Every Timeframe”\n\nShorter timeframes generally contain more noise.\n\n#### “A Pattern Has Meaning Before the Candle Closes”\n\nThe candle can change until the period ends.\n\n#### “Pattern Recognition Is Enough to Trade Profitably”\n\nPosition sizing, liquidity, execution and risk management remain essential.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,5,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-19-lesson-06','cognizen-crypto-mastery-foundations-production','Module Summary and Key Takeaway','cmf-module-2-19','text','### Module Summary\n\nCandlestick charts represent the open, high, low and close of an asset during a selected period.\n\nThe body shows the distance between the open and close.\n\nThe wicks show the highest and lowest prices reached.\n\nBullish candles close above their opening price.\n\nBearish candles close below it.\n\nBody size, wick length, total range and closing location provide information about:\n\nMomentum\n\nVolatility\n\nRejection\n\nBuyer and seller control\n\nMarket indecision\n\nCommon formations include:\n\nDoji\n\nSpinning top\n\nHammer\n\nShooting star\n\nEngulfing patterns\n\nInside bars\n\nMorning and evening stars\n\nThese patterns are not guaranteed predictions.\n\nTheir meaning depends on:\n\nTrend\n\nTimeframe\n\nLocation\n\nVolume\n\nLiquidity\n\nFollow-through\n\nThe objective is not to memorise every candlestick name.\n\nIt is to understand the behaviour represented by the open, high, low and close—and to define what would prove your interpretation wrong.\n\n### Key Takeaway\n\nEvery candlestick tells a brief story about the struggle between buyers and sellers.\n\nThe body shows who controlled the open-to-close movement. The wicks show where price was rejected, and the close shows where the market finished the period.\n\nBut one candle is only one chapter.\n\nRead it within the trend, the timeframe, the market level and the surrounding price action before drawing a conclusion.','markdown',NULL,NULL,NULL,2,0,0,0,'',NULL,6,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-19-lesson-07','cognizen-crypto-mastery-foundations-production','Check your understanding','cmf-module-2-19','text','### Check your understanding\n\nAnswer these questions to self-assess your understanding before moving on.\n\n1. What four price points does a candlestick display?\n\n2. What does the candle body represent?\n\n3. What do the upper and lower wicks represent?\n\n4. What makes a candle bullish?\n\n5. What makes a candle bearish?\n\n6. What can a large candle range indicate?\n\n7. Why is the closing position important?\n\n8. What may a long upper wick suggest?\n\n9. What may a long lower wick suggest?\n\n10. Why should an unfinished candle be interpreted cautiously?\n\n11. How does timeframe affect candlestick meaning?\n\n12. What is a doji?\n\n13. What is the difference between a hammer and a hanging man?\n\n14. What does an engulfing pattern attempt to show?\n\n15. What is an inside bar?\n\n16. Why are support and resistance important when evaluating a pattern?\n\n17. How can volume strengthen or weaken a candlestick interpretation?\n\n18. What is follow-through?\n\n19. Why can a failed pattern provide useful information?\n\n20. How can low liquidity distort candlestick formations?\n\n21. How do Heikin-Ashi candles differ from traditional candlesticks?\n\n22. Why is understanding candle behaviour more useful than memorising pattern names?\n\n23. What should define the invalidation of a candlestick setup?\n\n24. Why can a valid pattern still produce a losing trade?','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,7,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `course_sections` (`id`,`course_id`,`title`,`position`,`created_at`) SELECT 'cmf-module-2-20','cognizen-crypto-mastery-foundations-production','Module 2.20: Support and Resistance',20,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
