INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-20-lesson-01','cognizen-crypto-mastery-foundations-production','What Is Support? and Horizontal Support and Resistance','cmf-module-2-20','text','### Learning Objectives\n\nBy the end of this module, you should be able to:\n\nDefine support and resistance\n\nExplain how supply, demand and market psychology create important price zones\n\nIdentify support and resistance using previous highs, lows and consolidation areas\n\nDistinguish between horizontal, dynamic and psychological levels\n\nUnderstand role reversal after a breakout or breakdown\n\nEvaluate the significance of repeated tests, volume and timeframe\n\nRecognise false breakouts and liquidity sweeps\n\nUse support and resistance to structure entries, exits and risk\n\nAvoid treating technical levels as exact or guaranteed prices\n\n### Introduction\n\nSupport and resistance are among the most widely used concepts in technical analysis.\n\nThey identify areas where buying or selling pressure has previously affected price.\n\nSupport is an area where demand may become strong enough to slow or reverse a decline.\n\nResistance is an area where supply may become strong enough to slow or reverse an advance.\n\nThese areas can help participants understand:\n\nWhere buyers have previously entered\n\nWhere sellers have previously appeared\n\nWhere market sentiment may change\n\nWhere a trend could continue or weaken\n\nWhere risk might be defined\n\nSupport and resistance are not invisible barriers that price must obey.\n\nThey are records of previous market behaviour.\n\nPrice can:\n\nReverse at a level\n\nPause temporarily\n\nBreak through it\n\nMove beyond it briefly and return\n\nIgnore it entirely\n\nThe purpose is not to assume that a level will hold.\n\nThe purpose is to identify where the interaction between buyers and sellers may become especially important.\n\n### What Is Support?\n\nSupport is a price area where buying demand has previously been strong enough to interrupt a decline.\n\nAs price falls toward support:\n\nSome buyers may consider the asset more attractive\n\nShort sellers may take profits\n\nPrevious buyers may add to positions\n\nLimit orders may already be waiting\n\nTraders may expect a rebound\n\nIf buying demand becomes stronger than selling pressure, price may stop falling and begin recovering.\n\nSupport is commonly found near:\n\nPrevious market lows\n\nConsolidation boundaries\n\nHigh-volume trading areas\n\nFormer resistance\n\nPsychological round numbers\n\nRising trend lines or moving averages\n\nSupport represents a potential response area, not guaranteed protection.\n\n### What Is Resistance?\n\nResistance is a price area where selling supply has previously been strong enough to interrupt an advance.\n\nAs price rises toward resistance:\n\nExisting holders may take profits\n\nTraders may open short positions\n\nPrevious buyers may sell near their break-even prices\n\nLimit sell orders may be waiting\n\nParticipants may consider the asset overextended\n\nIf selling pressure becomes stronger than buying demand, price may stop rising and begin declining.\n\nResistance commonly appears near:\n\nPrevious market highs\n\nThe upper boundary of a range\n\nFormer support\n\nPsychological round numbers\n\nFalling trend lines or moving averages\n\nAreas of heavy previous trading\n\nResistance identifies an area where buyers may need to demonstrate sufficient demand to continue the advance.\n\n### Why Support and Resistance Form\n\nSupport and resistance develop because market participants remember previous prices and respond emotionally and financially to them.\n\nSuppose an asset repeatedly falls to 100 units and then recovers.\n\nMarket participants may begin to believe that 100 represents good value.\n\nThe next time price approaches 100:\n\nPrevious buyers may buy again\n\nNew buyers may enter\n\nShort sellers may close profitable positions\n\nAutomated systems may respond to the level\n\nTheir combined activity can create support.\n\nNow suppose the asset repeatedly rises to 130 and declines.\n\nParticipants may begin associating 130 with selling pressure.\n\nWhen price returns:\n\nHolders may take profits\n\nPrevious buyers trapped near 130 may sell\n\nShort sellers may enter\n\nAutomated orders may activate\n\nThis behaviour can recreate resistance.\n\nThe level becomes significant partly because participants believe it is significant and act accordingly.\n\n### Support and Resistance Are Zones\n\nSupport and resistance should generally be treated as zones rather than exact lines.\n\nPrice may reverse:\n\nSlightly above the marked level\n\nDirectly at the level\n\nTemporarily below or above it\n\nAcross a wider range of prices\n\nFor example, support may exist between 98 and 102 rather than precisely at 100.\n\nThis occurs because different participants:\n\nEnter at different prices\n\nUse different exchanges\n\nAnalyse different timeframes\n\nPlace orders at slightly different levels\n\nRespond differently to volatility\n\nDrawing an excessively precise line can create false confidence.\n\nA zone better represents the market’s uncertainty and variability.\n\n### Horizontal Support and Resistance\n\nHorizontal levels are based on previous price activity at similar values.\n\nThey may be identified from:\n\nMajor swing highs\n\nMajor swing lows\n\nRange boundaries\n\nRepeated reversals\n\nBreakout and breakdown points\n\nHorizontal zones are widely followed because they are easy to observe.\n\nThey also remain relevant across different market participants and charting systems.\n\nA level tested on several occasions may attract increasing attention.\n\nHowever, repeated tests can either strengthen its importance or weaken its ability to hold.\n\nContext determines which interpretation is more appropriate.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,1,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-20-lesson-02','cognizen-crypto-mastery-foundations-production','Swing Highs and Swing Lows and Moving Averages as Dynamic Levels','cmf-module-2-20','text','### Swing Highs and Swing Lows\n\nA swing high is a local peak where price stops rising and begins declining.\n\nA swing low is a local bottom where price stops falling and begins rising.\n\nMajor swing points often become support or resistance because they mark previous changes in control.\n\nFor example:\n\nA previous swing high may become future resistance\n\nA previous swing low may become future support\n\nNot every minor price fluctuation deserves a level.\n\nHigher-quality levels are usually associated with:\n\nClear market reactions\n\nSignificant price movement\n\nHigher timeframes\n\nIncreased volume\n\nRepeated relevance\n\nToo many lines can make a chart difficult to interpret.\n\n### Consolidation Ranges\n\nA consolidation range forms when price moves between an upper and lower boundary.\n\nThe lower boundary acts as support.\n\nThe upper boundary acts as resistance.\n\nWithin the range:\n\nBuyers tend to respond near the lower area\n\nSellers tend to respond near the upper area\n\nPrice repeatedly returns toward the centre\n\nThe range may continue until one side gains sufficient control.\n\nA move above resistance may create a breakout.\n\nA move below support may create a breakdown.\n\nHowever, range boundaries frequently produce false moves before a lasting direction develops.\n\n### Previous All-Time Highs and Lows\n\nPrevious all-time highs often attract substantial attention.\n\nWhen price approaches a previous peak:\n\nHolders may take profit\n\nTraders may expect rejection\n\nMedia attention may increase\n\nBreakout buyers may prepare to enter\n\nIf price breaks above the previous all-time high, there may be little visible historical resistance directly above it.\n\nThis is sometimes called price discovery.\n\nHowever, the absence of historical resistance does not mean price must continue rising.\n\nValuation, liquidity, leverage and psychology still matter.\n\nPrevious lows may also become important, particularly when they represent periods of market capitulation or long-term accumulation.\n\n### Psychological Levels\n\nPsychological levels are prices that attract attention because they are simple or memorable.\n\nExamples include:\n\n1\n\n10\n\n100\n\n1,000\n\n10,000\n\nPrices ending in zero or five\n\nParticipants may place orders near these round numbers because they are easy to remember and communicate.\n\nMedia reports and forecasts also frequently focus on them.\n\nPsychological levels can become support or resistance through collective attention.\n\nHowever, price may reverse slightly before reaching the number or move beyond it to trigger nearby orders.\n\nThe psychological level should therefore be treated as an area rather than a precise turning point.\n\n### Dynamic Support and Resistance\n\nNot every support or resistance area is horizontal.\n\nDynamic levels change over time.\n\nExamples include:\n\nTrend lines\n\nMoving averages\n\nPrice channels\n\nVolatility bands\n\nA rising moving average may act as dynamic support during an uptrend.\n\nA falling moving average may act as dynamic resistance during a downtrend.\n\nThese levels move as new price data enters the calculation.\n\nDynamic support and resistance can help visualise trends, but they remain derived from past price information.\n\nPrice does not reverse because a moving average possesses any physical power.\n\nParticipants may respond because they observe the same indicator or because the average represents a meaningful area within the broader trend.\n\n### Trend Lines\n\nA trend line connects a series of important market points.\n\n### Rising Trend Line\n\nUsually connects higher swing lows in an uptrend.\n\nIt may act as a potential support area.\n\n### Falling Trend Line\n\nUsually connects lower swing highs in a downtrend.\n\nIt may act as potential resistance.\n\nA trend line generally becomes more credible when it connects several meaningful points without being forced through unrelated price activity.\n\nHowever, trend-line drawing is subjective.\n\nTwo analysts may select different points and produce different lines.\n\nA trend line should be combined with market structure rather than treated as an independent signal.\n\n### Channels\n\nA price channel contains two roughly parallel boundaries.\n\nAn ascending channel may include:\n\nA rising support line\n\nA rising resistance line\n\nA descending channel may include:\n\nA falling resistance line\n\nA falling support line\n\nPrice may oscillate between these boundaries while maintaining the broader trend.\n\nA break outside the channel may indicate:\n\nTrend acceleration\n\nTrend weakening\n\nA false breakout\n\nA transition into another market structure\n\nChannels provide context, but their boundaries should still be interpreted as zones.\n\n### Moving Averages as Dynamic Levels\n\nMoving averages smooth price data across a selected number of periods.\n\nCommon examples include short-, medium- and long-term averages.\n\nDuring a strong uptrend, price may repeatedly return toward a rising moving average and recover.\n\nDuring a downtrend, price may rally toward a falling average and decline again.\n\nThe moving average may appear to act as support or resistance.\n\nHowever:\n\nDifferent traders use different settings\n\nSideways markets create repeated false signals\n\nPrice can move far beyond the average\n\nA moving average reacts after price has already changed\n\nMoving averages provide context rather than guaranteed boundaries.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,2,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-20-lesson-03','cognizen-crypto-mastery-foundations-production','Role Reversal and Acceptance Versus Rejection','cmf-module-2-20','text','### Role Reversal\n\nOne of the most important support-and-resistance concepts is role reversal.\n\nAfter resistance is broken, it may become support.\n\nAfter support is broken, it may become resistance.\n\n### Resistance Becoming Support\n\nSuppose price repeatedly fails near 120.\n\nEventually, strong buying pushes price above the resistance zone.\n\nWhen price later returns toward 120:\n\nTraders who missed the breakout may buy\n\nShort sellers may close positions\n\nExisting buyers may defend the level\n\nFormer sellers may reconsider their view\n\nThe previous resistance may now act as support.\n\n### Support Becoming Resistance\n\nSuppose price repeatedly holds near 80 but later breaks below it.\n\nWhen price recovers toward 80:\n\nPrevious buyers may sell near their entry price\n\nShort sellers may enter\n\nThe market may view the broken support as evidence of weakness\n\nThe former support may now act as resistance.\n\nRole reversal reflects a shift in market psychology and positioning.\n\nIt does not occur every time.\n\n### Breakouts\n\nA breakout occurs when price moves above resistance.\n\nA credible breakout may include:\n\nA decisive move beyond the zone\n\nA candle close above resistance\n\nIncreased volume\n\nStrong market participation\n\nContinued price movement\n\nSuccessful retesting of the level\n\nThe breakout suggests that demand has overcome the available selling pressure.\n\nHowever, buying immediately after every move above resistance can be dangerous.\n\nSome breakouts fail quickly.\n\n### Breakdowns\n\nA breakdown occurs when price moves below support.\n\nEvidence that may strengthen the breakdown includes:\n\nA decisive close below the zone\n\nIncreased selling volume\n\nA failed attempt to recover support\n\nLower highs and lower lows\n\nWeakness across related markets\n\nA breakdown can trigger:\n\nStop-loss orders\n\nLeveraged liquidations\n\nPanic selling\n\nAutomated momentum strategies\n\nThese effects may accelerate the decline.\n\n### Retests\n\nA retest occurs when price returns to a recently broken support or resistance area.\n\nAfter a bullish breakout, price may return to the former resistance.\n\nIf buyers defend the zone, it may confirm the role reversal into support.\n\nAfter a bearish breakdown, price may recover toward former support.\n\nIf sellers reject the recovery, the zone may become resistance.\n\nRetests can offer clearer risk definition because the invalidation point may be nearby.\n\nHowever, not every breakout retests, and not every retest holds.\n\nWaiting for one may cause the participant to miss the movement entirely.\n\n### False Breakouts\n\nA false breakout occurs when price moves above resistance but fails to remain there.\n\nPrice then returns below the level or back into the previous range.\n\nPossible causes include:\n\nInsufficient buying demand\n\nProfit-taking\n\nStop-loss activation\n\nMarket manipulation\n\nNews-driven volatility\n\nLow liquidity\n\nLarge sellers using the breakout to exit\n\nA false breakout can trap participants who bought after the initial move.\n\nTheir later exits may add selling pressure.\n\n### False Breakdowns\n\nA false breakdown occurs when price moves below support but rapidly recovers above it.\n\nThis may happen when:\n\nStop-loss orders are triggered\n\nLeveraged positions are liquidated\n\nLarge buyers seek liquidity below support\n\nSellers cannot sustain the move\n\nPanic briefly overwhelms normal demand\n\nA false breakdown can trap short sellers and cause a rapid recovery if they are forced to close positions.\n\nThese moves are sometimes called bear traps.\n\nFalse breakouts above resistance may similarly be called bull traps.\n\n### Liquidity Around Support and Resistance\n\nSupport and resistance often attract clusters of orders.\n\nAround support, there may be:\n\nBuy orders\n\nStop losses from long positions\n\nShort-profit targets\n\nLiquidation levels\n\nAround resistance, there may be:\n\nSell orders\n\nStop losses from short positions\n\nLong-profit targets\n\nBreakout-entry orders\n\nThis concentration creates liquidity.\n\nLarge market participants may need substantial liquidity to enter or exit positions.\n\nPrice may temporarily move beyond an obvious level, trigger orders and then reverse.\n\nThis is sometimes described as a liquidity sweep.\n\n### Liquidity Sweeps\n\nA liquidity sweep occurs when price moves through an obvious level, activates clustered orders and then reverses.\n\nFor example:\n\nSupport is visible near 100\n\nMany traders place stops below 100\n\nPrice falls to 98\n\nStops and liquidations create sell orders\n\nLarge buyers absorb the selling\n\nPrice recovers above 100\n\nThe move below support was real, but it failed to establish acceptance at lower prices.\n\nA liquidity sweep cannot be identified reliably before it occurs.\n\nNot every move beyond support or resistance is manipulation.\n\nSometimes a genuine breakout simply begins with the same behaviour.\n\nConfirmation and follow-through remain important.\n\n### Acceptance Versus Rejection\n\nA useful way to evaluate a level is to examine whether the market accepts or rejects prices beyond it.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,3,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-20-lesson-04','cognizen-crypto-mastery-foundations-production','Acceptance and Stablecoin Pair Distortion','cmf-module-2-20','text','### Acceptance\n\nPrice moves through the level and continues trading beyond it.\n\nEvidence may include:\n\nSeveral closes beyond the zone\n\nGrowing volume\n\nSuccessful retest\n\nContinued market structure in the breakout direction\n\n### Rejection\n\nPrice moves beyond the level but returns quickly.\n\nEvidence may include:\n\nLong wicks\n\nA close back inside the range\n\nStrong opposing volume\n\nFailure to continue\n\nAcceptance supports the possibility of a genuine regime change.\n\nRejection suggests that the market was not prepared to sustain the new price area.\n\n### Repeated Tests\n\nA level tested several times becomes widely visible.\n\nRepeated tests can have two competing interpretations.\n\n### Increasing Significance\n\nA level that repeatedly produces strong reversals may demonstrate persistent buyer or seller interest.\n\n### Weakening Defence\n\nEvery test may consume some of the available orders defending the level.\n\nFor example, repeated visits to support may gradually exhaust buyers.\n\nEventually, the level may break.\n\nA useful question is not only how often the level was tested, but how price reacted each time.\n\nWeakening rebounds from support may suggest declining demand.\n\nIncreasingly shallow declines from resistance may suggest growing buying pressure.\n\n### Strength of a Support or Resistance Zone\n\nSeveral factors may increase a zone’s analytical importance.\n\n### Higher Timeframe\n\nA weekly or monthly level generally represents more trading activity than a five-minute level.\n\n### Strong Historical Reaction\n\nA large move away from the zone suggests meaningful imbalance.\n\n### Multiple Relevant Tests\n\nRepeated reactions may show that participants continue recognising the area.\n\n### High Volume\n\nSignificant trading activity can indicate that many positions were established there.\n\n### Confluence\n\nThe zone may align with:\n\nA major swing point\n\nA moving average\n\nA psychological number\n\nA trend line\n\nA high-volume region\n\n### Recent Relevance\n\nRecent levels may better reflect the positions of current market participants.\n\nOlder levels can remain relevant but may lose influence as market structure changes.\n\n### Fresh Versus Tested Levels\n\nA fresh level has not been revisited since producing a strong market reaction.\n\nSome analysts consider fresh zones more likely to contain unfilled orders.\n\nA heavily tested level may have less remaining buying or selling interest.\n\nThis interpretation is plausible but not guaranteed.\n\nA well-established level may continue holding because new participants keep entering.\n\nThe quality of the reaction matters more than the label.\n\n### Volume and Support or Resistance\n\nVolume can provide information about participation around a level.\n\n### High Volume at Support\n\nMay indicate strong buying interest, panic selling or both.\n\nThe candle structure and subsequent price movement help interpret the activity.\n\n### Breakout With Rising Volume\n\nMay indicate broader participation and stronger acceptance beyond resistance.\n\n### Breakout With Weak Volume\n\nMay indicate limited conviction, although some markets can continue rising without a major volume increase.\n\n### Declining Volume During Repeated Tests\n\nMay indicate reduced participation before a larger move.\n\nVolume supports analysis but does not determine the outcome independently.\n\n### Volume Profile and High-Volume Areas\n\nA volume profile displays how much trading occurred at different price levels rather than across time.\n\nHigh-volume areas may represent:\n\nMarket agreement\n\nLarge numbers of open positions\n\nPrevious consolidation\n\nPotential support or resistance\n\nLow-volume areas may represent prices through which the market moved quickly.\n\nPrice may move rapidly through these areas again because less historical trading occurred there.\n\nVolume profile is more advanced than ordinary volume analysis, but its core principle is useful:\n\nPrice areas with substantial previous participation may remain important because many participants have financial and psychological exposure there.\n\n### Higher-Timeframe Levels\n\nLevels from higher timeframes generally deserve priority.\n\nA weekly support zone may influence price more strongly than several short-term levels.\n\nA practical top-down process may involve:\n\nMark monthly and weekly levels\n\nIdentify important daily structure\n\nUse shorter timeframes only for entry detail\n\nThis reduces chart clutter and prevents minor intraday fluctuations from overshadowing broader market structure.\n\nA shorter-timeframe level may still matter for a short-term trade, but it should be interpreted within the larger context.\n\n### Support and Resistance Across Exchanges\n\nCryptocurrency trading is fragmented.\n\nThe same asset can show slightly different highs and lows across exchanges.\n\nA level may appear to break on one exchange while remaining intact on another.\n\nDifferences may result from:\n\nLiquidity\n\nTrading pairs\n\nStablecoin prices\n\nLocal order flow\n\nExchange outages\n\nAbnormal transactions\n\nFor major analysis, consider:\n\nHigh-liquidity markets\n\nSeveral credible exchanges\n\nAggregated data\n\nThe market on which the actual position will be executed\n\nThe level must be relevant to the venue being traded.\n\n### Stablecoin Pair Distortion\n\nSuppose an asset is priced against a stablecoin that temporarily loses its peg.\n\nThe cryptocurrency price may appear to rise, even when its value against traditional currency has not changed significantly.\n\nSupport and resistance drawn on that pair may become distorted.\n\nAlways confirm:\n\nThe quote asset\n\nStablecoin stability\n\nAlternative trading pairs\n\nBroader market pricing\n\nTechnical analysis depends on the reliability of both assets in the pair.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,4,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-20-lesson-05','cognizen-crypto-mastery-foundations-production','Support and Resistance in Strong Trends and Confluence','cmf-module-2-20','text','### Support and Resistance in Strong Trends\n\nDuring a strong uptrend:\n\nPrevious resistance may become support\n\nPullbacks may remain shallow\n\nResistance levels may break quickly\n\nPrice may stay above moving averages\n\nDuring a strong downtrend:\n\nPrevious support may become resistance\n\nRecoveries may remain weak\n\nSupport levels may fail repeatedly\n\nPrice may remain below falling averages\n\nAttempting to trade every resistance level against a powerful uptrend can produce repeated losses.\n\nSimilarly, buying every support level during a strong downtrend can be dangerous.\n\nTrend context should influence expectations.\n\n### Support and Resistance During Consolidation\n\nSupport and resistance are especially visible during sideways ranges.\n\nA range-based approach may expect:\n\nBuying interest near support\n\nSelling pressure near resistance\n\nReversion toward the middle\n\nHowever, the longer a range continues, the greater the possibility of an eventual breakout.\n\nRange participants must define what happens when the boundary fails.\n\nA strategy designed for consolidation should not be continued unchanged after the market establishes a trend.\n\n### Support and Resistance for Entry Planning\n\nSupport and resistance can help identify areas where a position may offer a more favourable relationship between risk and potential reward.\n\nFor example, a long entry near support may allow:\n\nInvalidation below the zone\n\nA target near resistance\n\nA defined risk distance\n\nEntering in the middle of a range may create:\n\nSimilar distance to support and resistance\n\nPoorer risk-to-reward\n\nLess clear market advantage\n\nThe existence of support does not justify an entry automatically.\n\nThe participant should still examine:\n\nTrend\n\nConfirmation\n\nVolume\n\nLiquidity\n\nPosition size\n\n### Support and Resistance for Exit Planning\n\nResistance may provide a reference for:\n\nTaking partial profits\n\nReducing a position\n\nTightening risk controls\n\nReviewing valuation\n\nSupport may provide a reference for:\n\nProtecting a short position\n\nEvaluating a breakdown\n\nReviewing an investment thesis\n\nA target placed exactly at a highly visible level may not execute if price reverses slightly beforehand.\n\nSome participants place orders before the exact zone.\n\nThis improves the chance of execution but reduces potential reward.\n\nEvery choice involves trade-offs.\n\n### Support and Resistance for Stop Placement\n\nA stop-loss may be positioned beyond a support or resistance area.\n\nFor a long position:\n\nInvalidation may lie below support\n\nFor a short position:\n\nInvalidation may lie above resistance\n\nHowever, placing the stop immediately beyond an obvious level can expose it to:\n\nNormal volatility\n\nLiquidity sweeps\n\nExchange-specific price differences\n\nBrief false breaks\n\nA wider stop requires a smaller position if the maximum amount at risk is to remain unchanged.\n\nThe stop should reflect the point at which the analysis is invalid—not merely the smallest possible loss distance.\n\n### Fundamental Support and Resistance\n\nThe terms support and resistance are mainly technical, but fundamental factors can influence the areas.\n\nFor example, investors may view a particular valuation as attractive because of:\n\nNetwork revenue\n\nTreasury assets\n\nAdoption\n\nProduction costs\n\nToken supply\n\nSelling may increase when valuation reaches levels viewed as unrealistic.\n\nTechnical and fundamental participants may therefore act near similar zones for different reasons.\n\nHowever, no fundamental calculation creates a guaranteed price floor.\n\n### Broken Support and the Investment Thesis\n\nA technical support break does not automatically mean a long-term project has failed.\n\nSimilarly, a price holding support does not prove that the project remains healthy.\n\nLong-term investors should distinguish between:\n\nTechnical deterioration\n\nFundamental deterioration\n\nTemporary market volatility\n\nPermanent impairment\n\nA support break may justify reviewing position size and assumptions.\n\nIt should not replace analysis of adoption, security, tokenomics and valuation.\n\n### Drawing Support and Resistance\n\nA practical drawing process is:\n\n### Step 1: Begin With a Higher Timeframe\n\nUse weekly or daily charts to identify major structure.\n\n### Step 2: Mark Clear Swing Points\n\nFocus on obvious highs and lows that produced meaningful movement.\n\n### Step 3: Identify Consolidation Areas\n\nMark the boundaries of established ranges.\n\n### Step 4: Use Zones\n\nInclude the cluster of relevant opens, closes and wicks rather than one exact price.\n\n### Step 5: Limit the Number of Levels\n\nPrioritise the levels closest to current price and those with the strongest evidence.\n\n### Step 6: Review Rather Than Constantly Redraw\n\nUpdate levels when market structure genuinely changes.\n\nA chart covered with dozens of lines loses analytical usefulness.\n\n### Subjectivity\n\nSupport and resistance contain a degree of subjectivity.\n\nAnalysts may disagree about:\n\nWhich swing points are important\n\nWhether wicks or closes define the zone\n\nHow wide the zone should be\n\nWhich timeframe deserves priority\n\nWhether a level remains valid\n\nThis does not make the concept useless.\n\nIt means the method should be applied consistently.\n\nA participant should define their own drawing rules and evaluate whether those rules improve decision-making over time.\n\n### Confluence\n\nA support or resistance zone may become more important when several forms of evidence overlap.\n\nFor example:\n\nPrevious weekly resistance\n\nA psychological round number\n\nA major moving average\n\nHigh historical volume\n\nA trend-line intersection\n\nThis overlap is called confluence.\n\nHowever, confluence does not guarantee a reaction.\n\nSeveral tools may also be based on the same underlying price information.\n\nThe level remains a probability area rather than a certainty.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,5,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-20-lesson-06','cognizen-crypto-mastery-foundations-production','A Support-and-Resistance Analysis Process and Key Takeaway','cmf-module-2-20','text','### A Support-and-Resistance Analysis Process\n\n\n\n### Step 1: Confirm the Market\n\nIdentify the asset, exchange and trading pair.\n\n### Step 2: Select the Relevant Timeframe\n\nMatch it to the intended holding period.\n\n### Step 3: Identify the Trend\n\nDetermine whether price is rising, falling or consolidating.\n\n### Step 4: Mark Major Zones\n\nUse significant highs, lows and consolidation boundaries.\n\n### Step 5: Observe the Approach\n\nAssess:\n\nMomentum\n\nCandle size\n\nVolume\n\nVolatility\n\n### Step 6: Evaluate the Reaction\n\nLook for:\n\nRejection\n\nAcceptance\n\nConsolidation\n\nBreakout\n\nBreakdown\n\n### Step 7: Wait for Confirmation Where Required\n\nPossible confirmation may include:\n\nA candle close\n\nFollow-through\n\nA retest\n\nIncreased volume\n\n### Step 8: Define Invalidation\n\nDetermine what would show that the analysis is wrong.\n\n### Step 9: Calculate Position Size\n\nUse the invalidation distance and maximum acceptable loss.\n\n### Step 10: Prepare Alternative Scenarios\n\nConsider what happens if the level holds, breaks or produces a false move.\n\n### Support-and-Resistance Checklist\n\nBefore acting near a level, ask:\n\nIs this support or resistance?\n\nWhich timeframe created the level?\n\nIs it a precise line or a broader zone?\n\nHow many meaningful reactions occurred there?\n\nWas the previous reaction strong?\n\nIs the level fresh or heavily tested?\n\nWhat is the broader trend?\n\nIs price approaching with strong or weak momentum?\n\nWhat does volume show?\n\nIs the market sufficiently liquid?\n\nHas price closed beyond the zone?\n\nIs there evidence of acceptance or rejection?\n\nHas role reversal occurred?\n\nCould the move be a false breakout or liquidity sweep?\n\nWhat would invalidate the setup?\n\nIs the risk-to-reward favourable?\n\nDoes the position size reflect the stop distance?\n\nCould exchange-specific data distort the level?\n\nAm I treating the level as a probability or a guarantee?\n\n### Common Support-and-Resistance Mistakes\n\n\n\n### Treating Levels as Exact Prices\n\nMarkets often respond across broader zones.\n\n### Drawing Too Many Levels\n\nEvery minor turn is marked, making the chart unusable.\n\n### Ignoring the Timeframe\n\nA small intraday level is treated as more important than weekly market structure.\n\n### Buying Support Automatically\n\nThe broader trend or fundamentals may be deteriorating.\n\n### Selling Resistance Automatically\n\nStrong demand may produce a lasting breakout.\n\n### Acting Before Confirmation\n\nA temporary move is mistaken for acceptance.\n\n### Ignoring Liquidity\n\nA wick or breakout may result from one abnormal transaction.\n\n### Moving Levels to Protect a Prediction\n\nFailed analysis is redrawn until it appears correct.\n\n### Using Obvious Stops Without Accounting for Volatility\n\nNormal movement or liquidity sweeps trigger the exit.\n\n### Ignoring Role Reversal\n\nFormer support or resistance continues being interpreted according to its old function after a confirmed break.\n\n### Common Misunderstandings\n\n#### “Support Means Price Cannot Fall Further”\n\nSupport can fail when selling pressure exceeds demand.\n\n#### “Resistance Means Price Is Too Expensive”\n\nIt records previous selling behaviour, not an objective valuation conclusion.\n\n#### “The More Often a Level Is Tested, the Stronger It Becomes”\n\nRepeated tests can also consume the orders defending it.\n\n#### “A Break Above Resistance Guarantees a Rally”\n\nFalse breakouts are common.\n\n#### “A Wick Through Support Means the Level Failed”\n\nPrice may have swept liquidity and recovered before closing.\n\n#### “Every Move Beyond a Level Is Manipulation”\n\nMany moves are genuine changes in supply and demand.\n\n#### “A Previous All-Time High Must Become Support”\n\nRole reversal requires evidence and market acceptance.\n\n#### “Moving Averages Always Provide Support”\n\nThey are calculated from historical price and can fail repeatedly.\n\n#### “Support and Resistance Predict Exact Reversal Points”\n\nThey identify areas where a reaction may become more likely.\n\n### Module Summary\n\nSupport is an area where buying demand may slow or reverse a decline.\n\nResistance is an area where selling supply may slow or reverse an advance.\n\nThese zones develop because market participants remember and respond to previous prices.\n\nSupport and resistance may be:\n\nHorizontal\n\nPsychological\n\nDynamic\n\nTrend-based\n\nVolume-based\n\nPrevious resistance may become support after a breakout.\n\nPrevious support may become resistance after a breakdown.\n\nThis is known as role reversal.\n\nA breakout or breakdown becomes more credible when supported by:\n\nA decisive close\n\nVolume\n\nFollow-through\n\nMarket acceptance\n\nA successful retest\n\nFalse breakouts and liquidity sweeps can move price temporarily beyond visible levels before reversal.\n\nSupport and resistance should be treated as probability zones rather than guaranteed barriers.\n\nTheir primary value is helping participants define:\n\nMarket context\n\nPotential entries\n\nTargets\n\nInvalidation\n\nPosition size\n\nAlternative scenarios\n\n### Key Takeaway\n\nSupport and resistance do not tell the market where it must turn.\n\nThey show where buyers and sellers have previously demonstrated conviction and where they may act again.\n\nMark the zone, observe the reaction and define what would prove your interpretation wrong.\n\nThe level provides the context. Price behaviour provides the evidence.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,6,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-20-lesson-07','cognizen-crypto-mastery-foundations-production','Check your understanding','cmf-module-2-20','text','### Check your understanding\n\nAnswer these questions to self-assess your understanding before moving on.\n\n1. What is support?\n\n2. What is resistance?\n\n3. Why do support and resistance form?\n\n4. Why should levels generally be treated as zones?\n\n5. What is a swing high?\n\n6. What is a swing low?\n\n7. How do range boundaries function as support and resistance?\n\n8. What is a psychological level?\n\n9. What is dynamic support or resistance?\n\n10. How can a trend line act as a technical level?\n\n11. What is role reversal?\n\n12. What evidence may support a genuine breakout?\n\n13. What is a retest?\n\n14. What is a false breakout?\n\n15. What is a liquidity sweep?\n\n16. How does market acceptance differ from rejection?\n\n17. Why can repeated tests weaken a level?\n\n18. What factors can increase a zone’s significance?\n\n19. How can volume support the analysis?\n\n20. Why should higher-timeframe levels generally receive greater attention?\n\n21. How can a stablecoin depeg distort technical levels?\n\n22. Why should stop distance affect position size?\n\n23. What is confluence?\n\n24. Why should support and resistance not replace fundamental analysis?','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,7,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `course_sections` (`id`,`course_id`,`title`,`position`,`created_at`) SELECT 'cmf-module-2-21','cognizen-crypto-mastery-foundations-production','Module 2.21: Trends and Market Structure',21,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
