INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-21-lesson-01','cognizen-crypto-mastery-foundations-production','What Is a Trend? and Sideways Market Structure','cmf-module-2-21','text','### Learning Objectives\n\nBy the end of this module, you should be able to:\n\nDefine an uptrend, downtrend and sideways market\n\nIdentify swing highs and swing lows\n\nRecognise higher-high, higher-low, lower-high and lower-low structures\n\nDistinguish between trend continuation, correction and reversal\n\nExplain breaks of structure and changes in market character\n\nUnderstand how trends differ across timeframes\n\nEvaluate trend strength using price behaviour, volume and momentum\n\nUse market structure to define risk and invalidation\n\nAvoid assuming that every short-term movement represents a new trend\n\n### Introduction\n\nA cryptocurrency chart can appear chaotic when viewed as a collection of individual price movements.\n\nPrice rises, falls, pauses, reverses and accelerates. Short-term volatility can make it difficult to identify what the market is actually doing.\n\nMarket structure helps organise this movement.\n\nIt examines the sequence of important highs and lows to determine whether buyers, sellers or neither side currently controls the market.\n\nA market that repeatedly forms higher highs and higher lows is generally trending upward.\n\nA market that forms lower highs and lower lows is generally trending downward.\n\nWhen price remains between relatively stable boundaries, the market is consolidating or moving sideways.\n\nUnderstanding market structure helps participants answer questions such as:\n\nWhat is the prevailing trend?\n\nIs a decline a correction or the beginning of a reversal?\n\nHas an important price level failed?\n\nWhere would the current market view be invalidated?\n\nIs a possible entry aligned with or opposed to the broader trend?\n\nMarket structure does not predict the future with certainty.\n\nIt provides a consistent way to interpret the evidence currently visible in price.\n\n### What Is a Trend?\n\nA trend is the general direction in which a market moves over a meaningful period.\n\nThe three broad trend categories are:\n\nUptrend\n\nDowntrend\n\nSideways trend\n\nA trend does not require price to move continuously in one direction.\n\nAn uptrend includes declines.\n\nA downtrend includes rallies.\n\nThese countertrend movements are a normal part of market behaviour.\n\nThe broader sequence of highs and lows determines the trend—not every individual candle.\n\n### Swing Highs and Swing Lows\n\nMarket structure is built around swing points.\n\n### Swing High\n\nA swing high is a local price peak where an advance stops and price begins moving lower.\n\nIt represents an area where selling pressure became stronger than buying demand.\n\n### Swing Low\n\nA swing low is a local price bottom where a decline stops and price begins moving higher.\n\nIt represents an area where buying demand became stronger than selling pressure.\n\nImportant swing points may later function as:\n\nSupport\n\nResistance\n\nBreakout levels\n\nInvalidation points\n\nProfit targets\n\nNot every small fluctuation is a meaningful swing.\n\nThe importance of a swing generally increases when it:\n\nAppears on a higher timeframe\n\nProduces a large market reaction\n\nForms with significant volume\n\nDefines an established trend\n\nIs observed by many market participants\n\n### Uptrend Structure\n\nAn uptrend commonly consists of:\n\nHigher highs\n\nHigher lows\n\n### Higher High\n\nA higher high forms when price rises above the previous important swing high.\n\nThis suggests buyers are willing and able to transact at progressively higher prices.\n\n### Higher Low\n\nA higher low forms when a correction ends above the previous important swing low.\n\nThis suggests buyers are entering before price returns to the earlier low.\n\nA simplified uptrend may develop as follows:\n\nPrice rises to a swing high\n\nPrice corrects to a swing low\n\nPrice rises above the previous high\n\nPrice corrects but remains above the previous low\n\nThe sequence continues\n\nThe higher low is particularly important because it shows where buyers defended the trend.\n\n### Downtrend Structure\n\nA downtrend commonly consists of:\n\nLower highs\n\nLower lows\n\n### Lower Low\n\nA lower low forms when price declines below the previous important swing low.\n\nThis suggests sellers are willing to accept progressively lower prices.\n\n### Lower High\n\nA lower high forms when a recovery fails below the previous important swing high.\n\nThis suggests sellers are entering before price can recover fully.\n\nA simplified downtrend may develop as follows:\n\nPrice falls to a swing low\n\nPrice recovers to a swing high\n\nPrice falls below the previous low\n\nPrice rallies but remains below the previous high\n\nThe sequence continues\n\nThe lower high is an important area because it shows where selling pressure re-entered the market.\n\n### Sideways Market Structure\n\nA sideways market occurs when price does not maintain a sequence of higher highs or lower lows.\n\nInstead, it moves between:\n\nSupport near the lower boundary\n\nResistance near the upper boundary\n\nThis may be described as:\n\nConsolidation\n\nA range\n\nMarket balance\n\nSideways movement\n\nDuring consolidation:\n\nBuyers respond near support\n\nSellers respond near resistance\n\nBreakouts repeatedly fail\n\nPrice returns toward the centre\n\nA range is not the absence of market structure.\n\nIt is a structure in which neither buyers nor sellers maintain directional control.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,1,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-21-lesson-02','cognizen-crypto-mastery-foundations-production','Impulse and Correction and Minor Structure','cmf-module-2-21','text','### Impulse and Correction\n\nTrends usually develop through alternating impulse and corrective movements.\n\n### Impulse Move\n\nAn impulse move travels in the direction of the broader trend.\n\nIn an uptrend, the upward movement is the impulse.\n\nIn a downtrend, the downward movement is the impulse.\n\nImpulse moves may show:\n\nLarger candles\n\nStrong closes\n\nExpanding volume\n\nLimited overlap\n\nIncreasing momentum\n\n### Corrective Move\n\nA correction moves temporarily against the broader trend.\n\nIn an uptrend, the correction moves downward.\n\nIn a downtrend, the correction moves upward.\n\nCorrective moves may show:\n\nSmaller candles\n\nGreater overlap\n\nLower volume\n\nSlower momentum\n\nRepeated short-term reversals\n\nA correction does not automatically mean the trend has ended.\n\nThe structure remains intact until important swing levels fail.\n\n### Healthy and Weakening Trends\n\nNot all trends have the same strength.\n\n### Characteristics of a Healthy Uptrend\n\nClear higher highs and higher lows\n\nStrong upward impulse moves\n\nControlled corrections\n\nBuyers responding at support\n\nBreakouts holding above resistance\n\nVolume supporting advances\n\n### Signs of a Weakening Uptrend\n\nSmaller upward movements\n\nDeeper corrections\n\nFailed higher highs\n\nLong upper wicks near resistance\n\nDeclining volume on advances\n\nBreak below an important higher low\n\n### Characteristics of a Healthy Downtrend\n\nClear lower highs and lower lows\n\nStrong downward impulse moves\n\nWeak recovery rallies\n\nSellers responding at resistance\n\nSupport levels breaking\n\nVolume expanding during declines\n\n### Signs of a Weakening Downtrend\n\nSmaller downward movements\n\nFailure to create new lows\n\nStronger recovery rallies\n\nLong lower wicks near support\n\nReduced selling volume\n\nBreak above an important lower high\n\nWeakening momentum is not the same as a confirmed reversal.\n\nThe market may consolidate before continuing in the original direction.\n\n### Trend Continuation\n\nTrend continuation occurs when the existing directional structure remains intact.\n\nIn an uptrend, continuation may involve:\n\nPrice forming a higher high\n\nA correction remaining above the previous swing low\n\nBuyers returning\n\nPrice breaking to another higher high\n\nIn a downtrend, continuation may involve:\n\nPrice forming a lower low\n\nA recovery remaining below the previous swing high\n\nSellers returning\n\nPrice breaking to another lower low\n\nContinuation setups generally align with the established direction.\n\nTrading with a trend does not guarantee success, but it avoids requiring the market to reverse before the position can work.\n\n### Trend Reversal\n\nA trend reversal occurs when the existing structure changes direction.\n\nAn uptrend does not become a confirmed downtrend merely because price falls.\n\nA more complete bearish reversal may involve:\n\nFailure to create a convincing higher high\n\nBreak below an important higher low\n\nRecovery that forms a lower high\n\nFurther decline to a lower low\n\nSimilarly, a downtrend may reverse when:\n\nPrice fails to create a lower low\n\nAn important lower high is broken\n\nA pullback forms a higher low\n\nPrice advances to a higher high\n\nA reversal is a process rather than one candle or one indicator signal.\n\n### Break of Structure\n\nA break of structure, often abbreviated as BOS, occurs when price moves beyond an important swing point in the direction of the existing trend.\n\nIn an uptrend, a move above the previous swing high may confirm bullish continuation.\n\nIn a downtrend, a move below the previous swing low may confirm bearish continuation.\n\nA meaningful break may be supported by:\n\nA decisive candle close\n\nIncreased trading volume\n\nStrong momentum\n\nContinued movement after the break\n\nSuccessful retesting of the level\n\nA brief wick beyond a swing point followed by immediate reversal may represent a false break or liquidity sweep rather than lasting structural change.\n\n### Change of Character\n\nA change of character, sometimes abbreviated as CHoCH, describes an early structural movement against the prevailing trend.\n\nFor example, in an uptrend, price may break below the most recent higher low.\n\nThis suggests that buyer control may be weakening.\n\nIn a downtrend, a break above the most recent lower high may suggest improving buyer strength.\n\nA change of character is an alert, not automatic confirmation of a complete reversal.\n\nAfter the initial break, price may:\n\nEstablish a new trend\n\nEnter consolidation\n\nRecover and continue the original trend\n\nProduce a false structural signal\n\nLater price behaviour must confirm whether control has genuinely changed.\n\n### Major and Minor Structure\n\nMarkets contain structure within structure.\n\n### Major Structure\n\nRepresents the important swings defining the broader trend.\n\nIt is usually more visible on higher timeframes.\n\n### Minor Structure\n\nRepresents smaller fluctuations occurring within the major trend.\n\nFor example, a daily uptrend may contain an hourly downtrend during a correction.\n\nThe hourly decline may be significant for a short-term trader but remain a minor correction for a long-term investor.\n\nConfusing minor structure with major structure can cause participants to react excessively to ordinary volatility.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,2,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-21-lesson-03','cognizen-crypto-mastery-foundations-production','Internal and External Structure and Absorption','cmf-module-2-21','text','### Internal and External Structure\n\nSome analysts distinguish between internal and external market structure.\n\n### External Structure\n\nThe larger swing highs and lows defining the main range or trend.\n\n### Internal Structure\n\nSmaller movements occurring inside those boundaries.\n\nPrice may break several internal levels without changing the external trend.\n\nA major reversal generally requires evidence that the broader external structure has changed.\n\nThis distinction helps prevent every short-term fluctuation from being labelled a market reversal.\n\n### Multi-Timeframe Market Structure\n\nThe same asset can have different trends across different timeframes.\n\nFor example:\n\nMonthly chart: uptrend\n\nWeekly chart: consolidation\n\nDaily chart: downtrend\n\nHourly chart: short-term recovery\n\nNone of these descriptions is necessarily incorrect.\n\nThey answer different questions.\n\nA long-term investor may focus on monthly and weekly structure.\n\nA swing trader may focus on weekly and daily structure.\n\nAn intraday trader may focus on hourly and shorter periods.\n\nBefore analysing structure, define the relevant timeframe.\n\n### Top-Down Market Structure Analysis\n\nA top-down process begins with the larger timeframe.\n\n### Step 1: Identify the Higher-Timeframe Trend\n\nUse weekly or daily structure to determine the broader direction.\n\n### Step 2: Mark Major Swing Levels\n\nIdentify important highs, lows, support and resistance.\n\n### Step 3: Move to the Decision Timeframe\n\nExamine whether the shorter-term structure aligns with the broader trend.\n\n### Step 4: Refine Entry and Risk\n\nUse a shorter timeframe to identify:\n\nConfirmation\n\nInvalidation\n\nPosition size\n\nExecution level\n\nThis approach helps align smaller decisions with the larger market context.\n\n### Trend Alignment\n\nTrend alignment occurs when several relevant timeframes point in the same direction.\n\nFor example:\n\nWeekly: uptrend\n\nDaily: uptrend\n\nFour-hour: correction ending at support\n\nThis may offer stronger directional evidence than a setup where the timeframes conflict.\n\nHowever, perfect alignment often becomes visible only after price has already moved substantially.\n\nWaiting for greater confirmation reduces uncertainty but can worsen the entry price.\n\nThe trade-off between early entry and confirmation cannot be eliminated.\n\n### Countertrend Trading\n\nCountertrend trading involves taking a position against the prevailing trend.\n\nExamples include:\n\nBuying during a strong downtrend\n\nShorting during a strong uptrend\n\nCountertrend opportunities may arise near:\n\nMajor support or resistance\n\nExhaustion moves\n\nFailed breakouts\n\nMomentum divergences\n\nHigher-timeframe turning points\n\nCountertrend positions are generally more demanding because the trader must identify when the dominant side is losing control.\n\nPotential challenges include:\n\nStrong momentum continuing\n\nReversal signals failing\n\nReduced risk-to-reward after waiting for confirmation\n\nEmotional attempts to predict the exact top or bottom\n\nBeginners often confuse a lower price with a confirmed reversal.\n\n### Pullbacks\n\nA pullback is a temporary movement against the prevailing trend.\n\nIn an uptrend, a pullback may return toward:\n\nPrevious resistance turned support\n\nA rising trend line\n\nA moving average\n\nAn earlier breakout zone\n\nA higher low\n\nIn a downtrend, a recovery may return toward:\n\nPrevious support turned resistance\n\nA falling trend line\n\nA moving average\n\nA lower high\n\nA pullback can offer a more favourable entry than chasing an extended impulse.\n\nHowever, a pullback can develop into a reversal.\n\nThe structure and invalidation level must be defined.\n\n### Retracements\n\nA retracement measures how far price moves back through a previous impulse.\n\nA shallow retracement may indicate strong trend momentum.\n\nA deep retracement may indicate:\n\nIncreased opposition\n\nWeakening trend strength\n\nHigher volatility\n\nPossible structural change\n\nThere is no universal retracement percentage that separates a healthy correction from a reversal.\n\nThe key evidence is whether important structure holds and whether the original trend resumes.\n\n### Trend Exhaustion\n\nTrend exhaustion occurs when the dominant side can no longer sustain the existing movement.\n\nPossible signs include:\n\nSmaller impulse moves\n\nFailed breakouts\n\nLonger rejection wicks\n\nDecreasing volume\n\nIncreasingly deep corrections\n\nMomentum divergence\n\nRapid final price acceleration\n\nStructural break\n\nExhaustion can precede a reversal or consolidation.\n\nIt does not provide an exact timing signal.\n\nMarkets can remain extended or weak for longer than expected.\n\n### Expansion and Compression\n\n\n\n### Expansion\n\nPrice moves strongly and ranges increase.\n\nExpansion may indicate:\n\nTrend continuation\n\nBreakout\n\nPanic\n\nLiquidation\n\nStrong market participation\n\n### Compression\n\nPrice ranges become smaller and movement slows.\n\nCompression may indicate:\n\nConsolidation\n\nReduced liquidity\n\nMarket indecision\n\nPreparation for a larger move\n\nCompression frequently precedes expansion, but it does not determine direction.\n\nThe eventual break must be evaluated through structure, volume and follow-through.\n\n### Market Structure and Volume\n\nVolume can help evaluate structural changes.\n\n### Bullish Break With Rising Volume\n\nMay indicate strong buyer participation.\n\n### Bearish Break With Rising Volume\n\nMay indicate forceful selling or liquidations.\n\n### Structural Break With Weak Volume\n\nMay be less convincing, particularly in a liquid market.\n\n### High Volume Without Continued Movement\n\nMay indicate absorption, where strong opposing orders prevent further movement.\n\nVolume provides context but does not independently prove continuation or reversal.\n\n### Absorption\n\nAbsorption occurs when aggressive buying or selling is met by sufficient opposing liquidity to prevent further price movement.\n\nFor example:\n\nStrong selling enters near support\n\nLarge buyers absorb the sell orders\n\nPrice stops declining\n\nThe market later recovers\n\nHigh volume with limited downward progress may suggest seller exhaustion or buyer absorption.\n\nHowever, the same activity may represent temporary support before another decline.\n\nConfirmation from later structure is required.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,3,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-21-lesson-04','cognizen-crypto-mastery-foundations-production','Trend Strength and Candle Behaviour and Market Structure and Targets','cmf-module-2-21','text','### Trend Strength and Candle Behaviour\n\nCandles can provide visual evidence of trend quality.\n\n### Strong Uptrend Behaviour\n\nLarge bullish bodies\n\nCloses near highs\n\nSmall or controlled pullbacks\n\nBreakouts holding\n\nLimited candle overlap\n\n### Weakening Uptrend Behaviour\n\nSmall bullish bodies\n\nLong upper wicks\n\nGreater overlap\n\nFailed highs\n\nStrong bearish responses\n\n### Strong Downtrend Behaviour\n\nLarge bearish bodies\n\nCloses near lows\n\nWeak recoveries\n\nSupport breaking\n\nLimited overlap\n\n### Weakening Downtrend Behaviour\n\nLong lower wicks\n\nSmaller bearish candles\n\nStronger bullish responses\n\nFailure to create lower lows\n\nCandle behaviour supports the structural analysis but does not replace it.\n\n### Trend Lines and Channels\n\nTrend lines can help visualise structure.\n\nA rising trend line connects important higher lows.\n\nA falling trend line connects important lower highs.\n\nChannels use roughly parallel lines to contain price movement.\n\nA break of a trend line may suggest weakening momentum.\n\nHowever, it does not necessarily change the sequence of major swing highs and lows.\n\nMarket structure generally deserves greater priority than one subjective trend line.\n\nA line can be redrawn. A confirmed swing break is more objectively observable.\n\n### Moving Averages and Trend Structure\n\nMoving averages can help smooth price and display directional bias.\n\nA rising average with price above it may support an uptrend interpretation.\n\nA falling average with price below it may support a downtrend interpretation.\n\nHowever, moving averages are derived from historical data.\n\nThey may:\n\nLag structural changes\n\nProduce false signals during consolidation\n\nDiffer according to the selected setting\n\nUse moving averages as supporting evidence rather than as the sole definition of trend.\n\n### Trend Duration\n\nTrends may exist over:\n\nMinutes\n\nHours\n\nDays\n\nMonths\n\nYears\n\nA long-running trend may have greater structural significance, but it may also be closer to exhaustion.\n\nTrend duration alone does not determine whether continuation is likely.\n\nConsider:\n\nMomentum\n\nAdoption\n\nValuation\n\nLiquidity\n\nLeverage\n\nBroader market conditions\n\nThe statement “the trend is your friend” should be completed with:\n\nuntil the structure and evidence show that it has changed.\n\n### Trend Maturity\n\nA trend can be considered early, established or mature.\n\n### Early Trend\n\nInitial structural change\n\nLimited confirmation\n\nPotentially favourable entry\n\nHigher uncertainty\n\n### Established Trend\n\nClear continuation structure\n\nBroader participation\n\nGreater confirmation\n\nSome movement already completed\n\n### Mature Trend\n\nExtended price movement\n\nWidespread recognition\n\nPotential overconfidence\n\nGreater risk of exhaustion or reversal\n\nEntering earlier offers greater potential reward but less confirmation.\n\nEntering later offers more evidence but may provide a poorer risk-to-reward relationship.\n\n### Market Structure and Liquidity\n\nImportant swing highs and lows often contain clusters of orders.\n\nAbove a swing high, there may be:\n\nShort stop losses\n\nBreakout buy orders\n\nProfit targets\n\nBelow a swing low, there may be:\n\nLong stop losses\n\nBreakdown sell orders\n\nLiquidations\n\nPrice may move through a swing level to access this liquidity before reversing.\n\nA wick beyond structure does not always confirm a breakout.\n\nEvaluate whether price:\n\nCloses beyond the level\n\nContinues moving\n\nRetests successfully\n\nGains acceptance in the new area\n\n### Structural Break or Liquidity Sweep?\n\nA movement beyond a swing point may represent either:\n\nGenuine structural change\n\nTemporary liquidity sweep\n\n### Evidence Supporting a Genuine Break\n\nStrong close beyond the level\n\nExpanded volume\n\nContinued movement\n\nNew structure forming beyond it\n\nSuccessful retest\n\n### Evidence Supporting a Sweep\n\nBrief wick beyond the level\n\nImmediate return\n\nStrong rejection\n\nNo follow-through\n\nClose back inside the previous structure\n\nThe distinction is often clear only after the event.\n\nWaiting for evidence reduces uncertainty but cannot remove it.\n\n### Market Structure and Entry Planning\n\nMarket structure can provide a framework for entries.\n\nA trend-aligned long setup might involve:\n\nHigher-timeframe uptrend\n\nPullback toward support\n\nFormation of a higher low\n\nBullish confirmation\n\nInvalidation below the structural low\n\nA trend-aligned short setup might involve:\n\nHigher-timeframe downtrend\n\nRecovery toward resistance\n\nFormation of a lower high\n\nBearish confirmation\n\nInvalidation above the structural high\n\nThe setup remains probabilistic.\n\nThe purpose of structure is to define both the opportunity and the point at which it fails.\n\n### Market Structure and Stop Placement\n\nFor a long position, invalidation may be placed below an important higher low.\n\nFor a short position, invalidation may be placed above an important lower high.\n\nHowever, the stop should also account for:\n\nVolatility\n\nLiquidity sweeps\n\nExchange differences\n\nPosition size\n\nTimeframe\n\nA wider structural stop requires a smaller position to keep capital risk unchanged.\n\nThe stop should be connected to the analysis—not selected merely because it creates a convenient position size.\n\n### Market Structure and Targets\n\nPotential targets may include:\n\nPrevious swing highs\n\nPrevious swing lows\n\nRange boundaries\n\nMajor support or resistance\n\nAreas of likely liquidity\n\nHigher-timeframe structural levels\n\nA trend continuation may target the next major swing area.\n\nA range trade may target the opposite side of the range.\n\nTargets should reflect realistic market structure and liquidity rather than arbitrary percentage gains.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,4,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-21-lesson-05','cognizen-crypto-mastery-foundations-production','Market Structure and Fundamental Events and Module Summary','cmf-module-2-21','text','### Market Structure and Fundamental Events\n\nMajor events can disrupt established technical structure.\n\nExamples include:\n\nRegulatory decisions\n\nExchange failures\n\nSecurity exploits\n\nToken unlocks\n\nNetwork outages\n\nEconomic announcements\n\nA strong trend can reverse abruptly when new information changes market expectations.\n\nTechnical analysis shows the market response.\n\nFundamental analysis helps explain whether the event has changed the underlying investment case.\n\nBoth perspectives may be necessary.\n\n### Market Structure in Low-Liquidity Tokens\n\nStructure is less reliable when a token has:\n\nLow trading volume\n\nWide spreads\n\nFew market participants\n\nConcentrated ownership\n\nEasily manipulated prices\n\nOne large order can create an apparent breakout, higher high or lower low without broad market participation.\n\nBefore analysing structure, confirm:\n\nExchange quality\n\nOrder-book depth\n\nLiquidity-pool size\n\nGenuine trading activity\n\nA clear chart does not guarantee a reliable market.\n\n### A Market-Structure Analysis Process\n\n\n\n### Step 1: Confirm the Market\n\nIdentify:\n\nAsset\n\nExchange\n\nTrading pair\n\nLiquidity\n\n### Step 2: Select the Relevant Timeframe\n\nMatch the timeframe to the intended decision horizon.\n\n### Step 3: Mark Major Swing Highs and Lows\n\nFocus on levels that produced meaningful reactions.\n\n### Step 4: Classify the Structure\n\nDetermine whether the market is forming:\n\nHigher highs and higher lows\n\nLower highs and lower lows\n\nA range\n\n### Step 5: Distinguish Impulse From Correction\n\nAssess the direction and strength of each movement.\n\n### Step 6: Evaluate Trend Quality\n\nExamine:\n\nCandle behaviour\n\nVolume\n\nMomentum\n\nDepth of corrections\n\nBreakout follow-through\n\n### Step 7: Identify Critical Structural Levels\n\nDetermine which swing point must hold for the current trend interpretation to remain valid.\n\n### Step 8: Consider Multiple Timeframes\n\nCheck whether the decision aligns with or opposes the broader structure.\n\n### Step 9: Define Alternative Scenarios\n\nWhat happens if the trend continues, consolidates or reverses?\n\n### Step 10: Calculate Risk\n\nUse structural invalidation to determine appropriate position size.\n\n### Market-Structure Checklist\n\nBefore acting, ask:\n\nWhich timeframe am I analysing?\n\nWhat is the broader higher-timeframe trend?\n\nWhere are the important swing highs and lows?\n\nIs price forming higher highs and higher lows?\n\nIs price forming lower highs and lower lows?\n\nIs the market consolidating?\n\nWhich movements are impulses?\n\nWhich movements are corrections?\n\nIs trend momentum strengthening or weakening?\n\nAre corrections becoming deeper?\n\nDoes volume support structural breaks?\n\nHas price closed beyond the swing level?\n\nIs there follow-through?\n\nCould the move be a liquidity sweep?\n\nWhat level invalidates the current structure?\n\nDoes the entry offer acceptable risk-to-reward?\n\nIs the position aligned with or opposed to the broader trend?\n\nIs market liquidity sufficient for reliable analysis and execution?\n\nAm I reacting to minor structure while ignoring major structure?\n\nWhat evidence would confirm a genuine reversal?\n\n### Common Market-Structure Mistakes\n\n\n\n### Treating Every Price Movement as a New Trend\n\nShort-term fluctuations are confused with major structural change.\n\n### Ignoring the Timeframe\n\nA five-minute downtrend is used to reject a long-term bullish structure.\n\n### Declaring a Reversal Too Early\n\nOne candle or one minor swing is treated as proof of a complete trend change.\n\n### Ignoring Failed Higher Highs or Lower Lows\n\nWeakening structure is dismissed because the participant is emotionally committed.\n\n### Using Only Trend Lines\n\nA subjective line receives more weight than actual swing structure.\n\n### Acting on Wicks Alone\n\nA liquidity sweep is mistaken for a confirmed structural break.\n\n### Entering After an Extended Impulse\n\nThe trend is correct, but the entry offers poor risk-to-reward.\n\n### Moving Invalidation Levels\n\nThe structural thesis is changed after price contradicts it.\n\n### Ignoring Liquidity\n\nA manipulated or thin market produces misleading structure.\n\n### Switching Timeframes After a Loss\n\nA failed short-term position is reclassified as a long-term investment.\n\n### Common Misunderstandings\n\n#### “An Uptrend Means Price Will Continue Rising”\n\nThe structure describes current behaviour, not guaranteed continuation.\n\n#### “Any Break Below a Higher Low Ends the Bull Market”\n\nThe significance depends on whether the swing is major or minor and which timeframe is being analysed.\n\n#### “A Break of Structure Confirms a Reversal”\n\nA trend-direction break may provide early evidence, but new opposite structure should develop.\n\n#### “A Trend-Line Break Is the Same as a Market-Structure Break”\n\nA trend line is subjective; major swing structure may remain intact.\n\n#### “A Lower Price Means a Downtrend Is Ending”\n\nPrice can continue producing lower lows.\n\n#### “A Strong Trend Is Safe to Chase”\n\nExtended trends can offer poor entries and may be near exhaustion.\n\n#### “Several Timeframes Must Always Agree”\n\nTimeframes often conflict because they measure different market horizons.\n\n#### “A Wick Beyond a Swing Point Confirms the Break”\n\nThe market may reject the level and return immediately.\n\n#### “Market Structure Works Equally Well in Every Token”\n\nLow liquidity and manipulation can reduce reliability.\n\n### Module Summary\n\nMarket structure organises price movement through important swing highs and swing lows.\n\nAn uptrend commonly forms:\n\nHigher highs\n\nHigher lows\n\nA downtrend commonly forms:\n\nLower highs\n\nLower lows\n\nA sideways market moves within defined support and resistance boundaries.\n\nTrends develop through alternating impulse and corrective movements.\n\nA break of structure generally confirms continuation in the existing direction.\n\nA change of character may provide early evidence that the trend is weakening or reversing.\n\nHowever, a full reversal usually requires the development of new opposite structure.\n\nMarket structure differs across timeframes.\n\nA short-term decline can occur inside a long-term uptrend.\n\nTrend quality can be evaluated through:\n\nPrice structure\n\nCandle behaviour\n\nMomentum\n\nVolume\n\nCorrection depth\n\nBreakout follow-through\n\nImportant swing points can provide references for entries, targets and invalidation.\n\nThe purpose of market structure is not to guarantee the next move.\n\nIt is to define what the market is currently doing and what evidence would demonstrate that the interpretation is wrong.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,5,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-21-lesson-06','cognizen-crypto-mastery-foundations-production','Key Takeaway','cmf-module-2-21','text','### Market control and structure as a decision framework\n\nMarket structure is not certainty. It is a method for defining control at the current timeframe.\n\nControl changes when participants stop defending the prior swing structure and new structure gains confirmation.\n\n### Core structure logic\n\n- Uptrend: higher highs and higher lows\n- Downtrend: lower highs and lower lows\n- Range: overlapping buyer-seller response at a temporary balance\n\nStructure is meaningful only in the timeframe and market you actually trade.\n\n### Control means in practice\n\nControl is a probability statement.\n\nYour process should answer:\n\n- What level invalidates the current structure?\n- What confirms continuation?\n- What would flip the view?\n- Where does liquidity sit relative to your planned size?\n\n### Decision framework\n\n1. Confirm timeframe, exchange and pair\n2. Mark relevant swing points\n3. Distinguish impulse and correction\n4. Verify follow-through with volume and depth\n5. Match position size to invalidation distance\n6. Review faster when structure is mixed or uncertain\n\n### Institutional risk translation\n\n- If structure is weak, reduce size.\n- If structure is clean and liquidity stable, confidence may rise, but never to certainty.\n- If data is mixed, keep exposure smaller and review faster.\n\n### Module takeaway\n\nMarket structure gives language to your behavior:\n\n"This is what the market is showing now, and this is what I will do when it changes."\n\nYour edge is in testing views, sizing risk, and acting only when structure and liquidity align.\n','markdown',NULL,NULL,NULL,1,0,0,0,'',NULL,6,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-21-lesson-07','cognizen-crypto-mastery-foundations-production','Check your understanding','cmf-module-2-21','text','### Check your understanding\n\nAnswer these questions to self-assess your understanding before moving on.\n\n1. What is a market trend?\n\n2. What is a swing high?\n\n3. What is a swing low?\n\n4. Which price sequence commonly defines an uptrend?\n\n5. Which price sequence commonly defines a downtrend?\n\n6. What defines a sideways market?\n\n7. What is an impulse move?\n\n8. What is a corrective move?\n\n9. What signs may indicate a weakening uptrend?\n\n10. What signs may indicate a weakening downtrend?\n\n11. What is trend continuation?\n\n12. What structural process may confirm a trend reversal?\n\n13. What is a break of structure?\n\n14. What is a change of character?\n\n15. How does major structure differ from minor structure?\n\n16. Why can the same asset show different trends on different timeframes?\n\n17. What is top-down analysis?\n\n18. What is a pullback?\n\n19. What is trend exhaustion?\n\n20. How can volume support a structural break?\n\n21. What is absorption?\n\n22. How does a liquidity sweep differ from a confirmed structural break?\n\n23. How can market structure assist with stop placement?\n\n24. Why should position size change when the structural invalidation point is farther away?\n\n25. Why is market structure less reliable in an illiquid token?','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,7,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `course_sections` (`id`,`course_id`,`title`,`position`,`created_at`) SELECT 'cmf-module-2-22','cognizen-crypto-mastery-foundations-production','Module 2.22: Trading Volume and Liquidity',22,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
