INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-27-lesson-01','cognizen-crypto-mastery-foundations-production','What Is Staking? and Native Staking','cmf-module-2-27','text','### Learning Objectives\n\nBy the end of this module, you should be able to:\n\nExplain how proof-of-stake networks use validators and delegated capital\n\nDistinguish between native staking, delegated staking, pooled staking and liquid staking\n\nIdentify the sources of staking rewards\n\nCalculate nominal and approximate real staking returns\n\nExplain inflation, dilution, compounding and validator commissions\n\nUnderstand lock-up, unbonding, slashing and liquidity risks\n\nDistinguish protocol staking from centralised and DeFi yield products\n\nExplain how liquid-staking tokens operate\n\nIdentify restaking and layered yield risks\n\nEvaluate whether an advertised yield is sustainable\n\nAssess a staking opportunity using a structured framework\n\nApply safer staking and yield-generation practices\n\n### Introduction\n\nCryptocurrency holders are often encouraged to make their assets “work” by staking them or depositing them into yield-generating products.\n\nThe advertised benefit may be expressed as:\n\nStaking rewards\n\nInterest\n\nYield\n\nAnnual percentage rate\n\nAnnual percentage yield\n\nPassive income\n\nThese terms can make the return appear similar to interest earned through a conventional savings account.\n\nThe underlying economics are often very different.\n\nA staking reward may compensate a participant for:\n\nHelping secure a blockchain\n\nOperating a validator\n\nDelegating capital\n\nAccepting a lock-up period\n\nBearing slashing risk\n\nReceiving newly issued tokens\n\nGiving up liquidity\n\nOther cryptocurrency yields may come from:\n\nBorrower interest\n\nTrading fees\n\nToken incentives\n\nProtocol revenue\n\nMarket-making activity\n\nLeverage\n\nRehypothecation\n\nLending customer assets to third parties\n\nThe source of the return determines the risk.\n\nA twenty-percent reward created through token inflation is economically different from a five-percent return paid from genuine protocol fees.\n\nA yield product involving several smart contracts, bridges and leveraged strategies is different from native blockchain staking.\n\nThe central question is not:\n\nWhat percentage can I earn?\n\nIt is:\n\nWhere does the yield come from, what risks must I accept, and what is the return after inflation, fees and asset-price changes?\n\n### What Is Staking?\n\nStaking is the process of committing cryptocurrency to support the operation or security of a proof-of-stake blockchain.\n\nDepending on the network, staked assets may help with:\n\nSelecting validators\n\nProposing blocks\n\nConfirming transactions\n\nSecuring network consensus\n\nDiscouraging dishonest behaviour\n\nParticipating in governance\n\nIn return, validators and delegators may receive rewards.\n\nThe precise process differs between blockchains.\n\nStaking does not always require transferring legal ownership of the asset, but it may restrict:\n\nTransferability\n\nWithdrawal\n\nUse in other applications\n\nImmediate access during an unbonding period\n\nThe staked token also remains exposed to market-price movements.\n\n### Proof of Stake\n\nProof of stake is a blockchain consensus model in which participants commit economic value to help secure the network.\n\nThe network may select validators according to factors such as:\n\nAmount staked\n\nRandom selection\n\nValidator performance\n\nDelegated stake\n\nNetwork-specific rules\n\nValidators may be responsible for:\n\nProposing blocks\n\nConfirming blocks\n\nParticipating in consensus\n\nRemaining online\n\nFollowing protocol rules\n\nHonest participation may earn rewards.\n\nDishonest or unreliable behaviour may result in lost rewards or slashing.\n\nThe stake creates an economic incentive to protect the network.\n\n### Validators\n\nA validator is a participant or system authorised by the protocol to perform consensus-related work.\n\nA validator may need to:\n\nDeposit a minimum stake\n\nOperate specialised software\n\nMaintain reliable infrastructure\n\nProtect signing keys\n\nMonitor network upgrades\n\nAvoid double-signing\n\nMeet performance standards\n\nValidator operation can be technically demanding.\n\nFailures may result in:\n\nMissed rewards\n\nPenalties\n\nSlashing\n\nTemporary removal\n\nDamage to delegators\n\nOperating a validator is not equivalent to simply holding tokens.\n\nIt is an active technical responsibility.\n\n### Delegators\n\nSome proof-of-stake networks allow token holders to delegate stake to an existing validator.\n\nThe delegator contributes economic weight without operating the validator infrastructure directly.\n\nThe validator may:\n\nEarn rewards on the combined stake\n\nDeduct a commission\n\nDistribute the remaining rewards to delegators\n\nDelegation can make staking more accessible.\n\nHowever, the delegator remains exposed to risks involving:\n\nValidator performance\n\nValidator honesty\n\nCommission changes\n\nSlashing\n\nGovernance concentration\n\nUnbonding periods\n\nDelegation transfers operational work. It does not remove staking risk.\n\n### Native Staking\n\nNative staking occurs through the blockchain’s own consensus mechanism.\n\nExamples of native activities may include:\n\nRunning a validator\n\nDelegating directly through the protocol\n\nParticipating in an official staking contract\n\nUsing network-supported staking functionality\n\nThe reward may come from:\n\nNew token issuance\n\nTransaction fees\n\nA combination of both\n\nOther protocol-level payments\n\nNative staking should be distinguished from lending the token to a company or depositing it into an unrelated DeFi contract.\n\nThe interface may use the word “staking” for several economically different activities.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,1,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-27-lesson-02','cognizen-crypto-mastery-foundations-production','Custodial Staking and Token Issuance and Inflation','cmf-module-2-27','text','### Custodial Staking\n\nCustodial staking occurs when a centralised provider stakes assets on behalf of customers.\n\nThe user deposits or retains assets with the provider.\n\nThe provider handles:\n\nValidator operation\n\nDelegation\n\nReward collection\n\nTechnical maintenance\n\nSometimes withdrawal processing\n\nPotential benefits include:\n\nSimpler participation\n\nLower technical requirements\n\nSmall minimum deposits\n\nAutomated reward distribution\n\nRisks include:\n\nCustodian insolvency\n\nWithdrawal restrictions\n\nAccount freezing\n\nProvider hacking\n\nMismanagement\n\nRegulatory intervention\n\nUnclear asset ownership\n\nThe user is exposed to both staking risk and counterparty risk.\n\n### Non-Custodial Delegation\n\nIn non-custodial delegation, the token holder delegates staking power while retaining control through their own wallet.\n\nThe tokens may remain associated with the user’s address but become subject to protocol restrictions.\n\nPotential advantages include:\n\nReduced counterparty exposure\n\nGreater transparency\n\nDirect protocol participation\n\nIndependent validator selection\n\nPotential risks include:\n\nWallet mistakes\n\nValidator penalties\n\nUnbonding delays\n\nMalicious interfaces\n\nIncorrect delegation transactions\n\nSeed-phrase loss\n\nNon-custodial does not mean risk-free.\n\nIt changes which party carries which responsibility.\n\n### Pooled Staking\n\nA staking pool combines assets from many participants.\n\nThis may allow users to participate when:\n\nThe network requires a large minimum stake\n\nValidator operation is technically difficult\n\nIndividual deposits are too small\n\nRewards need to be distributed efficiently\n\nA pool may be:\n\nCentralised\n\nSmart-contract based\n\nGoverned by a decentralised protocol\n\nOperated by several validators\n\nParticipants should understand:\n\nWho controls the pool\n\nHow rewards are calculated\n\nWhich fees apply\n\nWhether withdrawals are immediate\n\nWhat happens if a validator is penalised\n\nWhether the pool contract is upgradeable\n\n### Liquid Staking\n\nLiquid staking allows a user to stake an asset while receiving a transferable token representing the staked position.\n\nThe received token is often called a liquid-staking token, or LST.\n\nA simplified process may be:\n\nThe user deposits the native asset\n\nThe protocol stakes it through validators\n\nThe user receives an LST\n\nStaking rewards accumulate\n\nThe LST can be held, traded or used in DeFi\n\nThe user later redeems it for the underlying asset, subject to protocol rules\n\nLiquid staking reduces the opportunity cost of locked capital.\n\nIt also introduces additional layers of risk.\n\n### How Liquid-Staking Tokens Reflect Rewards\n\nAn LST may reflect rewards in one of two broad ways.\n\n### Rebasing Model\n\nThe number of tokens in the user’s wallet increases as rewards accrue.\n\nFor example:\n\nStarting balance: 100 LST\n\nLater balance: 104 LST\n\n### Exchange-Rate Model\n\nThe token quantity remains unchanged, but each LST becomes redeemable for more of the underlying asset.\n\nFor example:\n\nInitially: 1 LST = 1 underlying token\n\nLater: 1 LST = 1.04 underlying tokens\n\nThe economic effect may be similar, but accounting and tax treatment can differ by jurisdiction.\n\nUsers should understand which model applies.\n\n### Liquid-Staking Token Price\n\nAn LST may trade at a market price different from its theoretical redemption value.\n\nIt can trade below the underlying asset because of:\n\nRedemption delays\n\nSmart contract concerns\n\nValidator problems\n\nLiquidity shortages\n\nMarket panic\n\nLoss of confidence\n\nWithdrawal restrictions\n\nIt may trade above theoretical value because of:\n\nStrong DeFi demand\n\nLimited supply\n\nIncentive programmes\n\nTemporary market imbalance\n\nThe LST is a separate token with its own market and liquidity risk.\n\n### Redemption and Withdrawal Queues\n\nA liquid-staking protocol may not provide immediate redemption.\n\nWithdrawals may require:\n\nAn unbonding period\n\nA validator exit\n\nA queue\n\nProtocol processing\n\nSufficient liquid reserves\n\nDuring periods of heavy withdrawal demand, users may need to wait.\n\nSelling the LST on a secondary market may provide faster liquidity, but potentially at a discount.\n\n“Liquid” does not mean liquidity is guaranteed at full value under all conditions.\n\n### Sources of Staking Rewards\n\nStaking returns may come from several sources.\n\n### Token Issuance\n\nThe network creates new tokens and distributes them to validators and delegators.\n\n### Transaction Fees\n\nUsers pay fees to have transactions processed.\n\n### Priority Fees or Tips\n\nUsers may pay additional amounts for faster or preferred execution.\n\n### Protocol Incentives\n\nA treasury may subsidise staking to increase network security.\n\n### Maximum Extractable Value\n\nValidators or specialised systems may earn value from transaction ordering.\n\n### Other Network Revenue\n\nSome protocols may distribute application, data or service revenue.\n\nThe source affects whether the return represents real economic income or primarily dilution-funded compensation.\n\n### Token Issuance and Inflation\n\nMany networks create new tokens to reward staking participants.\n\nThis increases total supply.\n\nSuppose:\n\nTotal token supply grows by 8 percent\n\nA staker earns 10 percent\n\nA non-staker earns no additional tokens\n\nThe staker’s token quantity increases faster than total supply.\n\nTheir relative ownership may increase slightly before considering fees and compounding.\n\nHowever, the approximate return relative to supply growth is much smaller than the nominal ten percent.\n\nA simplified approximation is:\n\nReal token-denominated return ≈ Staking yield − Supply inflation\n\nUsing the example:\n\n10 percent − 8 percent = approximately 2 percent\n\nThe exact result depends on:\n\nCompounding\n\nValidator commission\n\nParticipation rate\n\nFee revenue\n\nSupply definitions\n\nReward timing','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,2,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-27-lesson-03','cognizen-crypto-mastery-foundations-production','Dilution of Non-Stakers and Real Yield','cmf-module-2-27','text','### Dilution of Non-Stakers\n\nWhen staking rewards are funded through issuance, non-staking holders may be diluted.\n\nTheir number of tokens remains unchanged while total supply increases.\n\nSuppose an investor holds one percent of the supply.\n\nIf new tokens are issued to stakers, the investor’s ownership percentage may decline.\n\nStaking can therefore function partly as protection against protocol-level dilution.\n\nHowever, participating merely to avoid dilution does not guarantee a positive investment return.\n\nThe token’s market price may still fall significantly.\n\n### Participation Rate\n\nThe staking participation rate is the percentage of eligible tokens currently staked.\n\nThis rate can influence rewards.\n\nIf a fixed reward pool is distributed among fewer staked tokens, the yield per staked token may be higher.\n\nIf more tokens enter staking, the yield may decline.\n\nA higher participation rate may:\n\nImprove network security\n\nReduce liquid market supply\n\nLower individual rewards\n\nIncrease governance concentration\n\nA lower participation rate may:\n\nIncrease reward rates\n\nReduce security\n\nIncrease liquid supply\n\nReflect weak holder confidence\n\nThe relationship differs by protocol.\n\n### Validator Commission\n\nValidators may deduct a commission from rewards before distributing them to delegators.\n\nSuppose:\n\nGross staking reward: 8 percent\n\nValidator commission: 10 percent of rewards\n\nThe commission is not ten percentage points.\n\nIt is ten percent of the reward.\n\nApproximate net reward:\n\n8 percent × 90 percent = 7.2 percent\n\nAdditional costs may include:\n\nPool fees\n\nWithdrawal fees\n\nNetwork fees\n\nLiquid-staking protocol fees\n\nTax\n\nThe advertised network reward may therefore differ from the user’s realised return.\n\n### Reward Variability\n\nStaking rewards may change because of:\n\nNetwork participation\n\nValidator performance\n\nTransaction activity\n\nFee levels\n\nProtocol upgrades\n\nGovernance decisions\n\nInflation schedules\n\nValidator commission\n\nPenalties\n\nMEV income\n\nA current staking rate is not a fixed long-term promise.\n\nAnnualising a short period can create misleading expectations.\n\nUsers should review the protocol’s reward formula and historical variability.\n\n### Annual Percentage Rate and Annual Percentage Yield\n\n\n\n### Annual Percentage Rate\n\nAPR generally represents a simple annualised return without compounding.\n\n### Annual Percentage Yield\n\nAPY generally assumes rewards are reinvested and compound.\n\nSuppose a staking position earns rewards throughout the year.\n\nIf rewards are regularly restaked, the user begins earning rewards on previous rewards.\n\nThis can increase the annual outcome.\n\nHowever, compounding may require:\n\nManual claiming\n\nAdditional transactions\n\nNetwork fees\n\nWaiting periods\n\nTaxable events\n\nA theoretical APY can overstate the practical return when compounding is costly or impossible.\n\n### Compounding Frequency\n\nMore frequent compounding can increase returns, but the benefit may be small relative to costs.\n\nA user should compare:\n\nAdditional reward from compounding\n\nNetwork fees\n\nValidator or protocol fees\n\nTime and operational effort\n\nTax implications\n\nFor a small position, frequent claims may consume more value than they create.\n\nAutomatic compounding may reduce effort but introduces reliance on another contract or provider.\n\n### Nominal Return Versus Real Economic Return\n\nA nominal staking return measures additional tokens earned.\n\nThe real economic outcome should consider:\n\nToken-price movement\n\nSupply inflation\n\nValidator commission\n\nProtocol fees\n\nNetwork costs\n\nTaxes\n\nLock-up costs\n\nOpportunity cost\n\nSlashing\n\nCounterparty or smart contract losses\n\nSuppose a participant earns twelve percent more tokens while the token’s price declines forty percent.\n\nThe token balance increased.\n\nThe market value of the position still fell materially.\n\nYield cannot compensate automatically for poor asset performance.\n\n### Example of Nominal and Market Return\n\nSuppose a user stakes:\n\n1,000 tokens\n\nInitial price: 10 units\n\nInitial position value: 10,000 units\n\nStaking reward: 8 percent\n\nAfter one year, the user has:\n\n1,080 tokens\n\nIf the token price remains at 10:\n\n1,080 × 10 = 10,800 units\n\nThe gross gain is eight percent before fees and taxes.\n\nIf the token price falls to 6:\n\n1,080 × 6 = 6,480 units\n\nDespite earning rewards, the position lost:\n\n10,000 − 6,480 = 3,520 units\n\nThe market-price risk dominated the staking yield.\n\n### Real Yield\n\nThe term real yield is used in different ways.\n\nIn traditional economics, real return usually means return after inflation.\n\nWithin cryptocurrency, some participants use “real yield” to describe rewards paid from genuine protocol revenue rather than newly issued tokens.\n\nFor example, a protocol may distribute:\n\nTransaction fees\n\nTrading fees\n\nApplication revenue\n\nService payments\n\nThis may be economically stronger than paying rewards entirely through inflation.\n\nHowever, revenue-based yield still requires analysis.\n\nAsk:\n\nIs the revenue sustainable?\n\nIs it paid by genuine users?\n\nDoes the token holder have a clear claim?\n\nAre expenses higher than revenue?\n\nCan governance change the distribution?\n\nIs the revenue concentrated in temporary speculation?\n\n“Real yield” is a description, not a guarantee of quality.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,3,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-27-lesson-04','cognizen-crypto-mastery-foundations-production','Yield Paid in the Same Token and Validator Keys','cmf-module-2-27','text','### Yield Paid in the Same Token\n\nA protocol may advertise high yield paid in its own token.\n\nSuppose a user earns fifty percent more tokens.\n\nIf supply expands rapidly and recipients sell rewards, the token price may fall.\n\nThe user may receive:\n\nMore units\n\nBut less total value\n\nEvaluate:\n\nIssuance rate\n\nVesting\n\nRecipient behaviour\n\nToken demand\n\nLiquidity\n\nUtility\n\nValue capture\n\nToken-denominated yield should not be confused with a stable increase in purchasing power.\n\n### Yield Paid in Another Token\n\nRewards may be paid in a separate incentive token.\n\nThis creates two asset exposures:\n\nThe staked asset\n\nThe reward token\n\nThe reward token may have:\n\nDifferent volatility\n\nDifferent liquidity\n\nHigh inflation\n\nSelling restrictions\n\nVesting\n\nLimited utility\n\nThe displayed yield may use the reward token’s current price.\n\nIf that price falls, the realised yield may be much lower.\n\n### Reward Vesting and Lock-Ups\n\nStaking rewards may not become immediately transferable.\n\nThey may be:\n\nLocked\n\nVested gradually\n\nSubject to a claim period\n\nReleased after unbonding\n\nPaid in an escrowed token\n\nConvertible only after a delay\n\nA nominal reward has less immediate value when it cannot be sold or used.\n\nUsers should distinguish between:\n\nAccrued rewards\n\nClaimable rewards\n\nTransferable rewards\n\nLiquid market value\n\n### Lock-Up Period\n\nSome staking systems require assets to remain locked for a specified time.\n\nDuring the lock-up, the user may be unable to:\n\nSell\n\nTransfer\n\nUse the asset as collateral\n\nRespond to market changes\n\nAccess emergency liquidity\n\nLonger lock-ups may offer higher rewards.\n\nThe additional yield compensates partly for reduced flexibility.\n\nA lock-up should be evaluated against the possibility of:\n\nSevere price decline\n\nProtocol changes\n\nPersonal liquidity needs\n\nValidator problems\n\nBetter opportunities elsewhere\n\n### Unbonding Period\n\nAn unbonding period is the delay between requesting to unstake and receiving transferable tokens.\n\nThe delay may help protect the network by preventing validators from withdrawing immediately after harmful behaviour.\n\nDuring unbonding:\n\nRewards may stop\n\nTokens may remain non-transferable\n\nMarket price may change\n\nSlashing exposure may continue\n\nWithdrawal may be delayed further\n\nThe unbonding period should be understood before staking.\n\nIt can materially change the liquidity risk of the position.\n\n### Slashing\n\nSlashing is a protocol penalty that removes part of a validator’s stake for prohibited or harmful behaviour.\n\nPossible causes include:\n\nDouble-signing\n\nSigning conflicting blocks\n\nExtended downtime\n\nConsensus violations\n\nKey compromise\n\nValidator misconfiguration\n\nThe severity differs between networks.\n\nSlashing may affect:\n\nThe validator’s own stake\n\nDelegated assets\n\nFuture reward eligibility\n\nValidator reputation\n\nA user delegating to a validator should determine whether delegated capital can be slashed.\n\n### Downtime Penalties\n\nSome networks impose smaller penalties when a validator remains offline or fails to participate.\n\nEven without formal slashing, poor uptime may produce:\n\nMissed rewards\n\nLower effective yield\n\nTemporary suspension\n\nReduced validator ranking\n\nA validator offering low commission may still produce poor net returns if its performance is unreliable.\n\nCommission should be evaluated alongside operational quality.\n\n### Validator Selection\n\nA validator review may consider:\n\nHistorical uptime\n\nSlashing record\n\nCommission rate\n\nCommission-change rules\n\nTechnical experience\n\nTransparency\n\nGovernance participation\n\nDelegation concentration\n\nInfrastructure diversity\n\nCommunity reputation\n\nChoosing the largest validator may appear safe but can increase network centralisation.\n\nChoosing an unknown validator solely for a high reward or low fee may increase operational risk.\n\n### Validator Concentration\n\nIf a small number of validators control a large percentage of stake, they may gain substantial influence over:\n\nConsensus\n\nTransaction ordering\n\nGovernance\n\nNetwork upgrades\n\nCensorship\n\nFinality\n\nLarge custodial providers can contribute to this concentration.\n\nDelegators should consider both:\n\nTheir individual return\n\nThe effect of delegation on network resilience\n\nA high-yield decision can create broader systemic risk when everyone chooses the same operator.\n\n### Stake Centralisation\n\nStake can become concentrated through:\n\nLarge early allocations\n\nExchange staking services\n\nLiquid-staking protocols\n\nInstitutional custodians\n\nCompounding advantages\n\nGovernance delegation\n\nMinimum validator requirements\n\nCentralised stake may weaken the decentralisation the network intends to provide.\n\nA protocol can use proof of stake while still relying on a relatively small group of influential operators.\n\n### Self-Staking\n\nSelf-staking may involve running the user’s own validator.\n\nPotential advantages include:\n\nDirect control\n\nNo third-party commission\n\nGreater network contribution\n\nIndependent validator selection\n\nPotential disadvantages include:\n\nHardware and infrastructure costs\n\nTechnical complexity\n\nKey-management risk\n\nDowntime\n\nSlashing\n\nUpgrade responsibility\n\nMinimum stake requirements\n\nSelf-staking is appropriate only when the operator can maintain the necessary technical and security standards.\n\n### Validator Keys\n\nValidator systems may use different keys for:\n\nStaking ownership\n\nBlock signing\n\nWithdrawals\n\nGovernance\n\nSeparation can reduce the damage caused by one compromised key.\n\nFor example, a signing key may allow validator operation but not withdrawal of the underlying stake.\n\nUsers should understand:\n\nWhich keys exist\n\nWhere they are stored\n\nWhich key controls withdrawals\n\nHow backups and recovery work\n\nWhether remote signing or hardware security is supported\n\nA validator key should never be confused with an ordinary low-value application credential.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,4,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-27-lesson-05','cognizen-crypto-mastery-foundations-production','Staking Through an Exchange and Token Locking Programmes','cmf-module-2-27','text','### Staking Through an Exchange\n\nA centralised exchange may offer one-click staking.\n\nThe user may see rewards credited to an account balance.\n\nThe exchange may:\n\nStake assets directly\n\nUse an external validator\n\nPool customer funds\n\nRetain part of the reward\n\nOffer internal liquidity\n\nIssue a claim token\n\nThe user should investigate:\n\nWhether the asset is actually staked\n\nWhich commission is deducted\n\nWhether withdrawals are delayed\n\nWhether the exchange can freeze the account\n\nWhether assets are used for other purposes\n\nWhat happens if the exchange becomes insolvent\n\nConvenience adds counterparty dependence.\n\n### Staking-as-a-Service Providers\n\nA staking provider may operate validators while users retain withdrawal control.\n\nPossible models include:\n\nNon-custodial validator operation\n\nShared validator infrastructure\n\nInstitutional staking\n\nWhite-labelled services\n\nCloud-based validator hosting\n\nThe provider may still control:\n\nSigning infrastructure\n\nValidator performance\n\nSoftware updates\n\nFee collection\n\nReview legal terms, key architecture and slashing responsibility.\n\n“Non-custodial” should be verified technically rather than accepted as a marketing claim.\n\n### Cloud and Infrastructure Risk\n\nValidators may depend on:\n\nCloud hosting providers\n\nData centres\n\nInternet service providers\n\nClient software\n\nMonitoring systems\n\nIf many validators use the same infrastructure, one outage can affect a large portion of the network.\n\nGeographic and software diversity can improve resilience.\n\nA validator’s apparent independence may be limited when its infrastructure depends on the same providers as many others.\n\n### Client Diversity\n\nBlockchain validators may use different software clients implementing the same protocol.\n\nIf one client contains a critical bug and dominates the network, the problem can affect consensus broadly.\n\nClient diversity reduces dependence on one software implementation.\n\nValidator evaluation may therefore include:\n\nWhich client is used\n\nWhether the validator supports minority clients\n\nHow upgrades are tested\n\nWhether redundant infrastructure exists\n\nNetwork security depends on more than the amount staked.\n\n### Staking and Governance\n\nStaked tokens may provide governance rights.\n\nDepending on the protocol, voting power may belong to:\n\nValidators\n\nDelegators\n\nLiquid-staking protocols\n\nCustodial exchanges\n\nGovernance delegates\n\nUsers should determine whether staking:\n\nTransfers voting rights\n\nDelegates votes automatically\n\nAllows independent voting\n\nConcentrates power in the provider\n\nLocks governance participation\n\nA staking decision can influence both financial return and protocol control.\n\n### Staking and Taxation\n\nStaking rewards may create tax obligations depending on the jurisdiction.\n\nRelevant events may include:\n\nReceipt of rewards\n\nClaiming rewards\n\nConversion to another token\n\nSale\n\nDelegation\n\nLiquid-staking-token issuance\n\nRedemption\n\nRecord:\n\nDate received\n\nToken quantity\n\nMarket value\n\nWallet or provider\n\nFees\n\nLater disposal\n\nCost basis\n\nTax rules differ and can change.\n\nProfessional guidance may be required.\n\n### Staking Record-Keeping\n\nA staking record may include:\n\nAsset\n\nNetwork\n\nValidator or provider\n\nWallet address\n\nAmount staked\n\nStart date\n\nLock-up or unbonding period\n\nGross reward rate\n\nCommission\n\nRewards received\n\nNetwork fees\n\nSlashing events\n\nWithdrawal date\n\nMarket values\n\nTax information\n\nDo not store:\n\nSeed phrases\n\nPrivate keys\n\nAuthentication codes\n\nClear records help distinguish actual return from token-balance growth.\n\n### Yield Generation Beyond Native Staking\n\nMany cryptocurrency platforms use the term “staking” for activities unrelated to proof-of-stake consensus.\n\nA product labelled staking may actually involve:\n\nLending\n\nLiquidity provision\n\nToken locking\n\nProtocol incentives\n\nLeveraged trading\n\nRehypothecation\n\nRevenue sharing\n\nThe user should identify the economic activity rather than relying on the product name.\n\nAsk:\n\nWhat happens to the asset after I deposit it?\n\n### Lending Yield\n\nA lending platform may pay yield because borrowers pay interest.\n\nThis may occur through:\n\nA centralised company\n\nA DeFi lending protocol\n\nAn institutional credit arrangement\n\nMargin lending\n\nMarket-maker financing\n\nThe return compensates the lender for risks including:\n\nBorrower default\n\nCollateral failure\n\nPlatform insolvency\n\nSmart contract exploits\n\nLiquidity mismatch\n\nRegulatory intervention\n\nLending is covered in greater detail in Module 2.28.\n\n### Liquidity-Provider Yield\n\nA liquidity provider earns:\n\nTrading fees\n\nPossibly incentive tokens\n\nThe provider also accepts:\n\nImpermanent loss\n\nPool imbalance\n\nAsset risk\n\nSmart contract risk\n\nLiquidity risk\n\nThis is market-making income, not native staking.\n\nCalling LP rewards “staking yield” can hide the actual economic exposure.\n\n### Protocol Revenue Sharing\n\nA protocol may distribute part of its fees or revenue to users who lock or stake a governance token.\n\nThe economic return may come from:\n\nTrading fees\n\nBorrowing fees\n\nApplication usage\n\nService revenue\n\nReview whether:\n\nRevenue is genuine\n\nToken holders have a clear claim\n\nRewards are paid in valuable assets\n\nDistribution is sustainable\n\nGovernance can change the model\n\nLegal restrictions apply\n\nRevenue sharing can create stronger value capture than inflationary rewards, but it remains risky.\n\n### Token Locking Programmes\n\nA project may reward holders for locking tokens even when the tokens do not secure a blockchain.\n\nThe programme may aim to:\n\nReduce circulating supply\n\nEncourage long-term holding\n\nDistribute governance power\n\nCreate loyalty\n\nDelay selling\n\nRewards may be funded through:\n\nTreasury reserves\n\nToken issuance\n\nProtocol fees\n\nMarketing allocations\n\nThis is not consensus staking unless the locked tokens directly support network security.\n\nThe distinction matters because the risks and source of return differ.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,5,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-27-lesson-06','cognizen-crypto-mastery-foundations-production','Centralised Earn Products and Yield Spread','cmf-module-2-27','text','### Centralised Earn Products\n\nA centralised platform may offer yield on deposited cryptocurrency.\n\nThe platform may use customer assets for:\n\nLending\n\nMarket making\n\nTrading\n\nCollateral\n\nInstitutional financing\n\nInvestments\n\nRehypothecation\n\nThe user may not know the exact activities.\n\nRisks include:\n\nInsolvency\n\nUnsecured lending\n\nFraud\n\nAsset-liability mismatch\n\nWithdrawal suspension\n\nLegal restructuring\n\nLack of transparent reserves\n\nA fixed advertised rate does not make the underlying strategy low risk.\n\n### Rehypothecation\n\nRehypothecation occurs when an intermediary uses deposited or pledged assets for additional financial activities.\n\nFor example:\n\nA customer deposits cryptocurrency\n\nThe platform lends it to a borrower\n\nThe borrower pledges or uses it elsewhere\n\nSeveral claims develop around the same asset\n\nThis can increase capital efficiency.\n\nIt also creates interconnected counterparty risk.\n\nIf one participant fails, losses may spread through several layers.\n\nUsers should determine whether a platform has the right to lend, pledge or reuse their assets.\n\n### Yield Vaults\n\nA yield vault automatically allocates deposited assets according to a strategy.\n\nThe strategy may involve:\n\nLending\n\nLiquidity provision\n\nReward harvesting\n\nLeverage\n\nHedging\n\nCross-protocol movement\n\nAutomatic compounding\n\nThe vault simplifies user interaction.\n\nIt also adds another layer of:\n\nSmart contract risk\n\nStrategy risk\n\nManager risk\n\nFee risk\n\nDependency risk\n\nA simple interface can conceal a complex economic position.\n\n### Yield Aggregators\n\nA yield aggregator searches for or allocates capital among several yield sources.\n\nIt may move assets according to:\n\nInterest rates\n\nIncentives\n\nLiquidity\n\nRisk parameters\n\nGovernance decisions\n\nPotential benefits include:\n\nAutomated allocation\n\nCompounding\n\nReduced manual transactions\n\nAccess to several protocols\n\nPotential risks include:\n\nMultiple smart contracts\n\nStrategy errors\n\nProtocol migration\n\nHigh transaction costs\n\nUnclear risk models\n\nExposure to the weakest integrated protocol\n\nHigher optimisation often creates greater complexity.\n\n### Restaking\n\nRestaking allows already-staked assets or liquid-staking positions to provide economic security to additional services.\n\nA simplified model may be:\n\nAn asset secures its original blockchain\n\nThe staked position is committed to another protocol\n\nThe participant earns additional rewards\n\nAdditional penalties may apply for failure under the second system\n\nRestaking aims to reuse existing economic security.\n\nIt also creates layered obligations and correlated risk.\n\n### Restaking Rewards\n\nRestaking rewards may come from:\n\nAdditional protocol issuance\n\nFees paid by secured services\n\nIncentive programmes\n\nAirdrop expectations\n\nPoints systems\n\nService revenue\n\nEarly advertised returns may rely heavily on:\n\nSubsidies\n\nSpeculative token expectations\n\nTemporary rewards\n\nUncertain future demand\n\nThe economic sustainability depends on whether additional services genuinely pay for security.\n\n### Restaking Risk\n\nRestaking may expose the participant to:\n\nOriginal blockchain slashing\n\nAdditional protocol slashing\n\nSmart contract risk\n\nLiquid-staking-token risk\n\nOperator risk\n\nService failure\n\nWithdrawal delays\n\nCorrelated penalties\n\nGovernance changes\n\nThe same collateral supports several systems.\n\nA failure in one layer may affect the complete position.\n\nRestaking increases capital efficiency by increasing the responsibilities carried by the same capital.\n\n### Shared Security and Systemic Risk\n\nWhen many services rely on the same restaked assets, they become interconnected.\n\nPossible concerns include:\n\nOne operator serving many systems\n\nCommon software vulnerabilities\n\nCorrelated slashing\n\nConcentrated governance\n\nCascading liquidations\n\nComplex withdrawal queues\n\nA system may appear diversified because it supports many services while remaining dependent on one underlying pool of collateral.\n\n### Points and Future-Reward Programmes\n\nSome protocols reward participation through points rather than immediately transferable tokens.\n\nPoints may be expected to influence:\n\nFuture token distributions\n\nAirdrops\n\nGovernance allocation\n\nStatus\n\nReward multipliers\n\nHowever, points may have:\n\nNo legal claim\n\nNo guaranteed conversion\n\nNo fixed value\n\nChangeable rules\n\nEligibility restrictions\n\nUsers should not treat speculative future rewards as certain yield.\n\nThe capital remains exposed even when the reward has not been defined.\n\n### Leveraged Yield Strategies\n\nA leveraged yield strategy may involve:\n\nDepositing collateral\n\nBorrowing an asset\n\nStaking or lending the borrowed asset\n\nRepeating the process\n\nEarning a spread between reward and borrowing cost\n\nThis can increase returns when conditions remain favourable.\n\nIt also introduces:\n\nLiquidation risk\n\nVariable borrowing rates\n\nSmart contract risk\n\nPrice divergence\n\nComplex unwinding\n\nNegative yield when costs rise\n\nA small change in rates or collateral value can transform a profitable strategy into a loss.\n\n### Looping\n\nLooping is a leveraged strategy in which an asset is repeatedly deposited and borrowed.\n\nFor example:\n\nDeposit a liquid-staking token\n\nBorrow the underlying asset\n\nStake it again\n\nReceive more liquid-staking tokens\n\nDeposit again\n\nThis increases effective staking exposure.\n\nIt also increases:\n\nLeverage\n\nLiquidation sensitivity\n\nProtocol dependency\n\nDepeg risk\n\nBorrowing costs\n\nA yield displayed before financing costs and liquidation risk is incomplete.\n\n### Yield Spread\n\nA leveraged yield strategy may depend on the difference between:\n\nStaking or lending return\n\nBorrowing cost\n\nSuppose:\n\nStaking yield: 6 percent\n\nBorrowing cost: 3 percent\n\nThe gross spread is approximately three percent before:\n\nFees\n\nSlippage\n\nCompounding costs\n\nLiquidation risk\n\nRate changes\n\nTax\n\nIf borrowing costs rise to eight percent, the spread becomes negative.\n\nVariable rates should be stress-tested.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,6,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-27-lesson-07','cognizen-crypto-mastery-foundations-production','Yield and Token Price Risk and Yield and Market Efficiency','cmf-module-2-27','text','### Yield and Token Price Risk\n\nMost cryptocurrency yields are earned on volatile assets.\n\nA high yield can be overwhelmed by price movement.\n\nConsider:\n\nYield: 15 percent\n\nToken-price decline: 60 percent\n\nThe net market result remains strongly negative.\n\nYield analysis should always begin with the question:\n\nWould I be willing to hold this asset even without the reward?\n\nA weak asset does not become a strong investment because it offers more tokens.\n\n### Yield and Duration Risk\n\nA locked yield position commits capital for time.\n\nDuring the period:\n\nMarket conditions may change\n\nThe token may decline\n\nBetter opportunities may emerge\n\nThe user may need liquidity\n\nThe protocol may change rules\n\nRegulation may affect access\n\nA longer lock-up should generally require greater compensation.\n\nThe additional reward must be compared with the uncertainty created by reduced flexibility.\n\n### Yield and Liquidity Risk\n\nA token may show a high reward rate but have limited liquidity.\n\nThe user may be able to earn large quantities but unable to sell them efficiently.\n\nEvaluate:\n\nTrading volume\n\nPool depth\n\nBid-ask spread\n\nWithdrawal access\n\nToken unlocks\n\nMarket-maker dependence\n\nA reward has limited economic value when the market cannot absorb its sale.\n\n### Yield and Smart Contract Risk\n\nDeFi yield often requires assets to be deposited into smart contracts.\n\nPotential losses may arise from:\n\nCoding errors\n\nAccess-control failures\n\nOracle manipulation\n\nEconomic exploits\n\nUpgrade attacks\n\nGovernance capture\n\nUnsafe integrations\n\nA one-percent increase in yield may not justify exposing capital to an additional unaudited protocol.\n\nReturn should be assessed relative to the new risks introduced.\n\n### Yield and Stablecoin Risk\n\nStablecoin yield can appear less volatile than yield earned on other crypto assets.\n\nHowever, the user remains exposed to:\n\nDepegging\n\nReserve failure\n\nIssuer insolvency\n\nFreezing\n\nSmart contract risk\n\nLending defaults\n\nRegulation\n\nBridge failure\n\nStable value during normal conditions does not guarantee capital preservation during a crisis.\n\n### Yield Sustainability\n\nA yield may be more sustainable when it is funded through recurring economic activity.\n\nExamples include:\n\nTransaction fees\n\nBorrower interest\n\nApplication revenue\n\nService payments\n\nA yield may be less sustainable when it depends mainly on:\n\nRapid token issuance\n\nNew participant deposits\n\nTemporary incentives\n\nTreasury subsidies\n\nSpeculative demand\n\nThis does not mean issuance-funded rewards are always illegitimate.\n\nProof-of-stake networks may use inflation intentionally to pay for security.\n\nThe question is whether the economic purpose and long-term supply effects are understood.\n\n### Subsidised Yield\n\nA project may subsidise rewards during its early growth stage.\n\nThe objective may be to:\n\nAttract validators\n\nBuild liquidity\n\nEncourage adoption\n\nDistribute tokens\n\nSecure the network\n\nSubsidies can help launch an ecosystem.\n\nThey are not automatically sustainable.\n\nReview:\n\nWhen subsidies decline\n\nWhether genuine fees are growing\n\nWhether users remain after incentives fall\n\nHow much supply will be issued\n\nWho receives the rewards\n\nA protocol dependent permanently on subsidies may struggle when token demand weakens.\n\n### Unsustainably High Yield\n\nPotential warning signs include:\n\nReturns far above comparable markets\n\nNo clear source of revenue\n\nRewards paid entirely in a rapidly issued token\n\nDependence on constant new deposits\n\nVague strategy descriptions\n\nHidden leverage\n\nRestricted withdrawals\n\nUnaudited contracts\n\nConcentrated administrator control\n\nAggressive referral incentives\n\nAn unusually high yield may be compensation for unusually high risk.\n\nIt may also be economically impossible to sustain.\n\n### Ponzi-Like Yield Structures\n\nA yield structure becomes especially concerning when existing participants are paid primarily from funds contributed by new participants without sufficient independent economic activity.\n\nWarning signs may include:\n\nGuaranteed high returns\n\nLimited explanation of revenue\n\nRewards dependent on recruitment\n\nRestrictions discouraging withdrawal\n\nAnonymous operators\n\nFabricated dashboards\n\nNo verifiable on-chain strategy\n\nConstant pressure to reinvest\n\nBlockchain technology does not prevent fraudulent financial structures.\n\nA smart contract can automate an unsustainable model.\n\n### Treasury-Funded Rewards\n\nA protocol may pay rewards from a treasury.\n\nThis can be legitimate for a limited incentive programme.\n\nHowever, treasury-funded yield consumes reserves.\n\nAsk:\n\nHow large is the treasury?\n\nWhich assets does it hold?\n\nHow long can rewards continue?\n\nWho controls spending?\n\nWhat happens when subsidies end?\n\nIs the treasury dominated by the protocol’s own illiquid token?\n\nA large theoretical treasury value may not translate into spendable resources.\n\n### Yield Compression\n\nAs more capital enters an opportunity, returns may decline.\n\nFor example:\n\nMore tokens are staked\n\nMore lenders supply assets\n\nMore liquidity providers share fees\n\nArbitrage removes excess return\n\nGovernance reduces incentives\n\nHigh yields often attract capital that causes those yields to fall.\n\nA current reward rate should not be assumed to remain available.\n\n### Yield and Market Efficiency\n\nA persistent high yield may indicate:\n\nGenuine high demand for capital\n\nHigh operational requirements\n\nHigh risk\n\nTemporary market imbalance\n\nInefficiency\n\nUnsustainable incentives\n\nCompetition tends to reduce easy returns.\n\nA yield far above the market average deserves additional investigation rather than immediate enthusiasm.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,7,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-27-lesson-08','cognizen-crypto-mastery-foundations-production','Opportunity Cost and Staking Return Calculation','cmf-module-2-27','text','### Opportunity Cost\n\nStaking or locking an asset means it cannot be used elsewhere without additional mechanisms.\n\nThe opportunity cost may include:\n\nInability to sell quickly\n\nMissing another investment\n\nReduced collateral flexibility\n\nLost governance access\n\nUnavailable network fees\n\nWithdrawal delay\n\nLiquid staking attempts to reduce this cost but introduces additional token and protocol risk.\n\nThere is no yield without an alternative use of capital being given up.\n\n### Staking and Portfolio Allocation\n\nA staking position should be considered part of the underlying asset allocation.\n\nSuppose an investor holds:\n\nNative token\n\nStaked token\n\nLiquid-staking token\n\nRestaked version\n\nA lending position collateralised by the LST\n\nThese may appear as separate assets.\n\nThey all depend heavily on the same underlying token and network.\n\nThe portfolio may be far more concentrated than it appears.\n\nAggregate the economic exposure.\n\n### Staking and Custody Diversification\n\nStaking can concentrate custody through:\n\nOne exchange\n\nOne liquid-staking protocol\n\nOne validator\n\nOne wallet\n\nOne smart contract\n\nDiversification may involve:\n\nSeveral validators\n\nDifferent staking methods\n\nSeparate wallets\n\nLimiting custodial exposure\n\nExcessive fragmentation can also create complexity.\n\nThe structure should reduce single points of failure while remaining manageable.\n\n### Slashing Insurance\n\nSome staking services provide insurance-like protection against validator penalties.\n\nCoverage may be funded through:\n\nProvider reserves\n\nInsurance pools\n\nProtocol treasuries\n\nExternal underwriters\n\nReview:\n\nWhich slashing events are covered\n\nWhether downtime is included\n\nMaximum compensation\n\nExclusions\n\nClaim procedures\n\nProvider solvency\n\nLegal enforceability\n\nInsurance claims should not be assumed to be automatic or guaranteed.\n\n### Staking Reserve Funds\n\nA staking protocol may maintain reserves to cover:\n\nSlashing\n\nTemporary withdrawal demand\n\nValidator losses\n\nOperational failures\n\nA reserve can improve resilience.\n\nIts adequacy depends on:\n\nReserve size\n\nAsset quality\n\nAccess rules\n\nGovernance control\n\nCorrelated failure scenarios\n\nA reserve funded mainly with the protocol’s own token may weaken during the same event that creates losses.\n\n### Staking and Network Security\n\nStaking rewards are intended partly to attract enough capital and validator participation to secure the network.\n\nSecurity may depend on:\n\nTotal economic stake\n\nStake distribution\n\nValidator diversity\n\nSlashing strength\n\nToken liquidity\n\nGovernance\n\nSocial recovery processes\n\nA high token value can increase the economic cost of attacking the network.\n\nHowever, concentrated stake or weak slashing rules may reduce security despite a high total value staked.\n\n### Economic Security\n\nEconomic security refers to the value placed at risk by participants who must follow the protocol’s rules.\n\nA network may claim strong economic security because a large value is staked.\n\nExamine:\n\nWhether the stake is genuinely slashable\n\nHow concentrated it is\n\nWhether borrowed stake can influence the network\n\nWhether the token is sufficiently liquid\n\nWhether governance can override penalties\n\nWhether a social fork could change outcomes\n\nThe headline amount staked is only one part of network security.\n\n### Security Budget\n\nThe security budget is the economic compensation paid to validators or miners for protecting the network.\n\nIn proof-of-stake systems, it may come from:\n\nToken issuance\n\nTransaction fees\n\nOther protocol revenue\n\nA network must balance:\n\nSufficient rewards for security\n\nAcceptable token inflation\n\nAffordable user fees\n\nLong-term sustainability\n\nVery low rewards may weaken validator participation.\n\nVery high issuance may dilute holders and pressure token value.\n\n### Fee-Based Security\n\nSome networks aim to fund staking rewards increasingly through transaction fees rather than inflation.\n\nThis may reduce dilution.\n\nHowever, it requires sufficient economic activity.\n\nQuestions include:\n\nAre users generating enough fees?\n\nAre fees stable or highly cyclical?\n\nWould lower activity weaken security?\n\nAre validators dependent on MEV?\n\nCan users afford the fees?\n\nA low-inflation network still requires a credible long-term security budget.\n\n### Staking Yield and Valuation\n\nStaking yield should not be analysed separately from token valuation.\n\nA token may offer a high reward because:\n\nSupply inflation is high\n\nStaking participation is low\n\nNetwork risk is high\n\nDemand is weak\n\nThe protocol is subsidising adoption\n\nA lower-yield token may have:\n\nStronger fee revenue\n\nLower inflation\n\nGreater liquidity\n\nMore established security\n\nThe percentage alone does not reveal whether the token is attractively valued.\n\n### Comparing Staking Opportunities\n\nA comparison should include more than headline APY.\n\nPotential fields include:\n\nNetwork\n\nUnderlying asset\n\nReward source\n\nSupply inflation\n\nStaking participation\n\nValidator commission\n\nLock-up\n\nUnbonding period\n\nSlashing rules\n\nCustody model\n\nSmart contract exposure\n\nLiquid-staking-token liquidity\n\nHistorical reward variability\n\nGovernance implications\n\nTax complexity\n\nTwo identical reward percentages can represent very different risk-adjusted opportunities.\n\n### Staking Return Calculation\n\nA simplified calculation might begin with:\n\nGross rewards = Staked tokens × Gross reward rate\n\nThen subtract:\n\nValidator commission\n\nProtocol fees\n\nNetwork fees\n\nSlashing losses\n\nOther service charges\n\nThis produces net token rewards.\n\nTo calculate the market return, include:\n\nStarting token price\n\nEnding token price\n\nRewards earned\n\nTaxes\n\nWithdrawal costs\n\nTo estimate relative return, compare the result with:\n\nHolding the unstaked asset\n\nA different validator\n\nA liquid-staking alternative\n\nAnother investment benchmark','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,8,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-27-lesson-09','cognizen-crypto-mastery-foundations-production','Example of Validator Commission and Inflation and Staking Monitoring','cmf-module-2-27','text','### Example of Validator Commission and Inflation\n\nSuppose:\n\nStaked amount: 10,000 tokens\n\nGross reward rate: 9 percent\n\nValidator commission: 8 percent of rewards\n\nSupply inflation: 6 percent\n\nGross rewards:\n\n10,000 × 9 percent = 900 tokens\n\nValidator commission:\n\n900 × 8 percent = 72 tokens\n\nNet rewards:\n\n900 − 72 = 828 tokens\n\nNet nominal token return:\n\n828 ÷ 10,000 × 100 = 8.28 percent\n\nA simple approximation after supply inflation:\n\n8.28 percent − 6 percent = approximately 2.28 percent\n\nThis excludes:\n\nCompounding\n\nToken-price changes\n\nFees\n\nTaxes\n\nSlashing\n\n### Example of Liquid-Staking Discount\n\nSuppose:\n\nOne LST is theoretically redeemable for 1.05 underlying tokens\n\nThe market values the LST at the equivalent of 0.98 underlying tokens\n\nThe LST trades below its redemption value.\n\nPossible reasons include:\n\nLong redemption queue\n\nProtocol concern\n\nLimited market liquidity\n\nImmediate selling pressure\n\nA buyer may see an arbitrage opportunity.\n\nThey also accept the risk that redemption may fail, be delayed or become less valuable.\n\nA discount is not automatically free profit.\n\n### Example of Layered Yield\n\nSuppose a user:\n\nStakes the native asset\n\nReceives an LST\n\nDeposits the LST into a lending protocol\n\nBorrows a stablecoin\n\nSupplies the stablecoin to a liquidity pool\n\nRestakes the position for additional incentives\n\nThe advertised combined yield may be attractive.\n\nThe position contains exposure to:\n\nNative asset price\n\nValidator performance\n\nLiquid-staking protocol\n\nLST market value\n\nLending contract\n\nLiquidation\n\nStablecoin\n\nLiquidity pool\n\nImpermanent loss\n\nRestaking protocol\n\nMultiple governance systems\n\nYield stacking also stacks risk.\n\n### Evaluating a Native Staking Opportunity\n\nA native staking review may include:\n\n### Network Purpose\n\nWhat does the blockchain do?\n\nIs genuine usage developing?\n\n### Consensus Design\n\nHow are validators selected?\n\nWhich behaviour can be slashed?\n\n### Reward Source\n\nIssuance, fees or both?\n\nHow may rewards change?\n\n### Supply Economics\n\nWhat is the inflation rate?\n\nHow does staking affect dilution?\n\n### Participation\n\nWhat percentage is staked?\n\nIs stake concentrated?\n\n### Validator Quality\n\nWhat are uptime, commission and penalty records?\n\n### Liquidity\n\nWhat lock-up or unbonding period applies?\n\n### Custody\n\nWho controls withdrawal keys?\n\n### Governance\n\nDoes delegation transfer voting power?\n\n### Evaluating a Liquid-Staking Protocol\n\nAdditional questions include:\n\nWho operates validators?\n\nIs the stake distributed across operators?\n\nWhich smart contracts hold deposits?\n\nCan contracts be upgraded?\n\nWho controls emergency powers?\n\nHow does the LST reflect rewards?\n\nHow can it be redeemed?\n\nIs a withdrawal queue present?\n\nHow deep is secondary-market liquidity?\n\nHas the LST previously traded at a discount?\n\nWhat protocol fee is deducted?\n\nAre reserves or insurance mechanisms available?\n\nCan the token be frozen or paused?\n\nThe LST should be evaluated as a separate protocol asset.\n\n### Evaluating a Yield Product\n\nFor any yield-generating product, ask:\n\n### Source\n\nWhere does the return come from?\n\n### Asset Movement\n\nWhat happens to the deposited asset?\n\n### Counterparties\n\nWho borrows, holds, invests or manages it?\n\n### Contracts\n\nWhich smart contracts are involved?\n\n### Leverage\n\nIs borrowing or rehypothecation used?\n\n### Liquidity\n\nCan funds be withdrawn immediately?\n\n### Loss Allocation\n\nWho bears losses when the strategy fails?\n\n### Transparency\n\nCan the activity be verified?\n\n### Sustainability\n\nWhat happens when incentives decline?\n\n### Legal Position\n\nWhat claim does the user hold if the provider becomes insolvent?\n\n### Safer Staking Practices\n\nRisk can be reduced, though not eliminated, by:\n\nUnderstanding the specific staking model\n\nUsing official or verified interfaces\n\nProtecting wallet and withdrawal keys\n\nSelecting validators carefully\n\nDiversifying validator exposure where appropriate\n\nReviewing commissions and commission-change limits\n\nMaintaining sufficient liquid assets\n\nUnderstanding lock-up and unbonding periods\n\nMonitoring network upgrades\n\nAvoiding excessive concentration\n\nKeeping accurate reward records\n\nTesting withdrawal processes\n\nTreating liquid-staking tokens as separate risk-bearing assets\n\nAvoiding layered leverage unless fully understood\n\n### Testing the Staking Process\n\nBefore staking a significant amount, a user may:\n\nVerify the official network or provider\n\nConfirm the wallet and network\n\nStake a small amount\n\nConfirm validator selection\n\nObserve reward accrual\n\nTest reward claiming if required\n\nInitiate a small unstaking request\n\nConfirm the unbonding and withdrawal process\n\nA successful test does not guarantee future safety.\n\nIt can identify operational misunderstandings before greater capital is committed.\n\n### Maintaining a Liquidity Reserve\n\nStaking all available tokens may create problems.\n\nA participant may need liquid assets for:\n\nNetwork fees\n\nEmergency transactions\n\nTaxes\n\nPersonal obligations\n\nPortfolio rebalancing\n\nMargin or collateral management\n\nA reserve can reduce the need to sell an LST at a discount or wait through an unbonding period.\n\nLiquidity planning should occur before staking.\n\n### Staking Position Sizing\n\nA staking position remains exposed to the underlying token’s full market risk.\n\nAdditional potential losses may arise through:\n\nSlashing\n\nProvider insolvency\n\nSmart contract exploits\n\nLST depegging\n\nLocked withdrawals\n\nPosition size should reflect the possibility of severe or total loss.\n\nStaking rewards should not be used to justify an allocation larger than the investor would otherwise hold.\n\n### Staking Monitoring\n\nA staking position may require monitoring of:\n\nValidator performance\n\nCommission changes\n\nNetwork upgrades\n\nSlashing events\n\nReward-rate changes\n\nInflation\n\nParticipation rate\n\nGovernance proposals\n\nUnbonding queues\n\nLST liquidity\n\nSecurity incidents\n\nProvider financial health\n\n“Passive” yield can require active oversight.\n\nThe monitoring burden increases as more protocols and yield layers are added.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,9,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-27-lesson-10','cognizen-crypto-mastery-foundations-production','Exit Planning and Common Misunderstandings','cmf-module-2-27','text','### Exit Planning\n\nBefore staking, decide what may justify exit.\n\nPossible triggers include:\n\nValidator performance deterioration\n\nCommission increase\n\nSecurity concern\n\nGovernance capture\n\nLST discount\n\nSmart contract exploit\n\nProtocol upgrade risk\n\nToken-thesis failure\n\nPersonal liquidity need\n\nUnsustainable inflation\n\nBetter risk-adjusted alternatives\n\nThe user should also know:\n\nHow long unbonding takes\n\nWhether rewards continue\n\nWhich fees apply\n\nWhether funds can be sold through another route\n\n### Staking and Yield Checklist\n\nBefore committing assets, ask:\n\nIs this native staking, lending, liquidity provision or another product?\n\nWhat exactly happens to my tokens?\n\nWho controls the assets or withdrawal keys?\n\nWhere does the yield come from?\n\nIs the reward funded by issuance, fees, borrowers or subsidies?\n\nWhat is the token’s inflation rate?\n\nWhat is the approximate return after inflation?\n\nWhat commission and protocol fees apply?\n\nIs the advertised figure APR or APY?\n\nDoes the APY assume frequent compounding?\n\nWhat network fees will compounding require?\n\nWhat percentage of the supply is staked?\n\nIs stake concentrated among a few validators or providers?\n\nCan delegated tokens be slashed?\n\nWhat validator behaviour causes penalties?\n\nWhat is the validator’s uptime and slashing history?\n\nCan commission change without warning?\n\nIs there a lock-up or unbonding period?\n\nDo rewards continue during unbonding?\n\nWhat happens if the token price falls sharply?\n\nWould I hold the asset without the staking reward?\n\nIs a liquid-staking token issued?\n\nHow does the LST accrue rewards?\n\nHow is the LST redeemed?\n\nCan it trade below redemption value?\n\nHow deep is its market liquidity?\n\nAre smart contracts upgradeable or pausable?\n\nWho controls administrator powers?\n\nIs restaking or leverage involved?\n\nHow many protocols and counterparties are in the strategy?\n\nCan funds be withdrawn during market stress?\n\nAre withdrawal queues possible?\n\nWhat tax obligations may arise?\n\nIs the position size acceptable if the full amount is lost?\n\nWhat specific event would cause me to exit?\n\n### Common Staking and Yield Mistakes\n\n\n\n### Selecting the Highest Advertised Yield\n\nThe source, inflation and risk are ignored.\n\n### Treating Token Rewards as Guaranteed Profit\n\nThe token price may decline more than the reward earned.\n\n### Ignoring Supply Inflation\n\nNominal yield is mistaken for real ownership growth.\n\n### Confusing Native Staking With Lending\n\nA platform product is assumed to support blockchain consensus when assets are actually lent or reused.\n\n### Staking Through One Centralised Provider\n\nCounterparty and network concentration increase.\n\n### Choosing a Validator Only by Commission\n\nUptime, security and slashing history are ignored.\n\n### Staking Every Available Token\n\nNo liquid balance remains for fees, taxes or emergencies.\n\n### Ignoring Unbonding\n\nThe user expects immediate access during a market decline.\n\n### Treating an LST as Identical to the Underlying Asset\n\nRedemption, liquidity and smart contract risks are overlooked.\n\n### Layering Yield Without Mapping Dependencies\n\nEach added protocol introduces another failure point.\n\n### Assuming Auto-Compounding Is Free\n\nVault fees, gas and contract risk are ignored.\n\n### Using Leverage to Increase a Small Yield Spread\n\nLiquidation and variable borrowing costs dominate the strategy.\n\n### Common Misunderstandings\n\n#### “Staking Is the Same as Earning Bank Interest”\n\nStaking compensates participants for network security, inflation exposure, lock-ups and technical risks.\n\n#### “A Ten-Percent Staking Yield Means My Wealth Grows Ten Percent”\n\nToken-price decline, inflation, fees and taxes may produce a very different result.\n\n#### “Staking Rewards Are Free Tokens”\n\nRewards may be funded through dilution of the total supply.\n\n#### “A Higher Staking Rate Is Better”\n\nIt may signal high inflation, low participation or greater network risk.\n\n#### “Delegation Transfers Ownership to the Validator”\n\nThis depends on the protocol, but non-custodial delegation may preserve withdrawal control while assigning staking power.\n\n#### “Non-Custodial Staking Has No Counterparty Risk”\n\nValidator, interface, protocol and wallet risks remain.\n\n#### “Liquid Staking Removes Lock-Up Risk”\n\nIt replaces some illiquidity with LST market, redemption and smart contract risk.\n\n#### “An LST Must Always Equal the Underlying Asset”\n\nIt can trade at a discount or premium.\n\n#### “Restaking Earns Extra Return Without Extra Capital”\n\nIt places additional obligations and risks on the same collateral.\n\n#### “Stablecoin Yield Is Low Risk”\n\nDepegging, lending, contract and issuer risks remain.\n\n#### “Real Yield Means the Return Is Safe”\n\nRevenue can fall, governance can change and the protocol can still fail.\n\n#### “Auto-Compounding Guarantees a Higher Net Return”\n\nCosts and additional protocol risk may exceed the compounding benefit.\n\n#### “Locked Tokens Cannot Lose Value”\n\nTheir market price can fall while the holder is unable to sell.\n\n#### “Passive Yield Requires No Monitoring”\n\nValidators, protocols, rates and withdrawal conditions can change.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,10,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-27-lesson-11','cognizen-crypto-mastery-foundations-production','Module Summary and Key Takeaway','cmf-module-2-27','text','### Module Summary\n\nStaking commits cryptocurrency to support a proof-of-stake blockchain or related protocol function.\n\nParticipants may:\n\nOperate validators\n\nDelegate to validators\n\nJoin staking pools\n\nUse custodial providers\n\nReceive liquid-staking tokens\n\nRewards may come from:\n\nToken issuance\n\nTransaction fees\n\nPriority fees\n\nMEV\n\nProtocol subsidies\n\nOther network revenue\n\nNominal staking yield should be adjusted for:\n\nSupply inflation\n\nValidator commission\n\nProtocol fees\n\nNetwork costs\n\nToken-price movement\n\nTaxes\n\nSlashing\n\nOpportunity cost\n\nNative staking differs from:\n\nLending\n\nLiquidity provision\n\nToken locking\n\nCentralised earn products\n\nYield vaults\n\nRestaking\n\nLiquid staking improves flexibility by issuing a transferable claim on staked assets.\n\nIt also adds:\n\nSmart contract risk\n\nValidator-operator risk\n\nRedemption risk\n\nWithdrawal queues\n\nSecondary-market liquidity risk\n\nPotential price divergence\n\nRestaking places additional security obligations on already-staked collateral.\n\nIt may increase rewards while adding slashing, protocol and systemic risks.\n\nHigh yield is not inherently attractive.\n\nIt may reflect:\n\nHigh inflation\n\nWeak liquidity\n\nHidden leverage\n\nTemporary incentives\n\nSubstantial technical or counterparty risk\n\nA responsible yield analysis begins by identifying the source of the return and mapping every party, contract and asset involved.\n\nThe reward percentage is the most visible part of the product.\n\nThe underlying risk structure determines whether that reward creates genuine value.\n\n### Key Takeaway\n\nYield is never created by the percentage displayed on a screen.\n\nIt comes from token issuance, user fees, borrowers, market-making activity, protocol revenue or additional risk placed on capital.\n\nBefore staking or depositing an asset, identify the source of every reward, subtract inflation and fees, understand the withdrawal conditions and map every validator, custodian and smart contract involved.\n\nMore tokens are useful only when the assets remain secure, liquid and valuable.','markdown',NULL,NULL,NULL,2,0,0,0,'',NULL,11,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-27-lesson-12','cognizen-crypto-mastery-foundations-production','Check your understanding','cmf-module-2-27','text','### Check your understanding\n\nAnswer these questions to self-assess your understanding before moving on.\n\n1. What is staking?\n\n2. How does proof of stake use committed capital to secure a network?\n\n3. What is a validator?\n\n4. What is a delegator?\n\n5. How does native staking differ from lending?\n\n6. What is custodial staking?\n\n7. What is pooled staking?\n\n8. What is a liquid-staking token?\n\n9. How can an LST reflect accumulated rewards?\n\n10. Why can an LST trade below its theoretical redemption value?\n\n11. What is an unbonding period?\n\n12. What is slashing?\n\n13. How can validator downtime affect returns?\n\n14. What factors should be considered when choosing a validator?\n\n15. Why can validator concentration weaken decentralisation?\n\n16. What are the main sources of staking rewards?\n\n17. How does token issuance create dilution?\n\n18. Why may non-stakers lose relative ownership?\n\n19. How can the staking participation rate affect rewards?\n\n20. How is validator commission applied?\n\n21. How does APR differ from APY?\n\n22. Why can frequent compounding be uneconomic?\n\n23. How does nominal token yield differ from real economic return?\n\n24. How may staking return be compared with supply inflation?\n\n25. What does “real yield” sometimes mean in DeFi?\n\n26. Why can rewards paid in an incentive token lose value?\n\n27. What risks arise from staking through a centralised exchange?\n\n28. What is rehypothecation?\n\n29. What does a yield vault do?\n\n30. What is restaking?\n\n31. Why does restaking add risk even though it uses the same collateral?\n\n32. What is looping?\n\n33. How can a change in borrowing rates make a leveraged yield strategy unprofitable?\n\n34. Why should a participant consider whether they would hold an asset without its yield?\n\n35. What characteristics may indicate an unsustainable yield?\n\n36. How can treasury-funded rewards become problematic?\n\n37. Why do yields often decline as more capital enters?\n\n38. How should staked and liquid-staking assets be treated in portfolio allocation?\n\n39. What should be recorded for a staking position?\n\n40. Why should a user test staking and unstaking with a small amount?\n\n41. What should be monitored after assets are staked?\n\n42. Which events may justify exiting a staking position?','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,12,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `course_sections` (`id`,`course_id`,`title`,`position`,`created_at`) SELECT 'cmf-module-2-28','cognizen-crypto-mastery-foundations-production','Module 2.28: Lending and Borrowing Protocols',28,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
