INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-28-lesson-01','cognizen-crypto-mastery-foundations-production','What Is Cryptocurrency Lending? and Lending Pools','cmf-module-2-28','text','### Learning Objectives\n\nBy the end of this module, you should be able to:\n\nExplain how cryptocurrency lending and borrowing protocols operate\n\nDistinguish between centralised lending and decentralised lending\n\nUnderstand why most DeFi loans are overcollateralised\n\nCalculate loan-to-value and collateral ratios\n\nExplain collateral factors, liquidation thresholds and health factors\n\nUnderstand how lending and borrowing interest rates are determined\n\nDistinguish between supply yield, borrowing cost and protocol incentives\n\nExplain how liquidations protect a lending protocol\n\nIdentify the risks of recursive borrowing and leveraged lending strategies\n\nUnderstand how oracles, liquidity and stablecoins affect lending markets\n\nEvaluate lender, borrower and protocol-level risks\n\nAssess a lending protocol using a structured framework\n\nParticipate more cautiously in cryptocurrency credit markets\n\n### Introduction\n\nLending and borrowing are central functions of the financial system.\n\nTraditional lenders evaluate borrowers using information such as:\n\nIncome\n\nEmployment\n\nCredit history\n\nExisting debt\n\nAssets\n\nLegal identity\n\nAbility to repay\n\nCryptocurrency lending can operate differently.\n\nA blockchain protocol may allow a user to deposit digital assets as collateral and borrow another asset without submitting a conventional credit application.\n\nThe smart contract does not necessarily know:\n\nWho the borrower is\n\nWhere the borrower lives\n\nWhether the borrower is employed\n\nWhat the borrower earns\n\nWhether the borrower intends to repay\n\nInstead, the protocol protects lenders by requiring collateral worth more than the amount borrowed.\n\nIf the collateral falls too far in value, the protocol may sell it automatically.\n\nThis makes permissionless borrowing possible, but it introduces new risks involving:\n\nVolatile collateral\n\nSmart contracts\n\nPrice oracles\n\nLiquidations\n\nStablecoins\n\nMarket liquidity\n\nGovernance\n\nNetwork congestion\n\nLenders may earn interest, but they are not receiving a risk-free return.\n\nBorrowers gain liquidity, but they can lose their collateral during ordinary market volatility.\n\nA complete analysis must examine the economics of the loan, the assets involved and the mechanism used to protect the protocol.\n\n### What Is Cryptocurrency Lending?\n\nCryptocurrency lending allows one party to make digital assets available to another party in return for interest or another form of compensation.\n\nThe main participants may include:\n\nLenders or suppliers\n\nBorrowers\n\nA centralised company\n\nA decentralised protocol\n\nCollateral providers\n\nLiquidators\n\nGovernance participants\n\nPrice-oracle providers\n\nThe lender may supply:\n\nStablecoins\n\nNative blockchain assets\n\nTokenised assets\n\nOther accepted cryptocurrencies\n\nThe borrower may use the borrowed funds for:\n\nTrading\n\nLiquidity\n\nBusiness activity\n\nTax planning\n\nHedging\n\nDeFi strategies\n\nAvoiding the immediate sale of an existing asset\n\nThe economic purpose resembles conventional credit, but the operating structure can be very different.\n\n### Centralised Cryptocurrency Lending\n\nA centralised lending platform is operated by a company.\n\nUsers may deposit assets with the company and receive interest.\n\nThe company may lend those assets to:\n\nInstitutional traders\n\nMarket makers\n\nHedge funds\n\nRetail borrowers\n\nOther platforms\n\nAffiliated businesses\n\nThe company decides:\n\nWho may borrow\n\nWhich collateral is accepted\n\nWhich interest rate applies\n\nHow customer assets are used\n\nWhen withdrawals are processed\n\nUsers depend on the company’s:\n\nSolvency\n\nRisk management\n\nSecurity\n\nAccounting\n\nLegal structure\n\nHonesty\n\nThe platform may describe the product as an earn account, savings product or staking service even when the underlying activity is lending.\n\n### Centralised Lending Risks\n\nPotential risks include:\n\nPlatform insolvency\n\nBorrower default\n\nUnsecured lending\n\nFraud\n\nPoor collateral management\n\nRehypothecation\n\nWithdrawal suspension\n\nRegulatory intervention\n\nCybersecurity breaches\n\nLack of transparent reserves\n\nA user may see only an account balance and interest payment.\n\nThey may not know:\n\nWho borrowed the assets\n\nWhether collateral exists\n\nWhether the collateral is liquid\n\nWhether the company has lent the same assets several times\n\nWhether customer deposits are legally protected\n\nConvenience can hide substantial counterparty risk.\n\n### Decentralised Lending\n\nA decentralised lending protocol uses smart contracts to manage deposits, loans, interest and liquidations.\n\nA simplified process may be:\n\nLenders deposit assets into a smart contract\n\nBorrowers deposit approved collateral\n\nThe protocol calculates a borrowing limit\n\nBorrowers withdraw available assets\n\nInterest accrues automatically\n\nOracles monitor collateral values\n\nBorrowers repay their debt\n\nThe collateral becomes withdrawable\n\nUndercollateralised positions may be liquidated\n\nThe rules are generally visible in the protocol code and documentation.\n\nUsers interact through blockchain wallets.\n\nNo traditional loan officer may be involved.\n\n### Lending Pools\n\nMany DeFi protocols use pooled lending.\n\nLenders deposit assets into shared liquidity pools.\n\nBorrowers draw from those pools.\n\nFor example, a stablecoin market may contain:\n\nTen million units supplied\n\nSix million units borrowed\n\nFour million units available for withdrawal or new loans\n\nInterest paid by borrowers is distributed among suppliers after protocol fees and other deductions.\n\nThe individual lender is not necessarily matched with one specific borrower.\n\nThey hold a proportional claim on the shared pool.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,1,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-28-lesson-02','cognizen-crypto-mastery-foundations-production','Supply Tokens and Health Factor','cmf-module-2-28','text','### Supply Tokens\n\nWhen a lender deposits an asset, the protocol may issue a receipt token representing the position.\n\nThe receipt token may:\n\nIncrease in quantity as interest accrues\n\nIncrease in redemption value\n\nRepresent a claim on supplied assets\n\nBe transferable\n\nBe usable as collateral\n\nBe deposited into another protocol\n\nThe receipt token creates composability.\n\nIt also adds risk.\n\nIf it is used elsewhere, the lender becomes exposed to:\n\nThe original lending protocol\n\nThe receipt token\n\nThe second protocol\n\nAny additional borrowing or liquidity strategy\n\nA deposited asset can therefore become part of several interconnected positions.\n\n### Why Borrow Cryptocurrency?\n\nA borrower may want liquidity without selling an existing asset.\n\nSuppose an investor owns a cryptocurrency expected to appreciate over the long term.\n\nSelling it may:\n\nEnd future exposure\n\nCreate a taxable event\n\nConflict with the investment thesis\n\nBe undesirable during a temporary price decline\n\nThe investor may instead deposit it as collateral and borrow a stablecoin.\n\nThis preserves exposure to the collateral asset while creating spendable or investable liquidity.\n\nHowever, the borrower now has:\n\nContinued asset-price risk\n\nDebt\n\nInterest expense\n\nLiquidation risk\n\nSmart contract exposure\n\nBorrowing does not remove the need to sell. It may postpone or force a sale under less favourable conditions.\n\n### Why Most DeFi Loans Are Overcollateralised\n\nA permissionless lending protocol may not have access to conventional borrower information.\n\nIt cannot depend easily on:\n\nSalary deductions\n\nCredit bureaux\n\nCourt enforcement\n\nPersonal guarantees\n\nProperty registration\n\nCollection agencies\n\nIt therefore requires collateral worth more than the loan.\n\nSuppose a borrower wants 10,000 stablecoin units.\n\nThe protocol may require collateral worth 15,000 or 20,000 units.\n\nIf the collateral value falls, the protocol can liquidate it before the loan becomes undersecured.\n\nOvercollateralisation replaces much of the conventional credit assessment with automated asset protection.\n\n### Collateral\n\nCollateral is an asset pledged to secure a loan.\n\nAccepted collateral may include:\n\nNative blockchain coins\n\nStablecoins\n\nLiquid-staking tokens\n\nWrapped assets\n\nTokenised real-world assets\n\nGovernance tokens\n\nLiquidity-provider positions\n\nEach collateral asset has different risks.\n\nA protocol should consider:\n\nPrice volatility\n\nLiquidity\n\nMarket depth\n\nOracle quality\n\nToken concentration\n\nSmart contract risk\n\nBridge risk\n\nStablecoin risk\n\nA volatile or illiquid asset normally supports less borrowing than a stable and liquid one.\n\n### Loan-to-Value Ratio\n\nThe loan-to-value ratio, or LTV, compares the amount borrowed with the value of the collateral.\n\nThe formula is:\n\nLTV = Loan value ÷ Collateral value × 100\n\nSuppose:\n\nCollateral value: 20,000 units\n\nDebt: 10,000 units\n\nThe LTV is:\n\n10,000 ÷ 20,000 × 100 = 50 percent\n\nA lower LTV generally means a greater safety buffer.\n\nA higher LTV means the position is closer to liquidation.\n\n### Collateral Ratio\n\nThe collateral ratio expresses the relationship in the opposite direction.\n\nThe formula is:\n\nCollateral ratio = Collateral value ÷ Debt value × 100\n\nUsing the same example:\n\n20,000 ÷ 10,000 × 100 = 200 percent\n\nAn LTV of fifty percent is equivalent to a collateral ratio of two hundred percent.\n\nBoth measurements describe the same position from different perspectives.\n\nUsers should confirm which measure a protocol displays.\n\n### Collateral Factor\n\nA collateral factor determines how much borrowing capacity an asset provides.\n\nSuppose a protocol assigns an asset a collateral factor of seventy percent.\n\nIf a user deposits collateral worth 10,000 units, the theoretical maximum borrowing capacity may be:\n\n10,000 × 70 percent = 7,000 units\n\nThe collateral factor reflects the protocol’s assessment of the asset’s risk.\n\nA more volatile or less liquid asset may receive a lower factor.\n\nA stable and liquid asset may receive a higher one.\n\nThe maximum permitted amount is not necessarily a prudent borrowing amount.\n\nBorrowing to the limit leaves little room for market movement.\n\n### Liquidation Threshold\n\nThe liquidation threshold is the point at which a borrower’s position becomes eligible for liquidation.\n\nIt may differ from the initial borrowing limit.\n\nFor example:\n\nMaximum initial LTV: 70 percent\n\nLiquidation threshold: 80 percent\n\nA user depositing collateral worth 10,000 units may initially borrow up to 7,000.\n\nIf the debt rises or collateral falls until the LTV reaches eighty percent, liquidation can begin.\n\nThe difference between the initial borrowing limit and liquidation threshold creates a limited safety buffer.\n\n### Health Factor\n\nMany protocols display a health factor to summarise the safety of a borrowing position.\n\nA simplified formula may be expressed as:\n\nHealth factor = Adjusted collateral value ÷ Debt value\n\nAdjusted collateral value usually incorporates the liquidation threshold.\n\nA health factor:\n\nAbove 1 indicates the position is currently above the liquidation boundary\n\nEqual to 1 indicates liquidation eligibility\n\nBelow 1 indicates an undercollateralised position\n\nExact formulas differ between protocols.\n\nA health factor slightly above one may still be dangerously close to liquidation.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,2,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-28-lesson-03','cognizen-crypto-mastery-foundations-production','Health Factor Example and Supply APR and APY','cmf-module-2-28','text','### Health Factor Example\n\nSuppose:\n\nCollateral value: 15,000 units\n\nLiquidation threshold: 80 percent\n\nDebt: 10,000 units\n\nAdjusted collateral value:\n\n15,000 × 80 percent = 12,000 units\n\nHealth factor:\n\n12,000 ÷ 10,000 = 1.20\n\nThe position has a health factor of 1.20.\n\nIf the collateral falls to 12,500:\n\nAdjusted collateral value:\n\n12,500 × 80 percent = 10,000\n\nHealth factor:\n\n10,000 ÷ 10,000 = 1.00\n\nThe position may now be liquidated.\n\n### Maximum Borrowing Is Not Safe Borrowing\n\nProtocols often display the maximum amount a user is technically allowed to borrow.\n\nThis limit protects the protocol under its model.\n\nIt does not guarantee that the borrower can tolerate normal volatility.\n\nBorrowing near the maximum can create:\n\nFrequent liquidation risk\n\nConstant monitoring requirements\n\nHigh emotional pressure\n\nInability to respond during network congestion\n\nForced selling after a modest decline\n\nA prudent borrower generally maintains a larger buffer than the minimum protocol requirement.\n\n### Interest Accrual\n\nBorrowing interest typically accrues continuously or at frequent intervals.\n\nThe debt may increase every block or over another protocol-defined period.\n\nSuppose a borrower owes 10,000 units at an annualised rate of ten percent.\n\nIf the rate remained constant for one year, the approximate simple interest would be:\n\n10,000 × 10 percent = 1,000 units\n\nThe borrower would owe approximately:\n\n11,000 units\n\nIn practice:\n\nRates may change\n\nInterest may compound\n\nFees may apply\n\nRepayments may occur earlier\n\nThe debt token may update continuously\n\nA borrowing position can move toward liquidation even when the collateral price remains unchanged because the debt balance is growing.\n\n### Supply Interest\n\nLenders earn a portion of the interest paid by borrowers.\n\nSuppose:\n\nBorrowers pay an average rate of eight percent\n\nThe protocol retains a portion\n\nOnly part of the supplied liquidity is borrowed\n\nThe supplier rate will generally be lower than the borrowing rate.\n\nThe difference may compensate for:\n\nProtocol reserves\n\nRisk funds\n\nOperating incentives\n\nUnused liquidity\n\nA lender should not expect the borrowing APR to equal the supply APY.\n\n### Utilisation Rate\n\nThe utilisation rate measures how much supplied liquidity has been borrowed.\n\nThe simplified formula is:\n\nUtilisation = Borrowed amount ÷ Supplied amount × 100\n\nSuppose:\n\nTotal supplied: 10 million units\n\nTotal borrowed: 7 million units\n\nUtilisation:\n\n7 million ÷ 10 million × 100 = 70 percent\n\nThree million units remain available before considering reserves and other restrictions.\n\nUtilisation is a central input in many DeFi interest-rate models.\n\n### Interest-Rate Curves\n\nMany protocols adjust interest rates automatically according to utilisation.\n\n### Low Utilisation\n\nWhen little capital is borrowed:\n\nBorrowing rates may be low\n\nSupplier yields may be low\n\nThe protocol may try to encourage borrowing\n\n### High Utilisation\n\nWhen most liquidity is borrowed:\n\nBorrowing rates may rise\n\nSupplier yields may rise\n\nHigher rates encourage repayment\n\nHigher returns may attract new deposits\n\nThe rate curve attempts to maintain sufficient liquidity for withdrawals and new borrowing.\n\n### The Kink Model\n\nSome lending markets use an interest-rate curve with a target utilisation point, sometimes called a kink.\n\nBelow the target:\n\nRates rise gradually\n\nAbove the target:\n\nRates rise sharply\n\nSuppose the target utilisation is eighty percent.\n\nThe protocol may tolerate increasing borrowing up to that point.\n\nBeyond eighty percent, borrowing becomes much more expensive.\n\nThis is intended to:\n\nEncourage debt repayment\n\nAttract more suppliers\n\nProtect withdrawal liquidity\n\nA borrower should understand how rapidly the rate can change above the target.\n\n### Variable Borrowing Rates\n\nA variable rate changes according to market utilisation and protocol rules.\n\nPotential advantages include:\n\nEfficient response to supply and demand\n\nLower cost during periods of abundant liquidity\n\nTransparent formula-based adjustment\n\nPotential risks include:\n\nSudden rate increases\n\nUncertain future costs\n\nNegative leveraged-yield spreads\n\nFaster debt growth\n\nA borrowing strategy that is profitable at three percent may become unprofitable if the rate rises to fifteen percent.\n\n### Fixed or Stable Borrowing Rates\n\nSome protocols offer a rate intended to remain more stable.\n\nThis may provide:\n\nGreater cost predictability\n\nEasier planning\n\nReduced exposure to short-term utilisation changes\n\nHowever, the rate may not be permanently fixed.\n\nThe protocol may rebalance or change it when:\n\nMarket conditions become extreme\n\nLiquidity changes materially\n\nGovernance adjusts the model\n\nThe position violates protocol rules\n\nRead the definition carefully.\n\n“Stable” does not necessarily mean legally fixed for the full loan term.\n\n### Supply APR and APY\n\nLending dashboards may display:\n\nSupply APR\n\nSupply APY\n\nBorrow APR\n\nBorrow APY\n\nAPR generally excludes compounding.\n\nAPY generally assumes compounding.\n\nRates may be calculated from:\n\nCurrent utilisation\n\nRecent block activity\n\nIncentive-token values\n\nHistorical averages\n\nAn annualised number can change within minutes.\n\nIt should be viewed as a current estimate rather than a one-year guarantee.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,3,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-28-lesson-04','cognizen-crypto-mastery-foundations-production','Reserve Factor and Liquidation Bonus','cmf-module-2-28','text','### Reserve Factor\n\nThe reserve factor determines what portion of borrower interest is retained by the protocol rather than paid to suppliers.\n\nSuppose borrowers pay 10,000 units of interest.\n\nIf the reserve factor is ten percent:\n\n1,000 units go to protocol reserves\n\n9,000 units are available for suppliers, subject to other calculations\n\nReserves may help cover:\n\nBad debt\n\nSecurity incidents\n\nProtocol development\n\nGovernance-approved spending\n\nA large reserve factor lowers lender returns but may improve protocol resilience.\n\n### Protocol Reserves\n\nA lending protocol may accumulate reserves in several assets.\n\nThese funds may be used for:\n\nAbsorbing bad debt\n\nSupporting liquidity\n\nEmergency response\n\nIncentives\n\nTreasury spending\n\nEvaluate:\n\nReserve size\n\nAsset quality\n\nLiquidity\n\nGovernance control\n\nHistorical usage\n\nWhether reserves are sufficient under stress\n\nA reserve dominated by the protocol’s own token may lose value during the same event that creates losses.\n\n### Lending Incentives\n\nProtocols may reward lenders and borrowers with additional tokens.\n\nA borrower may even receive incentives that partially or temporarily exceed the interest cost.\n\nThe displayed net rate may therefore appear:\n\nVery low\n\nZero\n\nNegative\n\nA negative net borrowing rate means token incentives currently exceed borrowing interest.\n\nThis condition may not last.\n\nThe incentive token may:\n\nFall in price\n\nBecome less liquid\n\nBe reduced by governance\n\nBe subject to vesting\n\nCreate tax obligations\n\nThe contractual debt remains even if the incentive disappears.\n\n### Gross Versus Net Borrowing Cost\n\nA borrower should calculate:\n\nNet borrowing cost = Interest + fees − incentives received\n\nThis calculation should also consider:\n\nIncentive-token price changes\n\nClaiming costs\n\nTax\n\nSlippage when selling rewards\n\nOpportunity cost of collateral\n\nLiquidation risk\n\nA borrowing strategy that appears profitable from headline rates may be negative after all costs.\n\n### Lender Yield Sources\n\nA lender’s return may come from:\n\nBorrower interest\n\nProtocol incentives\n\nFee distributions\n\nTreasury subsidies\n\nExternal strategy income\n\nEach component should be separated.\n\nBorrower interest may be more economically sustainable than temporary token issuance.\n\nHowever, it still depends on:\n\nBorrowing demand\n\nCollateral quality\n\nLiquidation performance\n\nProtocol security\n\nA high supplier yield can signal high demand, but it can also signal market stress and liquidity shortage.\n\n### Withdrawal Liquidity\n\nA lender may be able to withdraw only if sufficient unborrowed liquidity remains in the pool.\n\nSuppose:\n\nTen million units are supplied\n\nNine-and-a-half million are borrowed\n\nOnly five hundred thousand remain\n\nA lender attempting to withdraw one million may be unable to do so immediately.\n\nThe protocol may require:\n\nOther suppliers to deposit\n\nBorrowers to repay\n\nLiquidations to occur\n\nInterest rates to attract liquidity\n\nA position can be economically solvent but temporarily illiquid.\n\n### Withdrawal Queues\n\nSome lending systems use withdrawal queues when immediate liquidity is unavailable.\n\nA user may submit a withdrawal request and wait until:\n\nBorrowers repay\n\nNew lenders deposit\n\nAssets mature\n\nCollateral is liquidated\n\nThe protocol processes the queue\n\nThe queue may function normally during calm conditions and grow during stress.\n\nBefore lending, determine whether withdrawals are:\n\nImmediate\n\nBest effort\n\nQueue-based\n\nSubject to lock-ups\n\nControlled by a company or governance process\n\n### Liquidity Mismatch\n\nLiquidity mismatch occurs when lenders expect short-term access while borrowers use funds for longer or less liquid activities.\n\nThis is common in conventional banking and can also occur in cryptocurrency lending.\n\nFor example:\n\nDepositors expect instant withdrawals\n\nThe platform makes long-term or illiquid loans\n\nMany depositors withdraw simultaneously\n\nThe platform cannot return assets immediately\n\nDecentralised pooled lending reduces some forms of opacity, but highly utilised pools can still experience withdrawal pressure.\n\nCentralised lenders may have even greater mismatch when their loan book is not publicly visible.\n\n### Liquidation\n\nLiquidation protects the protocol when collateral value becomes insufficient.\n\nA liquidator repays part of the borrower’s debt.\n\nIn return, the liquidator receives collateral, usually at a discount.\n\nThis process:\n\nReduces outstanding debt\n\nRestores the position’s safety\n\nRewards the liquidator\n\nProtects lenders from bad debt\n\nFor the borrower, liquidation creates:\n\nCollateral loss\n\nA penalty\n\nReduced future exposure\n\nPotential tax consequences\n\nThe mechanism is automatic and does not wait for the borrower’s permission.\n\n### Liquidation Bonus\n\nThe liquidation bonus is the discount or incentive paid to the liquidator.\n\nSuppose:\n\nA liquidator repays 1,000 units of debt\n\nLiquidation bonus: 5 percent\n\nThe liquidator may receive collateral worth approximately:\n\n1,000 × 1.05 = 1,050 units\n\nThe extra fifty units compensates for:\n\nTransaction fees\n\nExecution risk\n\nMarket volatility\n\nCompetition\n\nThe need to sell collateral\n\nThe bonus is effectively paid from the borrower’s collateral.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,4,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-28-lesson-05','cognizen-crypto-mastery-foundations-production','Close Factor and Stablecoin Borrowing','cmf-module-2-28','text','### Close Factor\n\nA close factor may limit how much debt can be liquidated in one transaction.\n\nFor example, a protocol may allow a liquidator to repay no more than fifty percent of the outstanding debt at once.\n\nThis can prevent unnecessary full liquidation after a small threshold breach.\n\nHowever, severe conditions may permit larger or complete liquidation.\n\nThe exact rules differ between protocols and can change through governance.\n\n### Partial and Full Liquidation\n\n\n\n### Partial Liquidation\n\nOnly part of the debt is repaid and part of the collateral is removed.\n\nThe position may remain open with an improved health factor.\n\n### Full Liquidation\n\nThe entire position is closed or most collateral is sold.\n\nThis may occur when:\n\nThe position is deeply undercollateralised\n\nProtocol rules allow complete closure\n\nMarket prices move rapidly\n\nCollateral liquidity deteriorates\n\nBorrowers should not assume liquidation will be a small or gradual event.\n\n### Liquidation Price\n\nA borrower may calculate the approximate collateral price at which liquidation begins.\n\nSuppose:\n\nOne collateral token is deposited\n\nIts current value is 2,000 units\n\nDebt is 1,000 units\n\nLiquidation threshold is 75 percent\n\nLiquidation begins when:\n\nCollateral value × 75 percent = Debt\n\nRequired collateral value:\n\n1,000 ÷ 0.75 = approximately 1,333.33 units\n\nIf the token price falls from 2,000 to approximately 1,333, the position reaches the threshold before accounting for interest growth and fees.\n\nThe actual liquidation level changes as debt accrues.\n\n### Maintaining a Safety Buffer\n\nA borrower can reduce liquidation risk by:\n\nBorrowing less\n\nDepositing more collateral\n\nRepaying part of the debt\n\nUsing less volatile collateral\n\nMonitoring interest\n\nMaintaining liquid funds for emergency repayment\n\nA larger buffer provides more time to respond.\n\nIt does not eliminate:\n\nFlash crashes\n\nOracle errors\n\nNetwork congestion\n\nStablecoin depegging\n\nProtocol failure\n\nA position should be safe enough to survive realistic stress, not only ordinary daily volatility.\n\n### Liquidation Cascades\n\nA liquidation cascade occurs when falling prices trigger forced collateral sales that push prices lower and cause additional liquidations.\n\nA simplified sequence is:\n\nCollateral price falls\n\nHealth factors decline\n\nPositions become liquidatable\n\nLiquidators sell collateral\n\nSelling pressure lowers the price\n\nMore positions become eligible\n\nThe cycle continues\n\nCascades may be amplified by:\n\nLeverage\n\nThin liquidity\n\nCorrelated collateral\n\nStablecoin stress\n\nExchange liquidations\n\nNetwork congestion\n\nA protocol’s risk model should consider how much collateral can realistically be sold during severe market stress.\n\n### Bad Debt\n\nBad debt occurs when the value recovered from collateral is insufficient to repay the borrower’s debt fully.\n\nPossible causes include:\n\nRapid price gaps\n\nIlliquid collateral\n\nDelayed oracle updates\n\nNetwork congestion\n\nFailed liquidations\n\nSmart contract errors\n\nCollateral depegging\n\nBad debt may be absorbed by:\n\nProtocol reserves\n\nInsurance funds\n\nGovernance treasury\n\nSuppliers\n\nA protocol-token auction\n\nSocialised losses\n\nUsers should understand who ultimately bears the loss.\n\n### Socialised Losses\n\nSocialised losses occur when losses from one part of the system are distributed across other users.\n\nFor example, suppliers may receive less than expected because the pool contains unrecoverable debt.\n\nThe protocol may reduce:\n\nRedemption value\n\nInterest payments\n\nAvailable withdrawals\n\nToken backing\n\nA lending platform may advertise overcollateralisation while still exposing suppliers to bad debt under extreme conditions.\n\n### Oracle Dependence\n\nLending protocols require reliable asset prices to calculate:\n\nCollateral value\n\nBorrowing capacity\n\nHealth factors\n\nLiquidation thresholds\n\nLiquidation payments\n\nA price oracle supplies this information.\n\nIf the oracle reports an incorrect value, the protocol may:\n\nLiquidate healthy borrowers\n\nAllow excessive borrowing\n\nMisprice collateral\n\nAccumulate bad debt\n\nOracle design is therefore a critical part of lending security.\n\n### Oracle Manipulation\n\nAn attacker may attempt to manipulate a low-liquidity market used by the oracle.\n\nA simplified attack could involve:\n\nBorrowing large temporary capital\n\nTrading aggressively in a shallow market\n\nDistorting the reported collateral price\n\nBorrowing excessive assets against the inflated collateral\n\nAllowing the collateral price to return to normal\n\nLeaving the protocol with bad debt\n\nStrong oracle systems may use:\n\nMultiple exchanges\n\nTime-weighted averages\n\nIndependent data providers\n\nPrice-deviation limits\n\nCircuit breakers\n\nMinimum liquidity requirements\n\n### Stale Oracle Data\n\nAn oracle may fail to update quickly during market volatility.\n\nIf the reported price is too old:\n\nBorrowers may withdraw too much\n\nLiquidations may be delayed\n\nHealthy positions may be misclassified\n\nProtocol losses may increase\n\nThe protocol should define:\n\nUpdate frequency\n\nMaximum acceptable delay\n\nFallback sources\n\nEmergency behaviour\n\nA highly secure smart contract can still fail economically when it receives poor data.\n\n### Stablecoin Borrowing\n\nBorrowing stablecoins is common because they provide a relatively stable unit of account.\n\nA borrower may deposit volatile collateral and borrow a stablecoin.\n\nThis creates a leveraged exposure to the collateral asset.\n\nSuppose:\n\nThe borrower deposits a cryptocurrency\n\nBorrows stablecoins\n\nUses the stablecoins for expenses\n\nRetains the collateral\n\nIf the collateral rises, the borrower benefits from continued exposure.\n\nIf it falls, liquidation risk increases.\n\nThe debt remains denominated in the stablecoin.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,5,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-28-lesson-06','cognizen-crypto-mastery-foundations-production','Stablecoin Depeg Risk for Borrowers and Token Listing Risk','cmf-module-2-28','text','### Stablecoin Depeg Risk for Borrowers\n\nA stablecoin debt may become more or less expensive if the stablecoin loses its peg.\n\nSuppose a borrower owes 10,000 stablecoin units.\n\nIf each unit rises above its intended value, repaying the debt becomes more expensive in external currency terms.\n\nIf the stablecoin falls below its peg, repayment may become cheaper—but the protocol or market may experience broader instability.\n\nThe borrower is exposed to both:\n\nCollateral price\n\nDebt-asset stability\n\n### Stablecoin Lending Risk\n\nA lender supplying stablecoins faces risks involving:\n\nStablecoin issuer\n\nReserve quality\n\nRedemption\n\nRegulation\n\nSmart contract\n\nBorrower collateral\n\nProtocol liquidity\n\nA five-percent stablecoin yield is not equivalent to risk-free cash interest.\n\nThe lender may lose through:\n\nDepegging\n\nProtocol exploit\n\nBad debt\n\nWithdrawal restrictions\n\nIssuer freezing\n\nBridge failure\n\n### Borrowing Volatile Assets\n\nA user may borrow a volatile cryptocurrency instead of a stablecoin.\n\nThis creates a short-like exposure.\n\nSuppose the borrower:\n\nBorrows Asset A\n\nSells it for a stablecoin\n\nPlans to repurchase it later at a lower price\n\nRepays the loan\n\nIf Asset A falls, the strategy may profit.\n\nIf Asset A rises, the debt becomes more expensive.\n\nPotential losses can be very large because an asset’s price has no fixed maximum.\n\nBorrowing a volatile asset involves substantial market risk in addition to interest and liquidation risk.\n\n### Collateral Correlation\n\nCollateral risk depends partly on its relationship with the borrowed asset.\n\nSuppose a user deposits one volatile token and borrows another highly correlated token.\n\nBoth may decline together, but the exact effect depends on their relative movement.\n\nA protocol may offer higher collateral efficiency for closely related assets because their prices historically move together.\n\nThis introduces correlation-break risk.\n\nAssets that normally track one another can diverge during stress.\n\n### Efficiency Modes\n\nSome protocols offer specialised borrowing modes for highly correlated assets.\n\nThese modes may allow:\n\nHigher LTV\n\nLower liquidation buffers\n\nGreater capital efficiency\n\nExamples may include borrowing one stablecoin against another or borrowing an underlying asset against its liquid-staking token.\n\nThe higher efficiency depends on the assumption that the assets remain closely linked.\n\nIf one depegs or redemption fails, liquidation can occur rapidly.\n\nCapital efficiency increases when safety margins decrease.\n\n### Isolated Collateral\n\nIn an isolated market, a specific collateral asset can support borrowing only under restricted conditions.\n\nThe protocol may limit:\n\nWhich asset may be borrowed\n\nMaximum total debt\n\nLTV\n\nExposure to the rest of the system\n\nIsolation helps contain the damage if a riskier collateral asset fails.\n\nIt reduces contagion between markets.\n\nUsers should determine whether their position is isolated and what restrictions apply.\n\n### Cross-Collateral Borrowing\n\nCross-collateral systems combine several collateral assets into one borrowing account.\n\nPotential advantages include:\n\nGreater capital efficiency\n\nSimplified portfolio borrowing\n\nOffsetting collateral values\n\nPotential risks include:\n\nOne weak asset endangering the entire account\n\nLiquidation across multiple holdings\n\nComplex risk calculation\n\nCorrelation during market stress\n\nA user may lose high-quality collateral because a smaller speculative collateral position deteriorates.\n\n### Cross-Margin Risk\n\nCross-margin structures use the value of several positions to support total debt.\n\nLosses in one position can consume collateral associated with another.\n\nThis may delay liquidation initially but increase the eventual loss.\n\nThe user should understand whether:\n\nEach position is independent\n\nAll collateral supports all debt\n\nLiquidators can seize any collateral\n\nRisk can spread across the account\n\nEfficiency and contagion often increase together.\n\n### Supply Caps and Borrow Caps\n\nProtocols may limit how much of an asset can be supplied or borrowed.\n\n### Supply Cap\n\nLimits total collateral or deposits accepted.\n\n### Borrow Cap\n\nLimits total borrowing of an asset.\n\nCaps can reduce exposure to:\n\nIlliquid tokens\n\nOracle manipulation\n\nConcentrated collateral\n\nSudden market expansion\n\nIf caps are reached, users may be unable to deposit or borrow more.\n\nGovernance may adjust the limits over time.\n\n### Debt Ceilings\n\nA debt ceiling limits how much debt can be created against a particular collateral type.\n\nThis is particularly useful for higher-risk or isolated assets.\n\nA low ceiling contains potential losses if the collateral fails.\n\nA rapidly increasing ceiling may signal that governance is accepting greater system exposure.\n\nRisk parameters should be reviewed as part of protocol governance analysis.\n\n### Token Listing Risk\n\nA lending protocol must decide which assets are accepted as collateral or borrowable markets.\n\nAdding a new token can create:\n\nNew fee and borrowing demand\n\nGreater protocol usage\n\nOracle risk\n\nLiquidity risk\n\nGovernance conflict\n\nBad-debt risk\n\nA token may be unsuitable as collateral when it has:\n\nConcentrated ownership\n\nLow liquidity\n\nChangeable transfer rules\n\nHigh volatility\n\nWeak oracles\n\nLarge unlocks\n\nBridge dependence\n\nListing is a risk decision, not merely a growth feature.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,6,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-28-lesson-07','cognizen-crypto-mastery-foundations-production','Governance Risk and Leveraged Short Strategy','cmf-module-2-28','text','### Governance Risk\n\nGovernance may control:\n\nCollateral factors\n\nLiquidation thresholds\n\nInterest-rate models\n\nReserve factors\n\nAsset listings\n\nSupply and borrow caps\n\nOracle providers\n\nContract upgrades\n\nTreasury use\n\nA poorly designed or malicious proposal can change the safety of existing positions.\n\nUsers should monitor governance when they hold meaningful lending or borrowing exposure.\n\n### Administrator Powers\n\nA protocol may have administrator keys that can:\n\nPause markets\n\nFreeze borrowing\n\nChange risk parameters\n\nUpgrade contracts\n\nReplace oracles\n\nRecover assets\n\nRestrict withdrawals\n\nEmergency powers can protect users during an exploit.\n\nThey also create centralisation and key-compromise risk.\n\nReview:\n\nWho controls the keys\n\nWhether a multisignature is used\n\nWhether changes have a timelock\n\nWhether emergency actions are publicly documented\n\n### Smart Contract Risk\n\nLending contracts may contain vulnerabilities involving:\n\nInterest calculations\n\nCollateral accounting\n\nToken transfers\n\nLiquidation logic\n\nAccess controls\n\nUpgradeability\n\nPrice oracles\n\nRe-entrancy\n\nFlash loans\n\nAn exploit may:\n\nDrain supplied assets\n\nCreate artificial collateral\n\nPrevent withdrawals\n\nProduce bad debt\n\nManipulate interest\n\nAudits reduce risk but cannot guarantee safety.\n\n### Economic Design Risk\n\nThe code may function exactly as intended while the economic model fails.\n\nExamples include:\n\nCollateral limits set too high\n\nLiquidation bonuses set too low\n\nPoorly designed interest curves\n\nWeak withdrawal incentives\n\nInadequate reserves\n\nRisky collateral accepted\n\nOracle markets too shallow\n\nProtocol evaluation must consider both software and financial design.\n\n### Flash Loans\n\nA flash loan is borrowed and repaid within one blockchain transaction.\n\nNo ordinary collateral is required because the transaction reverses if repayment does not occur.\n\nFlash loans may support:\n\nArbitrage\n\nDebt refinancing\n\nCollateral swaps\n\nLiquidations\n\nInterest-rate optimisation\n\nThey may also fund attacks involving:\n\nOracle manipulation\n\nGovernance exploits\n\nLow-liquidity collateral\n\nEconomic-design weaknesses\n\nThe flash loan is usually the source of temporary capital, not the underlying vulnerability.\n\n### Credit Delegation\n\nCredit delegation occurs when one user allows another user to borrow against their supplied capital or credit line.\n\nThe delegator accepts some form of borrower risk.\n\nThe arrangement may use:\n\nLegal agreements\n\nWhitelists\n\nSmart contracts\n\nInstitutional underwriting\n\nOn-chain reputation\n\nUnlike ordinary overcollateralised lending, credit delegation may expose the lender more directly to default.\n\nUsers should understand:\n\nWho the borrower is\n\nWhich recourse exists\n\nWhether the loan is secured\n\nHow losses are allocated\n\n### Undercollateralised Lending\n\nUndercollateralised lending allows borrowing with collateral worth less than the loan.\n\nThis resembles conventional credit more closely.\n\nIt requires some substitute for full on-chain collateral, such as:\n\nIdentity\n\nCredit assessment\n\nLegal agreements\n\nFuture income\n\nInstitutional reputation\n\nInsurance\n\nCommunity guarantees\n\nPotential use cases include:\n\nBusiness credit\n\nMarket-maker financing\n\nTrade finance\n\nReal-world lending\n\nThe system introduces greater default, legal and enforcement risk.\n\nPermissionless overcollateralised lending and undercollateralised credit should not be treated as the same product.\n\n### Real-World Asset Lending\n\nBlockchain protocols may finance loans connected to real-world assets or borrowers.\n\nPossible collateral or repayment sources include:\n\nProperty\n\nInvoices\n\nLoans\n\nBonds\n\nBusiness revenue\n\nEquipment\n\nCommodities\n\nThese systems may use blockchain records and tokens while relying heavily on off-chain institutions.\n\nRisks include:\n\nLegal enforceability\n\nAsset custody\n\nValuation\n\nFraud\n\nServicing\n\nJurisdiction\n\nBorrower default\n\nBankruptcy procedures\n\nTokenisation does not remove conventional credit risk.\n\n### Rehypothecation\n\nRehypothecation occurs when deposited or pledged assets are reused in additional financial activities.\n\nA centralised lender may lend customer assets to another institution.\n\nA DeFi user may deposit a lending receipt token into another protocol.\n\nThis can create multiple layers of claims.\n\nPotential benefits include:\n\nGreater capital efficiency\n\nAdditional yield\n\nMore available credit\n\nPotential risks include:\n\nContagion\n\nUnclear asset ownership\n\nComplex liquidation\n\nSeveral protocols depending on the same collateral\n\nThe same economic value may support multiple positions.\n\n### Recursive Borrowing\n\nRecursive borrowing, also called looping, repeatedly deposits and borrows assets to increase exposure.\n\nA simplified strategy may be:\n\nDeposit collateral\n\nBorrow an asset\n\nUse the borrowed asset to buy more collateral\n\nDeposit the additional collateral\n\nBorrow again\n\nRepeat\n\nThis increases effective leverage.\n\nIt may also increase:\n\nInterest cost\n\nLiquidation sensitivity\n\nTransaction fees\n\nSmart contract exposure\n\nUnwinding complexity\n\n### Leveraged Long Strategy\n\nSuppose a user expects Asset A to rise.\n\nThey may:\n\nDeposit Asset A\n\nBorrow stablecoins\n\nBuy more Asset A\n\nDeposit it as additional collateral\n\nThe user now has greater exposure to Asset A than their original capital.\n\nIf the asset rises, gains are amplified.\n\nIf it falls, losses and liquidation risk are amplified.\n\nThis is a leveraged long position, even though it may appear as several lending transactions.\n\n### Leveraged Short Strategy\n\nA user expecting Asset A to fall may:\n\nDeposit stablecoin collateral\n\nBorrow Asset A\n\nSell Asset A for stablecoins\n\nRepurchase it later at a lower price\n\nRepay the debt\n\nIf Asset A rises, the debt becomes more expensive and may threaten the collateral.\n\nShort exposure can create very large losses.\n\nBorrowing should be analysed according to its economic direction, not only its interface.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,7,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-28-lesson-08','cognizen-crypto-mastery-foundations-production','Yield Looping and Lender Risk Analysis','cmf-module-2-28','text','### Yield Looping\n\nA user may borrow to increase yield exposure.\n\nFor example:\n\nDeposit a liquid-staking token\n\nBorrow the underlying asset\n\nStake or convert it into more LST\n\nDeposit again\n\nThe strategy may earn the difference between:\n\nStaking yield\n\nBorrowing cost\n\nIt also adds:\n\nLeverage\n\nLST depeg risk\n\nLiquidation risk\n\nVariable rates\n\nSmart contract dependencies\n\nA small negative change in the yield spread can make the strategy unprofitable.\n\n### Net Yield Spread\n\nA simplified leveraged-yield calculation is:\n\nNet spread = Yield earned − Borrowing cost − fees\n\nSuppose:\n\nStaking yield: 7 percent\n\nBorrowing rate: 4 percent\n\nOther annualised costs: 1 percent\n\nApproximate net spread:\n\n7 − 4 − 1 = 2 percent\n\nThe two-percent spread may not justify:\n\nLiquidation risk\n\nSmart contract risk\n\nRate variability\n\nDepegging\n\nOperational complexity\n\nReturns should be compared with the full risk, not only the positive spread.\n\n### Rate Inversion\n\nRate inversion occurs when borrowing costs rise above the yield earned.\n\nSuppose a strategy earns six percent while the borrowing rate rises to nine percent.\n\nThe position now loses approximately three percent annually before other costs.\n\nThe borrower may need to:\n\nRepay debt\n\nReduce leverage\n\nAccept negative carry\n\nWait for rates to change\n\nHigh utilisation can cause rate inversion rapidly.\n\n### Liquidation During Network Congestion\n\nA borrower may plan to add collateral or repay debt during a decline.\n\nDuring network congestion:\n\nTransactions may remain pending\n\nFees may rise sharply\n\nThe user’s transaction may fail\n\nLiquidators may use faster execution\n\nFront-end interfaces may become overloaded\n\nA position that requires immediate manual action is not truly safe.\n\nMaintain enough buffer to account for operational delays.\n\n### Liquidator Competition\n\nLiquidations can be profitable.\n\nAutomated liquidators compete to identify and close eligible positions.\n\nThey may use:\n\nBots\n\nPrivate transaction routing\n\nHigh network fees\n\nSpecialised infrastructure\n\nFlash loans\n\nBorrowers should not assume they will receive a warning period.\n\nOnce a position becomes eligible, automated systems may liquidate it almost immediately.\n\n### MEV and Liquidations\n\nMaximum Extractable Value may affect liquidation ordering.\n\nBlock producers or specialised traders may compete to place profitable liquidation transactions first.\n\nThis can improve protocol solvency by encouraging rapid liquidation.\n\nIt can also:\n\nIncrease network fees\n\nCreate transaction-ordering advantages\n\nExclude ordinary participants\n\nConcentrate liquidation profits\n\nThe system relies on economic incentives to protect lenders.\n\n### Deleveraging\n\nDeleveraging reduces borrowing exposure.\n\nA borrower may:\n\nRepay part of the debt\n\nAdd collateral\n\nSell part of the collateral to repay\n\nClose recursive loops\n\nMove to less volatile collateral\n\nDeleveraging is easier before market stress becomes severe.\n\nWaiting until the health factor approaches liquidation may leave few practical options.\n\n### Collateral Swaps\n\nSome protocols allow borrowers to replace one collateral asset with another without closing the entire loan.\n\nPotential benefits include:\n\nReducing volatility\n\nChanging market exposure\n\nAvoiding several manual transactions\n\nImproving the health factor\n\nRisks include:\n\nSlippage\n\nSmart contract complexity\n\nTemporary exposure during the swap\n\nTax consequences\n\nOracle movement\n\nThe borrower should confirm that the final collateral remains appropriate and liquid.\n\n### Debt Refinancing\n\nA borrower may move debt between:\n\nAssets\n\nProtocols\n\nFixed and variable rates\n\nDifferent blockchains\n\nRefinancing may reduce interest or improve collateral efficiency.\n\nIt introduces:\n\nBridge risk\n\nTransaction fees\n\nSmart contract risk\n\nTiming risk\n\nTemporary double exposure\n\nNew governance rules\n\nA lower displayed rate may not justify moving to a weaker protocol.\n\n### Self-Repaying or Yield-Assisted Loans\n\nSome systems use the yield generated by collateral to reduce debt over time.\n\nA simplified structure may involve:\n\nThe user deposits a yield-generating asset\n\nThe protocol lends or stakes it\n\nGenerated yield repays the debt\n\nThe principal collateral remains locked\n\nThe loan is not literally guaranteed to repay itself.\n\nRepayment depends on:\n\nYield continuing\n\nCollateral remaining safe\n\nProtocol solvency\n\nFees\n\nNo exploit\n\nSufficient time\n\nIf yield declines or losses occur, repayment may take longer or fail.\n\n### Borrower Risk Analysis\n\nA borrower should evaluate:\n\nCollateral volatility\n\nBorrowed asset stability\n\nInterest-rate variability\n\nLiquidation threshold\n\nHealth factor\n\nUnbonding or withdrawal restrictions\n\nNetwork congestion\n\nOracle quality\n\nProtocol security\n\nRepayment liquidity\n\nThe borrower should also ask:\n\nWhat will happen if the collateral falls fifty percent while the borrowing rate doubles?\n\nA strategy that cannot survive a severe but plausible scenario may be oversized.\n\n### Lender Risk Analysis\n\nA lender should evaluate:\n\nBorrower demand\n\nCollateral quality\n\nLiquidation design\n\nOracle reliability\n\nAvailable withdrawal liquidity\n\nReserve adequacy\n\nBad-debt history\n\nSmart contract security\n\nIncentive sustainability\n\nStablecoin or token risk\n\nThe lender’s return is compensation for providing capital to a credit system.\n\nIt should not be judged by yield alone.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,8,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-28-lesson-09','cognizen-crypto-mastery-foundations-production','Protocol-Level Risk Analysis and Lending and Taxation','cmf-module-2-28','text','### Protocol-Level Risk Analysis\n\nA lending protocol must manage the interaction between:\n\nSupplied liquidity\n\nBorrowing demand\n\nCollateral volatility\n\nInterest rates\n\nLiquidators\n\nOracles\n\nGovernance\n\nReserves\n\nNetwork capacity\n\nA weakness in one area can affect the whole system.\n\nFor example:\n\nPoor oracle design allows excessive borrowing\n\nWeak liquidity prevents collateral sales\n\nBad debt reduces supplier claims\n\nWithdrawal pressure increases utilisation\n\nRates rise\n\nBorrowers repay or are liquidated\n\nMarket selling intensifies\n\nLending protocols can amplify market stress through feedback loops.\n\n### Protocol Solvency\n\nA lending protocol is solvent when the value of its recoverable assets and collateral is sufficient to meet its obligations to suppliers.\n\nSolvency can be threatened by:\n\nBad debt\n\nUnrecoverable collateral\n\nSmart contract exploits\n\nStablecoin depegging\n\nFraudulent assets\n\nOracle manipulation\n\nGovernance attacks\n\nA protocol may remain operational while carrying hidden or recognised bad debt.\n\nUsers should examine public risk reports and on-chain positions where available.\n\n### Proof of Reserves and Liabilities\n\nA centralised lender may publish proof of reserves.\n\nReserves alone do not show the complete financial position.\n\nA proper assessment also requires liabilities.\n\nFor example:\n\nAssets held\n\nCustomer deposits owed\n\nLoans receivable\n\nCollateral quality\n\nRelated-party exposures\n\nOff-balance-sheet obligations\n\nA wallet balance proves control of assets at a moment in time.\n\nIt does not prove that the company is solvent or that the assets are unencumbered.\n\n### Insurance and Safety Modules\n\nSome lending protocols use insurance or safety mechanisms funded by:\n\nProtocol reserves\n\nStaked governance tokens\n\nInsurance pools\n\nExternal coverage\n\nTreasury assets\n\nIn a deficit event, the system may:\n\nSell reserve assets\n\nSlash staked tokens\n\nMint new tokens\n\nCompensate suppliers partially\n\nSocialise losses\n\nReview:\n\nWhich events are covered\n\nMaximum available capital\n\nGovernance discretion\n\nAsset quality\n\nHistorical performance\n\nThe term insurance may not indicate a regulated or legally guaranteed policy.\n\n### Governance-Token Backstops\n\nA protocol may use staked governance tokens as a backstop.\n\nIf bad debt occurs, part of the staked token supply may be sold or reduced.\n\nThis creates:\n\nIncentive for governance oversight\n\nPotential loss for stakers\n\nAdditional market selling during stress\n\nDependence on governance-token liquidity\n\nIf the protocol and governance token fail together, the backstop may be weakest when most needed.\n\n### Circuit Breakers\n\nA circuit breaker temporarily limits or pauses activity when abnormal conditions occur.\n\nIt may:\n\nFreeze new borrowing\n\nReduce collateral factors\n\nPause liquidations\n\nLimit withdrawals\n\nReject stale oracle prices\n\nCircuit breakers can prevent further damage.\n\nThey may also restrict users during a crisis.\n\nThe protocol should disclose:\n\nTrigger conditions\n\nWho controls activation\n\nDuration\n\nRecovery procedures\n\nWhether governance approval is required\n\n### Emergency Risk Changes\n\nGovernance or administrators may change parameters rapidly during market stress.\n\nPossible actions include:\n\nLowering collateral factors\n\nFreezing a market\n\nReducing supply caps\n\nRaising reserve factors\n\nReplacing an oracle\n\nIncreasing liquidation incentives\n\nThese changes may protect the protocol but negatively affect users.\n\nA borrower’s safe position can become less safe after a parameter change.\n\nMonitoring governance is part of position management.\n\n### Bridge Risk in Cross-Chain Lending\n\nA lending protocol may operate on several blockchains or accept bridged assets.\n\nCross-chain lending can add:\n\nBridge-contract risk\n\nWrapped-asset risk\n\nMessage-passing risk\n\nValidator or signer risk\n\nDelayed settlement\n\nChain-specific liquidity differences\n\nA bridged asset may lose backing while remaining listed as collateral.\n\nProtocols should use conservative limits for assets dependent on external bridges.\n\n### Network-Specific Liquidity\n\nThe same token may have strong liquidity on one blockchain and weak liquidity on another.\n\nA protocol operating on a smaller network may have:\n\nLess collateral depth\n\nFewer liquidators\n\nWeaker stablecoin liquidity\n\nGreater oracle vulnerability\n\nHigher bridge dependence\n\nProtocol scale should be assessed on the exact network being used.\n\nGlobal brand recognition does not guarantee local chain liquidity.\n\n### Front-End Risk\n\nA legitimate lending protocol may be accessed through a compromised website.\n\nThe interface could:\n\nRequest malicious approvals\n\nDisplay false health factors\n\nRedirect deposits\n\nHide transaction details\n\nOffer fraudulent migrations\n\nUsers should verify:\n\nDomain\n\nContract addresses\n\nWallet requests\n\nGovernance announcements\n\nFor meaningful positions, understanding alternative contract-access methods may reduce dependence on one interface.\n\n### Token Approval Risk\n\nSupplying or repaying assets may require token approvals.\n\nAn unlimited approval can remain active after the loan is closed.\n\nIf the approved contract or interface is compromised later, the permission may create risk.\n\nUsers should:\n\nVerify the spender address\n\nLimit approvals where practical\n\nRevoke old permissions\n\nUse separate DeFi wallets\n\nA closed lending position does not automatically revoke every approval.\n\n### Lending and Taxation\n\nLending and borrowing may create complex tax events.\n\nDepending on the jurisdiction, relevant events may include:\n\nReceipt of interest\n\nIncentive rewards\n\nDepositing assets\n\nReceiving supply tokens\n\nLiquidation\n\nCollateral sale\n\nDebt forgiveness\n\nSwaps\n\nCross-chain transfers\n\nBorrowing itself may not always be treated as income, but liquidation or reward receipt may have consequences.\n\nAccurate records should include:\n\nDates\n\nAssets\n\nQuantities\n\nMarket values\n\nInterest\n\nFees\n\nTransaction identifiers\n\nLiquidation details\n\nProfessional guidance may be necessary.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,9,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-28-lesson-10','cognizen-crypto-mastery-foundations-production','Lending Position Records and Safer Lending Practices','cmf-module-2-28','text','### Lending Position Records\n\nA lending record may include:\n\nProtocol or provider\n\nBlockchain\n\nWallet\n\nAsset supplied\n\nAmount supplied\n\nSupply token received\n\nSupply rate\n\nIncentives\n\nWithdrawal conditions\n\nDeposit and withdrawal dates\n\nFees\n\nInterest earned\n\nTax values\n\nDo not store private keys or seed phrases.\n\n### Borrowing Position Records\n\nA borrowing record may include:\n\nCollateral asset\n\nCollateral quantity\n\nBorrowed asset\n\nDebt amount\n\nCurrent interest rate\n\nInitial LTV\n\nCurrent LTV\n\nLiquidation threshold\n\nHealth factor\n\nEstimated liquidation price\n\nUnbonding restrictions\n\nRepayment plan\n\nEmergency collateral source\n\nGovernance changes\n\nTransaction costs\n\nThis record should be updated as prices, debt and protocol parameters change.\n\n### A Borrowing Stress Test\n\nBefore borrowing, model several scenarios.\n\n### Collateral Falls 20 Percent\n\nWhat is the new LTV?\n\nWhat is the health factor?\n\n### Collateral Falls 50 Percent\n\nIs liquidation likely?\n\nCan additional collateral be added?\n\n### Borrowing Rate Doubles\n\nDoes the strategy remain profitable?\n\nHow quickly does debt grow?\n\n### Stablecoin Depegs\n\nDoes the debt become more expensive?\n\nIs the collateral affected too?\n\n### Network Becomes Congested\n\nCan repayment occur in time?\n\nAre sufficient fees available?\n\n### Protocol Changes Risk Parameters\n\nDoes the position remain safe?\n\nThe strategy should remain manageable under more than one favourable outcome.\n\n### Example: Collateral Decline\n\nSuppose:\n\nCollateral deposited: 10 tokens\n\nStarting token price: 2,000\n\nCollateral value: 20,000\n\nDebt: 8,000\n\nInitial LTV: 40 percent\n\nLiquidation threshold: 75 percent\n\nIf the token falls to 1,200:\n\nNew collateral value:\n\n10 × 1,200 = 12,000\n\nNew LTV:\n\n8,000 ÷ 12,000 × 100 = approximately 66.7 percent\n\nThe position remains above the liquidation threshold but has much less safety.\n\nIf the token falls to approximately 1,066.67:\n\nCollateral value:\n\n10 × 1,066.67 = approximately 10,666.70\n\nLTV:\n\n8,000 ÷ 10,666.70 ≈ 75 percent\n\nThe position reaches liquidation eligibility before considering accrued interest.\n\n### Example: Interest Increasing Liquidation Risk\n\nSuppose collateral value remains 15,000 units.\n\nInitial debt:\n\n10,000 units\n\nLiquidation threshold:\n\n75 percent\n\nMaximum debt before liquidation:\n\n15,000 × 75 percent = 11,250 units\n\nIf interest causes debt to rise from 10,000 to 11,250, the position reaches the threshold even though collateral price never changed.\n\nBorrowers must monitor both sides of the ratio.\n\n### Example: Supplier Yield\n\nSuppose:\n\nPool supply: 10 million units\n\nBorrowed amount: 8 million\n\nAverage borrower rate: 10 percent\n\nReserve factor: 15 percent\n\nAnnual borrower interest:\n\n8 million × 10 percent = 800,000 units\n\nAfter reserve deduction:\n\n800,000 × 85 percent = 680,000 units\n\nDistributed across ten million supplied units:\n\n680,000 ÷ 10 million = 6.8 percent\n\nThe approximate supplier rate is 6.8 percent before compounding, incentives, defaults and other effects.\n\n### Example: Recursive Leverage\n\nSuppose a user starts with 10,000 units of collateral and can borrow fifty percent repeatedly.\n\nFirst cycle:\n\nDeposit 10,000\n\nBorrow 5,000\n\nBuy and redeposit 5,000\n\nTotal collateral:\n\n15,000\n\nSecond cycle:\n\nBorrow an additional 2,500\n\nBuy and redeposit\n\nTotal collateral:\n\n17,500\n\nThe process can continue with progressively smaller amounts.\n\nThe user’s gross collateral exposure increases, but so does debt.\n\nThe portfolio is leveraged and more sensitive to price declines.\n\n### Evaluating a Lending Protocol\n\nA structured protocol review may include the following areas.\n\n### Purpose and Usage\n\nIs there genuine borrowing demand?\n\nWhich users and strategies use the protocol?\n\n### Operating History\n\nHow long has it functioned?\n\nHas it survived severe market conditions?\n\nHas it experienced bad debt or exploits?\n\n### Smart Contracts\n\nAre contracts verified?\n\nHave audits been published?\n\nCan contracts be upgraded?\n\n### Governance\n\nWho controls risk parameters?\n\nIs voting concentrated?\n\nAre timelocks used?\n\n### Oracles\n\nWhich price sources are used?\n\nHow are stale or manipulated prices handled?\n\n### Collateral\n\nWhich assets are accepted?\n\nAre they liquid and securely issued?\n\n### Liquidations\n\nAre liquidators active?\n\nCan collateral be sold under stress?\n\nWhat incentives apply?\n\n### Liquidity\n\nWhat is the utilisation rate?\n\nCan lenders withdraw during stress?\n\n### Reserves\n\nHow much capital exists to absorb bad debt?\n\nWhat assets support the reserves?\n\n### Incentives\n\nAre rates sustainable without token rewards?\n\n### Evaluating a Centralised Lender\n\nAdditional questions include:\n\nWho owns and manages the company?\n\nWhich legal entity holds customer assets?\n\nAre deposits segregated?\n\nCan the company lend assets without restriction?\n\nWho are the borrowers?\n\nAre loans collateralised?\n\nAre financial statements audited?\n\nAre reserves and liabilities disclosed?\n\nCan withdrawals be suspended?\n\nWhat claim does the customer have in insolvency?\n\nIs deposit protection available?\n\nWhich regulator, if any, oversees the product?\n\nA polished interface and regular interest payments do not prove solvency.\n\n### Safer Lending Practices\n\nPotential risk-reduction measures include:\n\nUsing established protocols with transparent operating histories\n\nVerifying contract addresses\n\nStarting with a small amount\n\nDiversifying protocol exposure\n\nAvoiding unusually high incentive-driven yields\n\nMonitoring utilisation and available liquidity\n\nReviewing stablecoin and collateral quality\n\nLimiting token approvals\n\nTesting withdrawals\n\nMaintaining tax records\n\nAssuming smart contract deposits can be lost entirely\n\nLenders should understand who ultimately bears bad debt.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,10,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-28-lesson-11','cognizen-crypto-mastery-foundations-production','Safer Borrowing Practices and Ignoring Cross-Collateral Contagion','cmf-module-2-28','text','### Safer Borrowing Practices\n\nPotential practices include:\n\nBorrowing well below the maximum LTV\n\nUsing liquid and better-understood collateral\n\nMaintaining an emergency repayment reserve\n\nMonitoring interest and health factor\n\nAvoiding dependence on one front end\n\nUnderstanding liquidation penalties\n\nStress-testing severe price declines\n\nAvoiding excessive recursive leverage\n\nPlanning repayment before borrowing\n\nKeeping sufficient network tokens for emergency transactions\n\nThe purpose of the safety buffer is to reduce dependence on perfect timing.\n\n### Testing With a Small Position\n\nBefore using a lending protocol substantially, a user may:\n\nVerify the official interface and contracts\n\nSupply a small amount\n\nConfirm receipt-token behaviour\n\nTest a partial withdrawal\n\nDeposit limited collateral\n\nBorrow a small amount\n\nObserve interest accrual\n\nMake a partial repayment\n\nClose the position\n\nRevoke unnecessary approvals\n\nA successful test cannot prove long-term security.\n\nIt can reveal operational misunderstandings before greater capital is exposed.\n\n### Lending Protocol Checklist\n\nBefore supplying assets, ask:\n\nIs this a centralised lender or DeFi protocol?\n\nWho controls the deposited assets?\n\nWhere does the supplier yield come from?\n\nWhich borrowers create demand?\n\nWhat portion of the yield comes from incentives?\n\nWhat is the current utilisation rate?\n\nHow has utilisation behaved during stress?\n\nIs sufficient liquidity available for withdrawal?\n\nCan withdrawals be queued or paused?\n\nWhich collateral assets support the loans?\n\nHow liquid are those assets?\n\nWhich oracle sources are used?\n\nHas the protocol experienced bad debt?\n\nWho absorbs unrecovered losses?\n\nHow large and liquid are protocol reserves?\n\nAre smart contracts audited and verified?\n\nCan contracts be upgraded?\n\nWho controls administrator powers?\n\nIs governance concentrated?\n\nWhich stablecoin, bridge or network risks are involved?\n\nIs the yield high because risk has increased?\n\nWhat tax events may occur?\n\nCan I test a withdrawal before depositing more?\n\nIs the position size acceptable if the protocol fails completely?\n\n### Borrowing Checklist\n\nBefore borrowing, ask:\n\nWhy am I borrowing instead of selling or using other capital?\n\nWhich asset will serve as collateral?\n\nWhich asset will I borrow?\n\nWhat is the initial LTV?\n\nWhat is the maximum permitted LTV?\n\nWhat is the liquidation threshold?\n\nWhat is the current health factor?\n\nAt what approximate collateral price could liquidation begin?\n\nHow does accrued interest change that price?\n\nIs the borrowing rate variable or stable?\n\nHow high could the rate rise?\n\nWhat liquidation penalty applies?\n\nCan the entire position be liquidated?\n\nIs cross-collateral or isolated collateral used?\n\nCould one weak collateral asset affect all positions?\n\nIs recursive leverage involved?\n\nDoes the strategy depend on a positive yield spread?\n\nWhat happens if the spread becomes negative?\n\nWhat happens if collateral falls fifty percent?\n\nWhat happens if the borrowed stablecoin depegs?\n\nCan I repay during network congestion?\n\nDo I have liquid emergency funds?\n\nWhich oracles and liquidators protect the protocol?\n\nWhat happens if they fail?\n\nCan governance change my risk parameters?\n\nHow will I repay the loan?\n\nWhat is the intended loan duration?\n\nWhat tax consequences may arise from liquidation?\n\nIs the potential benefit sufficient to justify leverage and contract risk?\n\nCan I accept the loss if the collateral is liquidated?\n\n### Common Lending and Borrowing Mistakes\n\n\n\n### Chasing the Highest Supplier Yield\n\nHigh rates may reflect temporary incentives, scarce liquidity or increased risk.\n\n### Borrowing at the Maximum LTV\n\nA modest collateral decline triggers liquidation.\n\n### Ignoring Interest Accrual\n\nDebt grows even when collateral price remains unchanged.\n\n### Treating Stablecoin Lending as Risk-Free\n\nIssuer, depeg, protocol and bad-debt risks remain.\n\n### Assuming Overcollateralisation Prevents Every Loss\n\nRapid market movement and weak liquidity can still create bad debt.\n\n### Ignoring Withdrawal Liquidity\n\nA lender may be unable to withdraw when utilisation is extremely high.\n\n### Confusing Receipt Tokens With the Original Asset\n\nThe receipt token depends on the lending protocol and redemption mechanism.\n\n### Using Recursive Borrowing Without Measuring Leverage\n\nSeveral simple transactions combine into a highly leveraged position.\n\n### Ignoring Variable Borrowing Rates\n\nA profitable spread can become negative.\n\n### Relying on Manual Rescue Near Liquidation\n\nCongestion and automated liquidators may prevent timely action.\n\n### Using Illiquid Collateral\n\nLiquidators cannot sell it efficiently during stress.\n\n### Ignoring Cross-Collateral Contagion\n\nOne weak asset threatens an entire account.','markdown',NULL,NULL,NULL,5,0,0,0,'',NULL,11,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-28-lesson-12','cognizen-crypto-mastery-foundations-production','Common Misunderstandings and Key Takeaway','cmf-module-2-28','text','### Common Misunderstandings\n\n#### “DeFi Loans Require No Trust”\n\nUsers trust smart contracts, oracles, governance, liquidators, collateral and blockchain security.\n\n#### “Overcollateralised Means Risk-Free”\n\nCollateral can fall too quickly or become illiquid.\n\n#### “My Collateral Is Not Sold Unless I Choose to Sell”\n\nThe protocol can liquidate it automatically.\n\n#### “A Health Factor Above One Means the Position Is Safe”\n\nA value only slightly above one may provide very little protection.\n\n#### “The Maximum Borrowing Limit Is a Recommended Amount”\n\nIt is a protocol boundary, not personalised risk guidance.\n\n#### “A Stable Borrowing Rate Never Changes”\n\nThe protocol may rebalance or alter it under specified conditions.\n\n#### “Supplier APY Is Guaranteed for a Year”\n\nRates change with utilisation, incentives and market conditions.\n\n#### “High Utilisation Is Always Good for Lenders”\n\nIt may raise yield while reducing withdrawal liquidity.\n\n#### “A Stablecoin Loan Has No Price Risk”\n\nThe collateral and stablecoin can both change in value.\n\n#### “Borrowing Instead of Selling Avoids Loss”\n\nIt adds debt and can force a sale through liquidation.\n\n#### “Recursive Lending Creates Free Yield”\n\nIt creates leverage, interest expense and liquidation risk.\n\n#### “Audits Eliminate Smart Contract Risk”\n\nAudits are limited reviews and cannot guarantee safety.\n\n#### “Proof of Reserves Proves a Centralised Lender Is Solvent”\n\nLiabilities, asset quality and encumbrances must also be known.\n\n#### “Liquidators Protect Borrowers”\n\nLiquidators protect protocol solvency and are paid from borrower collateral.\n\n#### “Borrowing Is Not a Market Position”\n\nBorrowing a volatile asset or borrowing against volatile collateral creates directional exposure.\n\n### Module Summary\n\nCryptocurrency lending allows users to supply assets in return for interest and allows borrowers to access liquidity by pledging collateral.\n\nCentralised lenders manage loans and customer assets through a company.\n\nDecentralised lending protocols use smart contracts, collateral rules, oracles and automated liquidations.\n\nMost DeFi loans are overcollateralised because the protocol may not know the borrower’s identity, income or credit history.\n\nImportant measurements include:\n\nLoan-to-value ratio\n\nCollateral ratio\n\nCollateral factor\n\nLiquidation threshold\n\nHealth factor\n\nInterest rates often change according to pool utilisation.\n\nWhen utilisation rises:\n\nBorrowing may become more expensive\n\nSupplier yields may rise\n\nWithdrawal liquidity may decline\n\nLiquidations occur when collateral no longer provides sufficient protection.\n\nLiquidators repay debt and receive discounted collateral.\n\nThis protects lenders but penalises borrowers.\n\nMajor risks include:\n\nCollateral-price decline\n\nInterest-rate increases\n\nLiquidation\n\nOracle failure\n\nBad debt\n\nSmart contract exploits\n\nStablecoin depegging\n\nWeak withdrawal liquidity\n\nGovernance changes\n\nBridge and network failure\n\nRecursive borrowing and yield looping create leverage even when each individual transaction appears simple.\n\nA borrower should maintain a substantial safety buffer, stress-test collateral declines and know exactly how the loan will be repaid.\n\nA lender should investigate collateral quality, liquidation performance, protocol reserves and who absorbs losses when the system fails.\n\nThe headline rate is only the visible part of the credit arrangement.\n\nThe real risk lies in the collateral, liquidity, contracts and incentives that make repayment possible.\n\n### Key Takeaway\n\nA cryptocurrency loan is not made safe simply because it is managed by a smart contract.\n\nThe protocol depends on collateral remaining valuable, oracles remaining accurate, liquidators acting quickly and markets remaining deep enough to sell collateral.\n\nFor borrowers, the decisive risk is liquidation.\n\nFor lenders, it is whether the system can recover enough value to honour withdrawals.\n\nBorrow well below the technical limit, lend only after understanding who bears bad debt and never confuse an advertised interest rate with a guaranteed return.','markdown',NULL,NULL,NULL,5,0,0,0,'',NULL,12,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-2-28-lesson-13','cognizen-crypto-mastery-foundations-production','Check your understanding','cmf-module-2-28','text','### Check your understanding\n\nAnswer these questions to self-assess your understanding before moving on.\n\n1. What is cryptocurrency lending?\n\n2. How does centralised lending differ from decentralised lending?\n\n3. Why are most permissionless DeFi loans overcollateralised?\n\n4. What is collateral?\n\n5. How is loan-to-value calculated?\n\n6. How does a collateral ratio differ from LTV?\n\n7. What is a collateral factor?\n\n8. What is a liquidation threshold?\n\n9. What does a health factor represent?\n\n10. Why is borrowing at the maximum permitted LTV dangerous?\n\n11. How does interest accrual affect liquidation risk?\n\n12. What is a lending pool?\n\n13. What does a supply or receipt token represent?\n\n14. What is the utilisation rate?\n\n15. How can high utilisation affect borrowers and lenders?\n\n16. What is an interest-rate curve?\n\n17. What is the purpose of a kink in the rate model?\n\n18. How does a variable borrowing rate differ from a stable rate?\n\n19. What is a reserve factor?\n\n20. Why is the supplier rate normally lower than the borrower rate?\n\n21. How can protocol incentives distort net borrowing or lending rates?\n\n22. What is withdrawal liquidity?\n\n23. Why can a solvent lending pool still experience withdrawal delays?\n\n24. What is liquidation?\n\n25. What is a liquidation bonus?\n\n26. What is a close factor?\n\n27. How can a liquidation cascade develop?\n\n28. What is bad debt?\n\n29. Who may absorb bad debt in a lending protocol?\n\n30. Why are price oracles essential to lending?\n\n31. How can oracle manipulation create protocol losses?\n\n32. What risks arise when borrowing stablecoins against volatile collateral?\n\n33. What risks arise when borrowing a volatile asset?\n\n34. What is isolated collateral?\n\n35. How does cross-collateral borrowing create contagion?\n\n36. What are supply caps and borrow caps?\n\n37. What is recursive borrowing?\n\n38. How can recursive borrowing create a leveraged long position?\n\n39. What is rate inversion?\n\n40. Why may a yield-looping strategy become unprofitable?\n\n41. How can network congestion increase liquidation risk?\n\n42. What is credit delegation?\n\n43. How does undercollateralised lending differ from ordinary DeFi lending?\n\n44. Why does real-world asset lending reintroduce legal and servicing risks?\n\n45. What is rehypothecation?\n\n46. Why is proof of reserves insufficient to prove solvency?\n\n47. What does a governance-token backstop do?\n\n48. Why should lenders monitor collateral quality and liquidation liquidity?\n\n49. What should borrowers include in a stress test?\n\n50. Which factors should be assessed before using a lending protocol?','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,13,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `course_sections` (`id`,`course_id`,`title`,`position`,`created_at`) SELECT 'cmf-module-2-29','cognizen-crypto-mastery-foundations-production','Module 2.29: Layer 1 and Layer 2 Networks',29,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
